output.rtl/encoder_64b66b.sv:
module encoder_64b66b (
    input  logic        clk_in,
    input  logic        rst_in,
    input  logic [63:0] encoder_data_in,
    input  logic [7:0]  encoder_control_in,
    output logic [65:0] encoder_data_out
);

    always_ff @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            encoder_data_out <= 66'd0;
        end else begin
            if (encoder_control_in == 8'b00000000) begin
                // Pure data encoding: sync header 2'b01 followed by 64-bit data
                encoder_data_out <= {2'b01, encoder_data_in};
            end else begin
                // Control character present: sync header 2'b10 followed by 64'd0
                encoder_data_out <= {2'b10, 64'd0};
            end
        end
    end

endmodule

output.rtl/priority_encoder.v:
module priority_encoder_8x3 (
    input  [7:0] in,
    output reg [2:0] out
);

always @(*) begin
    if (in[7])
        out = 3'b111;
    else if (in[6])
        out = 3'b110;
    else if (in[5])
        out = 3'b101;
    else if (in[4])
        out = 3'b100;
    else if (in[3])
        out = 3'b011;
    else if (in[2])
        out = 3'b010;
    else if (in[1])
        out = 3'b001;
    else
        out = 3'b000;
end

endmodule

output.rtl/GP.v:
module GP (
    input  wire i_A,
    input  wire i_B,
    input  wire i_Cin,
    output wire o_generate,
    output wire o_propagate,
    output wire o_Cout
);

    assign o_generate  = i_A & i_B;
    assign o_propagate = i_A | i_B;
    assign o_Cout      = o_generate | (o_propagate & i_Cin);

endmodule

output.rtl/glitch_free_mux.sv:
// Glitch-Free Clock Multiplexer
// When sel=0, clkout = clk1; when sel=1, clkout = clk2
// Glitch-free switching using enable flops on negative edges

module glitch_free_mux (
    input  wire clk1,
    input  wire clk2,
    input  wire rst_n,
    input  wire sel,
    output wire clkout
);

    reg clk1_en_reg;
    reg clk2_en_reg;

    // clk1 enable logic:
    // Captured on negative edge of clk1
    // Enable clk1 when sel=0 and clk2 is not enabled
    // Disable clk1 when sel=1
    always @(negedge clk1 or negedge rst_n) begin
        if (!rst_n) begin
            clk1_en_reg <= 1'b1; // default to clk1 after reset
        end else begin
            clk1_en_reg <= (~sel) & (~clk2_en_reg);
        end
    end

    // clk2 enable logic:
    // Captured on negative edge of clk2
    // Enable clk2 when sel=1 and clk1 is not enabled
    // Disable clk2 when sel=0
    always @(negedge clk2 or negedge rst_n) begin
        if (!rst_n) begin
            clk2_en_reg <= 1'b0;
        end else begin
            clk2_en_reg <= sel & (~clk1_en_reg);
        end
    end

    // Gate the clocks using AND gates
    // clk1_gated is active only when clk1_en_reg is high
    // clk2_gated is active only when clk2_en_reg is high
    // The output is the OR of the two gated clocks

    wire clk1_gated;
    wire clk2_gated;

    assign clk1_gated = clk1 & clk1_en_reg;
    assign clk2_gated = clk2 & clk2_en_reg;

    assign clkout = clk1_gated | clk2_gated;

endmodule

output.rtl/16qam_mapper.sv:
// rtl/16qam_mapper.sv
// QAM16 Mapper with Interpolation

module qam16_mapper_interpolated #(
    parameter int N         = 4,  // Number of input symbols (>= 2, multiple of 2)
    parameter int IN_WIDTH  = 4,  // Bit width of each input symbol (fixed at 4)
    parameter int OUT_WIDTH = 3   // Bit width of output components (fixed at 3)
) (
    input  logic [N*IN_WIDTH-1:0]          bits,
    output logic [(N+N/2)*OUT_WIDTH-1:0]   I,
    output logic [(N+N/2)*OUT_WIDTH-1:0]   Q
);

    // Total output symbols: N mapped + N/2 interpolated = N + N/2
    localparam int TOTAL_OUT = N + N/2;

    // Mapped I and Q arrays (signed, OUT_WIDTH bits each)
    logic signed [OUT_WIDTH-1:0] mapped_I [N];
    logic signed [OUT_WIDTH-1:0] mapped_Q [N];

    // Interpolated I and Q (need 1 extra bit for addition)
    logic signed [OUT_WIDTH:0] interp_I [N/2];
    logic signed [OUT_WIDTH:0] interp_Q [N/2];

    // Function to map 2 bits to QAM16 component value
    function automatic logic signed [OUT_WIDTH-1:0] map_bits(input logic [1:0] b);
        case (b)
            2'b00: map_bits = -3;
            2'b01: map_bits = -1;
            2'b10: map_bits =  1;
            2'b11: map_bits =  3;
            default: map_bits = 0;
        endcase
    endfunction

    // Map input bits to I and Q components
    always_comb begin
        for (int i = 0; i < N; i++) begin
            // Extract the i-th symbol (N*IN_WIDTH-1 downto 0, symbol 0 is MSB group)
            // Symbol i occupies bits [(N-1-i)*IN_WIDTH +: IN_WIDTH]
            automatic logic [IN_WIDTH-1:0] sym;
            sym = bits[(N-1-i)*IN_WIDTH +: IN_WIDTH];
            // MSBs [IN_WIDTH-1 : IN_WIDTH-2] -> I component
            mapped_I[i] = map_bits(sym[IN_WIDTH-1:IN_WIDTH-2]);
            // LSBs [1:0] -> Q component
            mapped_Q[i] = map_bits(sym[1:0]);
        end
    end

    // Compute interpolated values for each pair of consecutive symbols
    always_comb begin
        for (int p = 0; p < N/2; p++) begin
            // Symbols at indices 2*p and 2*p+1
            interp_I[p] = ({{1{mapped_I[2*p][OUT_WIDTH-1]}}, mapped_I[2*p]} + 
                           {{1{mapped_I[2*p+1][OUT_WIDTH-1]}}, mapped_I[2*p+1]}) >>> 1;
            interp_Q[p] = ({{1{mapped_Q[2*p][OUT_WIDTH-1]}}, mapped_Q[2*p]} + 
                           {{1{mapped_Q[2*p+1][OUT_WIDTH-1]}}, mapped_Q[2*p+1]}) >>> 1;
        end
    end

    // Arrange output: for each pair (sym[2*p], interp[p], sym[2*p+1])
    // Output index in packed array:
    //   TOTAL_OUT symbols, each OUT_WIDTH bits
    //   Output slot 0 is MSB (highest bits)
    //
    // For pair p (0-indexed):
    //   - slot 3*p+0: mapped_I/Q[2*p]
    //   - slot 3*p+1: interp_I/Q[p]  (truncated to OUT_WIDTH)
    //   - slot 3*p+2: mapped_I/Q[2*p+1]
    always_comb begin
        I = '0;
        Q = '0;
        for (int p = 0; p < N/2; p++) begin
            // Slot index for first mapped symbol of pair p
            automatic int slot0 = 3*p;
            automatic int slot1 = 3*p + 1;
            automatic int slot2 = 3*p + 2;

            // Pack into output: slot 0 is at top (MSB side)
            // Slot k occupies bits [(TOTAL_OUT-1-k)*OUT_WIDTH +: OUT_WIDTH]
            I[(TOTAL_OUT-1-slot0)*OUT_WIDTH +: OUT_WIDTH] = mapped_I[2*p];
            I[(TOTAL_OUT-1-slot1)*OUT_WIDTH +: OUT_WIDTH] = interp_I[p][OUT_WIDTH-1:0];
            I[(TOTAL_OUT-1-slot2)*OUT_WIDTH +: OUT_WIDTH] = mapped_I[2*p+1];

            Q[(TOTAL_OUT-1-slot0)*OUT_WIDTH +: OUT_WIDTH] = mapped_Q[2*p];
            Q[(TOTAL_OUT-1-slot1)*OUT_WIDTH +: OUT_WIDTH] = interp_Q[p][OUT_WIDTH-1:0];
            Q[(TOTAL_OUT-1-slot2)*OUT_WIDTH +: OUT_WIDTH] = mapped_Q[2*p+1];
        end
    end

endmodule

output.rtl/16qam_demapper.sv:
// rtl/16qam_demapper.sv
// QAM16 Demapper with Interpolated Error Detection

module qam16_demapper_interpolated #(
    parameter int N         = 4,
    parameter int OUT_WIDTH = 4,
    parameter int IN_WIDTH  = 3
)(
    input  logic [(N + N/2)*IN_WIDTH-1:0] I,
    input  logic [(N + N/2)*IN_WIDTH-1:0] Q,
    output logic [N*OUT_WIDTH-1:0]        bits,
    output logic                          error_flag
);

    // Error threshold for interpolated value comparison
    localparam int ERROR_THRESHOLD = 1;

    // Total number of samples (mapped + interpolated)
    localparam int TOTAL_SAMPLES = N + N/2;

    // Number of groups (each group: mapped, interpolated, mapped)
    localparam int NUM_GROUPS = N/2;

    // Function to map I or Q component to 2 bits
    function automatic logic [1:0] map_to_bits(input logic signed [IN_WIDTH-1:0] val);
        case (val)
            3'sb101: map_to_bits = 2'b00; // -3
            3'sb111: map_to_bits = 2'b01; // -1
            3'sb001: map_to_bits = 2'b10; //  1
            3'sb011: map_to_bits = 2'b11; //  3
            default: map_to_bits = 2'b00; // default
        endcase
    endfunction

    // Internal arrays for parsed I and Q samples
    logic signed [IN_WIDTH-1:0]   I_samples [0:TOTAL_SAMPLES-1];
    logic signed [IN_WIDTH-1:0]   Q_samples [0:TOTAL_SAMPLES-1];

    // Parse the input vectors into arrays
    // Input is packed: index 0 is at the MSB side
    // I[(TOTAL_SAMPLES-1)*IN_WIDTH +: IN_WIDTH] is sample 0
    // Actually, let's clarify: packed arrays in SV are MSB first
    // So I[TOTAL_SAMPLES*IN_WIDTH-1 : (TOTAL_SAMPLES-1)*IN_WIDTH] = sample 0

    integer k;
    always_comb begin
        for (k = 0; k < TOTAL_SAMPLES; k++) begin
            I_samples[k] = signed'(I[(TOTAL_SAMPLES-1-k)*IN_WIDTH +: IN_WIDTH]);
            Q_samples[k] = signed'(Q[(TOTAL_SAMPLES-1-k)*IN_WIDTH +: IN_WIDTH]);
        end
    end

    // Mapped sample indices and interpolated sample indices
    // Pattern: mapped(0), interp(1), mapped(2), mapped(3), interp(4), mapped(5), ...
    // Group g (0-indexed): 
    //   mapped_a  index = g*3
    //   interp    index = g*3 + 1
    //   mapped_b  index = g*3 + 2

    // Storage for error detection
    logic signed [IN_WIDTH:0]   expected_I [0:NUM_GROUPS-1]; // IN_WIDTH+1 bits
    logic signed [IN_WIDTH:0]   expected_Q [0:NUM_GROUPS-1];
    logic signed [IN_WIDTH:0]   diff_I     [0:NUM_GROUPS-1];
    logic signed [IN_WIDTH:0]   diff_Q     [0:NUM_GROUPS-1];
    logic        [IN_WIDTH:0]   abs_diff_I [0:NUM_GROUPS-1];
    logic        [IN_WIDTH:0]   abs_diff_Q [0:NUM_GROUPS-1];
    logic                       group_error[0:NUM_GROUPS-1];

    // Storage for mapped symbols
    // Each group has 2 mapped symbols: mapped_a and mapped_b
    // Total mapped symbols = N
    // Symbol ordering in output: group0_mapped_a, group0_mapped_b, group1_mapped_a, group1_mapped_b, ...
    logic [1:0] I_bits [0:N-1];
    logic [1:0] Q_bits [0:N-1];

    integer g;
    always_comb begin
        error_flag = 1'b0;

        for (g = 0; g < NUM_GROUPS; g++) begin
            // Indices
            // mapped_a: g*3, interp: g*3+1, mapped_b: g*3+2

            // Expected interpolated value = (mapped_a + mapped_b) / 2
            // Use IN_WIDTH+1 bits for addition
            expected_I[g] = ($signed({I_samples[g*3][IN_WIDTH-1], I_samples[g*3]}) + 
                             $signed({I_samples[g*3+2][IN_WIDTH-1], I_samples[g*3+2]})) >>> 1;
            expected_Q[g] = ($signed({Q_samples[g*3][IN_WIDTH-1], Q_samples[g*3]}) + 
                             $signed({Q_samples[g*3+2][IN_WIDTH-1], Q_samples[g*3+2]})) >>> 1;

            // Difference between actual interpolated and expected
            diff_I[g] = $signed({I_samples[g*3+1][IN_WIDTH-1], I_samples[g*3+1]}) - expected_I[g];
            diff_Q[g] = $signed({Q_samples[g*3+1][IN_WIDTH-1], Q_samples[g*3+1]}) - expected_Q[g];

            // Absolute difference
            abs_diff_I[g] = diff_I[g][IN_WIDTH] ? (~diff_I[g] + 1'b1) : diff_I[g];
            abs_diff_Q[g] = diff_Q[g][IN_WIDTH] ? (~diff_Q[g] + 1'b1) : diff_Q[g];

            // Check if error exceeds threshold
            group_error[g] = (abs_diff_I[g] > ERROR_THRESHOLD) || (abs_diff_Q[g] > ERROR_THRESHOLD);

            if (group_error[g])
                error_flag = 1'b1;

            // Map mapped_a (index g*3) to bits
            I_bits[g*2]   = map_to_bits(I_samples[g*3]);
            Q_bits[g*2]   = map_to_bits(Q_samples[g*3]);

            // Map mapped_b (index g*3+2) to bits
            I_bits[g*2+1] = map_to_bits(I_samples[g*3+2]);
            Q_bits[g*2+1] = map_to_bits(Q_samples[g*3+2]);
        end

        // Assemble output bits vector
        // bits[N*OUT_WIDTH-1:0], symbol 0 at MSB
        for (g = 0; g < N; g++) begin
            bits[(N-1-g)*OUT_WIDTH +: OUT_WIDTH] = {I_bits[g], Q_bits[g]};
        end
    end

endmodule

output.rtl/apb_dsp_unit.v:
// rtl/apb_dsp_unit.v

module apb_dsp_unit (
    input wire        pclk,
    input wire        presetn,
    input wire [9:0]  paddr,
    input wire        pselx,
    input wire        penable,
    input wire        pwrite,
    input wire [7:0]  pwdata,
    output reg        pready,
    output reg [7:0]  prdata,
    output reg        pslverr,
    output reg        sram_valid
);

    // FSM States
    localparam IDLE        = 2'b00;
    localparam WRITE_STATE = 2'b01;
    localparam READ_STATE  = 2'b10;

    reg [1:0] state, next_state;

    // Internal Registers
    reg [7:0] r_operand_1;
    reg [7:0] r_operand_2;
    reg [7:0] r_Enable;
    reg [7:0] r_write_address;
    reg [7:0] r_write_data;
    reg [7:0] r_result;

    // SRAM: 1KB = 1024 bytes
    reg [7:0] sram [0:1023];

    // Operand values read from SRAM
    wire [7:0] op1_data;
    wire [7:0] op2_data;
    assign op1_data = sram[r_operand_1];
    assign op2_data = sram[r_operand_2];

    // FSM: State Register
    always @(posedge pclk or negedge presetn) begin
        if (!presetn)
            state <= IDLE;
        else
            state <= next_state;
    end

    // FSM: Next State Logic
    always @(*) begin
        next_state = IDLE;
        case (state)
            IDLE: begin
                if (pselx && !penable) begin
                    if (pwrite)
                        next_state = WRITE_STATE;
                    else
                        next_state = READ_STATE;
                end else begin
                    next_state = IDLE;
                end
            end
            WRITE_STATE: next_state = IDLE;
            READ_STATE:  next_state = IDLE;
            default:     next_state = IDLE;
        endcase
    end

    // FSM: Output / Register Update Logic
    always @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            pready         <= 1'b0;
            prdata         <= 8'h00;
            pslverr        <= 1'b0;
            sram_valid     <= 1'b0;
            r_operand_1    <= 8'h00;
            r_operand_2    <= 8'h00;
            r_Enable       <= 8'h00;
            r_write_address<= 8'h00;
            r_write_data   <= 8'h00;
            r_result       <= 8'h00;
        end else begin
            // Default outputs each cycle
            pready     <= 1'b0;
            pslverr    <= 1'b0;
            prdata     <= 8'h00;
            sram_valid <= 1'b0;

            case (state)
                IDLE: begin
                    // Nothing to do; wait for transaction
                end

                WRITE_STATE: begin
                    pready <= 1'b1;
                    case (paddr)
                        10'h000: r_operand_1    <= pwdata;
                        10'h001: r_operand_2    <= pwdata;
                        10'h002: begin
                            r_Enable <= pwdata;
                        end
                        10'h003: r_write_address <= pwdata;
                        10'h004: r_write_data    <= pwdata;
                        default: pslverr <= 1'b1;
                    endcase
                end

                READ_STATE: begin
                    pready <= 1'b1;
                    case (paddr)
                        10'h000: prdata <= r_operand_1;
                        10'h001: prdata <= r_operand_2;
                        10'h002: prdata <= r_Enable;
                        10'h003: prdata <= r_write_address;
                        10'h004: prdata <= r_write_data;
                        10'h005: prdata <= r_result;
                        default: pslverr <= 1'b1;
                    endcase
                end

                default: begin
                    // Do nothing
                end
            endcase

            // Compute result based on r_Enable
            case (r_Enable)
                8'h01: begin
                    // Addition mode
                    r_result <= op1_data + op2_data;
                    sram[10'h005] <= op1_data + op2_data;
                end
                8'h02: begin
                    // Multiplication mode
                    r_result <= op1_data * op2_data;
                    sram[10'h005] <= op1_data * op2_data;
                end
                8'h03: begin
                    // Data Writing mode
                    sram_valid <= 1'b1;
                    sram[r_write_address] <= r_write_data;
                end
                default: begin
                    // Disabled or unknown
                end
            endcase
        end
    end

endmodule

output.rtl/axis_upscale.sv:
// AXI Stream Data Upsizer
// Upscales 24-bit input data to 32-bit output data
// Supports sign extension and data format selection

module axis_upscale (
    input  wire        clk,
    input  wire        resetn,

    // Data format control signals
    input  wire        dfmt_enable,
    input  wire        dfmt_type,
    input  wire        dfmt_se,

    // AXI Slave Interface
    input  wire        s_axis_valid,
    input  wire [23:0] s_axis_data,
    output wire        s_axis_ready,

    // AXI Master Interface
    output reg         m_axis_valid,
    output reg  [31:0] m_axis_data,
    input  wire        m_axis_ready
);

    // Internal signals for data formatting
    wire        msb_bit;
    wire        extended_bit;
    wire [31:0] formatted_data;

    // Ready signal: slave is ready when master is ready or master is not valid
    assign s_axis_ready = m_axis_ready | ~m_axis_valid;

    // Determine the MSB bit based on dfmt_type
    // dfmt_type = 1: inverted MSB of s_axis_data
    // dfmt_type = 0: MSB of s_axis_data as-is
    assign msb_bit = dfmt_type ? ~s_axis_data[23] : s_axis_data[23];

    // Determine the extension bit based on dfmt_se
    // dfmt_se = 1: extend with the (possibly inverted) MSB bit
    // dfmt_se = 0: extend with zero
    assign extended_bit = dfmt_se ? msb_bit : 1'b0;

    // Format the data based on dfmt_enable
    // dfmt_enable = 1: apply formatting with msb_bit and extended_bit
    // dfmt_enable = 0: zero-extend (8 zeros + 24-bit data)
    assign formatted_data = dfmt_enable ?
        {{8{extended_bit}}, msb_bit, s_axis_data[22:0]} :
        {8'h00, s_axis_data};

    // Pipeline register stage
    always @(posedge clk) begin
        if (!resetn) begin
            m_axis_valid <= 1'b0;
            m_axis_data  <= 32'h0;
        end else begin
            if (s_axis_ready) begin
                m_axis_valid <= s_axis_valid;
                if (s_axis_valid) begin
                    m_axis_data <= formatted_data;
                end
            end
        end
    end

endmodule

output.rtl/cvdp_copilot_apb_gpio.sv:
// =============================================================================
// Module: cvdp_copilot_apb_gpio
// Description: APB-compatible GPIO module with configurable width,
//              bidirectional control, interrupt generation, and synchronization.
// =============================================================================

module cvdp_copilot_apb_gpio #(
    parameter int GPIO_WIDTH = 8
) (
    // APB Interface
    input  logic                    pclk,
    input  logic                    preset_n,
    input  logic                    psel,
    input  logic [7:2]              paddr,
    input  logic                    penable,
    input  logic                    pwrite,
    input  logic [31:0]             pwdata,
    output logic [31:0]             prdata,
    output logic                    pready,
    output logic                    pslverr,

    // GPIO Interface
    input  logic [GPIO_WIDTH-1:0]   gpio_in,
    output logic [GPIO_WIDTH-1:0]   gpio_out,
    output logic [GPIO_WIDTH-1:0]   gpio_enable,
    output logic [GPIO_WIDTH-1:0]   gpio_int,
    output logic                    comb_int
);

    // =========================================================================
    // Register Map Address Definitions
    // =========================================================================
    localparam logic [7:2] ADDR_GPIO_IN       = 6'h00; // 0x00 >> 2 = 0
    localparam logic [7:2] ADDR_GPIO_OUT      = 6'h01; // 0x04 >> 2 = 1
    localparam logic [7:2] ADDR_GPIO_OE       = 6'h02; // 0x08 >> 2 = 2
    localparam logic [7:2] ADDR_GPIO_INT_EN   = 6'h03; // 0x0C >> 2 = 3
    localparam logic [7:2] ADDR_GPIO_INT_TYPE = 6'h04; // 0x10 >> 2 = 4
    localparam logic [7:2] ADDR_GPIO_INT_POL  = 6'h05; // 0x14 >> 2 = 5
    localparam logic [7:2] ADDR_GPIO_INT_STAT = 6'h06; // 0x18 >> 2 = 6

    // =========================================================================
    // Internal Registers
    // =========================================================================
    logic [GPIO_WIDTH-1:0] reg_out;        // GPIO Output Data Register
    logic [GPIO_WIDTH-1:0] reg_oe;         // GPIO Output Enable Register
    logic [GPIO_WIDTH-1:0] reg_int_en;     // GPIO Interrupt Enable Register
    logic [GPIO_WIDTH-1:0] reg_int_type;   // GPIO Interrupt Type Register (1=edge, 0=level)
    logic [GPIO_WIDTH-1:0] reg_int_pol;    // GPIO Interrupt Polarity Register (1=active-high/rising, 0=active-low/falling)
    logic [GPIO_WIDTH-1:0] reg_int_stat;   // GPIO Interrupt Status Register (read-only, internally driven)

    // =========================================================================
    // Two-Stage Synchronizer for gpio_in
    // =========================================================================
    logic [GPIO_WIDTH-1:0] gpio_sync_stage1;
    logic [GPIO_WIDTH-1:0] gpio_sync_stage2;
    logic [GPIO_WIDTH-1:0] gpio_sync_prev;  // Previous synchronized value for edge detection

    always_ff @(posedge pclk or negedge preset_n) begin
        if (!preset_n) begin
            gpio_sync_stage1 <= '0;
            gpio_sync_stage2 <= '0;
            gpio_sync_prev   <= '0;
        end else begin
            gpio_sync_stage1 <= gpio_in;
            gpio_sync_stage2 <= gpio_sync_stage1;
            gpio_sync_prev   <= gpio_sync_stage2;
        end
    end

    // =========================================================================
    // APB Write Logic
    // =========================================================================
    logic apb_write_en;
    assign apb_write_en = psel & penable & pwrite;

    always_ff @(posedge pclk or negedge preset_n) begin
        if (!preset_n) begin
            reg_out      <= '0;
            reg_oe       <= '0;
            reg_int_en   <= '0;
            reg_int_type <= '0;
            reg_int_pol  <= '0;
        end else if (apb_write_en) begin
            case (paddr)
                ADDR_GPIO_OUT:      reg_out      <= pwdata[GPIO_WIDTH-1:0];
                ADDR_GPIO_OE:       reg_oe       <= pwdata[GPIO_WIDTH-1:0];
                ADDR_GPIO_INT_EN:   reg_int_en   <= pwdata[GPIO_WIDTH-1:0];
                ADDR_GPIO_INT_TYPE: reg_int_type <= pwdata[GPIO_WIDTH-1:0];
                ADDR_GPIO_INT_POL:  reg_int_pol  <= pwdata[GPIO_WIDTH-1:0];
                default: begin
                    // No effect for undefined addresses
                end
            endcase
        end
    end

    // =========================================================================
    // APB Read Logic
    // =========================================================================
    logic apb_read_en;
    assign apb_read_en = psel & ~pwrite;

    always_ff @(posedge pclk or negedge preset_n) begin
        if (!preset_n) begin
            prdata <= 32'h0;
        end else if (apb_read_en) begin
            case (paddr)
                ADDR_GPIO_IN:       prdata <= {{(32-GPIO_WIDTH){1'b0}}, gpio_sync_stage2};
                ADDR_GPIO_OUT:      prdata <= {{(32-GPIO_WIDTH){1'b0}}, reg_out};
                ADDR_GPIO_OE:       prdata <= {{(32-GPIO_WIDTH){1'b0}}, reg_oe};
                ADDR_GPIO_INT_EN:   prdata <= {{(32-GPIO_WIDTH){1'b0}}, reg_int_en};
                ADDR_GPIO_INT_TYPE: prdata <= {{(32-GPIO_WIDTH){1'b0}}, reg_int_type};
                ADDR_GPIO_INT_POL:  prdata <= {{(32-GPIO_WIDTH){1'b0}}, reg_int_pol};
                ADDR_GPIO_INT_STAT: prdata <= {{(32-GPIO_WIDTH){1'b0}}, reg_int_stat};
                default:            prdata <= 32'h0;
            endcase
        end else begin
            prdata <= 32'h0;
        end
    end

    // =========================================================================
    // APB Fixed Signals
    // =========================================================================
    assign pready  = 1'b1;
    assign pslverr = 1'b0;

    // =========================================================================
    // GPIO Output Assignments
    // =========================================================================
    assign gpio_out    = reg_out;
    assign gpio_enable = reg_oe;

    // =========================================================================
    // Interrupt Logic
    // =========================================================================
    // Edge detection signals
    logic [GPIO_WIDTH-1:0] rising_edge_det;
    logic [GPIO_WIDTH-1:0] falling_edge_det;

    // Detect rising and falling edges on synchronized GPIO input
    assign rising_edge_det  = gpio_sync_stage2 & ~gpio_sync_prev;
    assign falling_edge_det = ~gpio_sync_stage2 & gpio_sync_prev;

    // Compute raw interrupt signals (before enable masking)
    // reg_int_type:  1 = edge-sensitive, 0 = level-sensitive
    // reg_int_pol:   1 = active-high (rising edge), 0 = active-low (falling edge)
    logic [GPIO_WIDTH-1:0] raw_int;

    genvar i;
    generate
        for (i = 0; i < GPIO_WIDTH; i++) begin : gen_raw_int
            always_comb begin
                if (reg_int_type[i]) begin
                    // Edge-sensitive
                    if (reg_int_pol[i]) begin
                        // Rising edge
                        raw_int[i] = rising_edge_det[i];
                    end else begin
                        // Falling edge
                        raw_int[i] = falling_edge_det[i];
                    end
                end else begin
                    // Level-sensitive
                    if (reg_int_pol[i]) begin
                        // Active-high level
                        raw_int[i] = gpio_sync_stage2[i];
                    end else begin
                        // Active-low level
                        raw_int[i] = ~gpio_sync_stage2[i];
                    end
                end
            end
        end
    endgenerate

    // Interrupt Status Register - captures edge interrupts; level interrupts are continuous
    // For edge-sensitive: latch and hold until cleared (sticky)
    // For level-sensitive: reflect current state
    always_ff @(posedge pclk or negedge preset_n) begin
        if (!preset_n) begin
            reg_int_stat <= '0;
        end else begin
            for (int j = 0; j < GPIO_WIDTH; j++) begin
                if (reg_int_type[j]) begin
                    // Edge-sensitive: set on edge, clear when interrupt is disabled or on read-clear
                    // For simplicity, set on edge detect; clear when interrupt enable is deasserted
                    if (raw_int[j] & reg_int_en[j]) begin
                        reg_int_stat[j] <= 1'b1;
                    end else if (!reg_int_en[j]) begin
                        reg_int_stat[j] <= 1'b0;
                    end
                end else begin
                    // Level-sensitive: continuously reflect state
                    reg_int_stat[j] <= raw_int[j] & reg_int_en[j];
                end
            end
        end
    end

    // Individual interrupt signals (masked by enable)
    always_comb begin
        for (int k = 0; k < GPIO_WIDTH; k++) begin
            if (reg_int_type[k]) begin
                // Edge-sensitive: driven by status register
                gpio_int[k] = reg_int_stat[k] & reg_int_en[k];
            end else begin
                // Level-sensitive: driven by raw signal masked by enable
                gpio_int[k] = raw_int[k] & reg_int_en[k];
            end
        end
    end

    // Combined interrupt: logical OR of all individual interrupts
    assign comb_int = |gpio_int;

endmodule

output.rtl/APBGlobalHistoryRegister.v:
// rtl/APBGlobalHistoryRegister.v

module APBGlobalHistoryRegister (
    // Clock & Reset
    input  wire       pclk,
    input  wire       presetn,

    // APB Signals
    input  wire [9:0] paddr,
    input  wire       pselx,
    input  wire       penable,
    input  wire       pwrite,
    input  wire [7:0] pwdata,
    output reg        pready,
    output reg  [7:0] prdata,
    output reg        pslverr,

    // History Shift Interface
    input  wire       history_shift_valid,

    // Clock Gating Enable
    input  wire       clk_gate_en,

    // Status & Interrupt Signals
    output wire       history_full,
    output wire       history_empty,
    output wire       error_flag,
    output wire       interrupt_full,
    output wire       interrupt_error
);

    // -------------------------------------------------------------------------
    // Internal Registers
    // -------------------------------------------------------------------------
    reg [7:0] control_register;  // Address 0x0
    reg [7:0] train_history;     // Address 0x1 (only [6:0] used)
    reg [7:0] predict_history;   // Address 0x2 (read-only via APB)

    // -------------------------------------------------------------------------
    // Clock Gating
    // -------------------------------------------------------------------------
    reg  clk_gate_en_latched;
    wire gated_clk;

    // Latch clk_gate_en on negative edge of pclk to avoid glitches
    always @(negedge pclk or negedge presetn) begin
        if (!presetn)
            clk_gate_en_latched <= 1'b0;
        else
            clk_gate_en_latched <= clk_gate_en;
    end

    // Gate the clock: when clk_gate_en_latched is high, gate pclk
    assign gated_clk = pclk & (~clk_gate_en_latched);

    // -------------------------------------------------------------------------
    // APB State Machine
    // -------------------------------------------------------------------------
    localparam IDLE        = 2'b00;
    localparam WRITE_STATE = 2'b01;
    localparam READ_STATE  = 2'b10;

    reg [1:0] apb_state;
    reg       error_flag_reg;

    // APB FSM - uses gated_clk
    always @(posedge gated_clk or negedge presetn) begin
        if (!presetn) begin
            apb_state        <= IDLE;
            pready           <= 1'b0;
            prdata           <= 8'b0;
            pslverr          <= 1'b0;
            control_register <= 8'b0;
            train_history    <= 8'b0;
            error_flag_reg   <= 1'b0;
        end else begin
            case (apb_state)
                IDLE: begin
                    pready  <= 1'b0;
                    pslverr <= 1'b0;
                    prdata  <= 8'b0;
                    error_flag_reg <= 1'b0;
                    if (pselx && !penable) begin
                        if (pwrite)
                            apb_state <= WRITE_STATE;
                        else
                            apb_state <= READ_STATE;
                    end
                end

                WRITE_STATE: begin
                    pready <= 1'b1;
                    if (pselx && penable && pwrite) begin
                        case (paddr)
                            10'h0: begin
                                control_register <= pwdata;
                                pslverr          <= 1'b0;
                                error_flag_reg   <= 1'b0;
                            end
                            10'h1: begin
                                train_history  <= pwdata;
                                pslverr        <= 1'b0;
                                error_flag_reg <= 1'b0;
                            end
                            10'h2: begin
                                // predict_history is read-only; treat as error
                                pslverr        <= 1'b1;
                                error_flag_reg <= 1'b1;
                            end
                            default: begin
                                pslverr        <= 1'b1;
                                error_flag_reg <= 1'b1;
                            end
                        endcase
                    end
                    apb_state <= IDLE;
                end

                READ_STATE: begin
                    pready <= 1'b1;
                    if (pselx && penable && !pwrite) begin
                        case (paddr)
                            10'h0: begin
                                // Reserved bits [7:4] read as 0
                                prdata         <= {4'b0, control_register[3:0]};
                                pslverr        <= 1'b0;
                                error_flag_reg <= 1'b0;
                            end
                            10'h1: begin
                                // Reserved bit [7] reads as 0
                                prdata         <= {1'b0, train_history[6:0]};
                                pslverr        <= 1'b0;
                                error_flag_reg <= 1'b0;
                            end
                            10'h2: begin
                                prdata         <= predict_history;
                                pslverr        <= 1'b0;
                                error_flag_reg <= 1'b0;
                            end
                            default: begin
                                prdata         <= 8'b0;
                                pslverr        <= 1'b1;
                                error_flag_reg <= 1'b1;
                            end
                        endcase
                    end
                    apb_state <= IDLE;
                end

                default: begin
                    apb_state <= IDLE;
                end
            endcase
        end
    end

    // -------------------------------------------------------------------------
    // Prediction History Update Logic
    // Triggered on rising edge of history_shift_valid (asynchronous to pclk)
    // -------------------------------------------------------------------------
    wire       predict_valid     = control_register[0];
    wire       predict_taken     = control_register[1];
    wire       train_mispredicted = control_register[2];
    wire       train_taken       = control_register[3];

    always @(posedge history_shift_valid or negedge presetn) begin
        if (!presetn) begin
            predict_history <= 8'b0;
        end else begin
            if (train_mispredicted) begin
                // Misprediction: restore history with actual outcome
                // {train_history[6:0], train_taken}
                predict_history <= {train_history[6:0], train_taken};
            end else if (predict_valid) begin
                // Normal update: shift in predicted direction at LSB
                predict_history <= {predict_history[6:0], predict_taken};
            end
            // If neither, no update
        end
    end

    // -------------------------------------------------------------------------
    // Status & Interrupt Signals
    // -------------------------------------------------------------------------
    assign history_full    = (predict_history == 8'hFF);
    assign history_empty   = (predict_history == 8'h00);
    assign error_flag      = error_flag_reg;
    assign interrupt_full  = history_full;
    assign interrupt_error = error_flag;

endmodule

output.rtl/barrel_shifter_8bit.sv:
module barrel_shifter_8bit (
    input  logic [7:0] data_in,
    input  logic [2:0] shift_bits,
    input  logic       left_right,
    output logic [7:0] data_out
);

    always_comb begin
        if (left_right)
            data_out = data_in << shift_bits;
        else
            data_out = data_in >> shift_bits;
    end

endmodule

output.rtl/bcd_counter.sv:
module bcd_counter (
    input  logic        clk,
    input  logic        rst,
    output logic [3:0]  ms_hr,
    output logic [3:0]  ls_hr,
    output logic [3:0]  ms_min,
    output logic [3:0]  ls_min,
    output logic [3:0]  ms_sec,
    output logic [3:0]  ls_sec
);

    always_ff @(posedge clk) begin
        if (rst) begin
            ms_hr  <= 4'd0;
            ls_hr  <= 4'd0;
            ms_min <= 4'd0;
            ls_min <= 4'd0;
            ms_sec <= 4'd0;
            ls_sec <= 4'd0;
        end else begin
            // Increment seconds
            if (ls_sec == 4'd9) begin
                ls_sec <= 4'd0;
                if (ms_sec == 4'd5) begin
                    ms_sec <= 4'd0;
                    // Increment minutes
                    if (ls_min == 4'd9) begin
                        ls_min <= 4'd0;
                        if (ms_min == 4'd5) begin
                            ms_min <= 4'd0;
                            // Increment hours
                            if (ms_hr == 4'd2 && ls_hr == 4'd3) begin
                                // Reset to 00:00:00
                                ms_hr <= 4'd0;
                                ls_hr <= 4'd0;
                            end else if (ls_hr == 4'd9) begin
                                ls_hr <= 4'd0;
                                ms_hr <= ms_hr + 4'd1;
                            end else begin
                                ls_hr <= ls_hr + 4'd1;
                            end
                        end else begin
                            ms_min <= ms_min + 4'd1;
                        end
                    end else begin
                        ls_min <= ls_min + 4'd1;
                    end
                end else begin
                    ms_sec <= ms_sec + 4'd1;
                end
            end else begin
                ls_sec <= ls_sec + 4'd1;
            end
        end
    end

endmodule

output.rtl/axi_register.sv:
module axi_register #(
    parameter int ADDR_WIDTH = 32,
    parameter int DATA_WIDTH = 32
)(
    input  logic                        clk_i,
    input  logic                        rst_n_i,

    // Write Address Channel
    input  logic [ADDR_WIDTH-1:0]       awaddr_i,
    input  logic                        awvalid_i,
    output logic                        awready_o,

    // Write Data Channel
    input  logic [DATA_WIDTH-1:0]       wdata_i,
    input  logic                        wvalid_i,
    input  logic [(DATA_WIDTH/8)-1:0]   wstrb_i,
    output logic                        wready_o,

    // Write Response Channel
    output logic [1:0]                  bresp_o,
    output logic                        bvalid_o,
    input  logic                        bready_i,

    // Read Address Channel
    input  logic [ADDR_WIDTH-1:0]       araddr_i,
    input  logic                        arvalid_i,
    output logic                        arready_o,

    // Read Data Channel
    output logic [DATA_WIDTH-1:0]       rdata_o,
    output logic                        rvalid_o,
    output logic [1:0]                  rresp_o,
    input  logic                        rready_i,

    // Hardware Interface
    input  logic                        done_i,
    output logic [19:0]                 beat_o,
    output logic                        start_o,
    output logic                        writeback_o
);

    // Fixed ID value
    localparam logic [31:0] ID_VALUE = 32'h0001_0001;

    // Register offsets
    localparam logic [11:0] BEAT_OFFSET      = 12'h100;
    localparam logic [11:0] START_OFFSET     = 12'h200;
    localparam logic [11:0] DONE_OFFSET      = 12'h300;
    localparam logic [11:0] WRITEBACK_OFFSET = 12'h400;
    localparam logic [11:0] ID_OFFSET        = 12'h500;

    // Internal registers
    logic [19:0]            beat_reg;
    logic                   start_reg;
    logic                   done_reg;
    logic                   writeback_reg;

    // Write state machine
    typedef enum logic [1:0] {
        WR_IDLE,
        WR_ADDR,
        WR_DATA,
        WR_RESP
    } wr_state_t;

    wr_state_t wr_state;

    // Read state machine
    typedef enum logic [1:0] {
        RD_IDLE,
        RD_ADDR,
        RD_DATA
    } rd_state_t;

    rd_state_t rd_state;

    // Latched addresses
    logic [ADDR_WIDTH-1:0]  awaddr_lat;
    logic [ADDR_WIDTH-1:0]  araddr_lat;

    // Latched write data
    logic [DATA_WIDTH-1:0]  wdata_lat;
    logic [(DATA_WIDTH/8)-1:0] wstrb_lat;

    // Write response
    logic [1:0]             bresp_lat;

    // Sync done_i to internal register
    always_ff @(posedge clk_i or negedge rst_n_i) begin
        if (!rst_n_i) begin
            done_reg <= 1'b0;
        end else begin
            if (done_i) begin
                done_reg <= 1'b1;
            end
        end
    end

    // -----------------------------------------------------------------------
    // Write State Machine
    // -----------------------------------------------------------------------
    always_ff @(posedge clk_i or negedge rst_n_i) begin
        if (!rst_n_i) begin
            wr_state     <= WR_IDLE;
            awready_o    <= 1'b0;
            wready_o     <= 1'b0;
            bvalid_o     <= 1'b0;
            bresp_o      <= 2'b00;
            bresp_lat    <= 2'b00;
            awaddr_lat   <= '0;
            wdata_lat    <= '0;
            wstrb_lat    <= '0;
            beat_reg     <= 20'h0;
            start_reg    <= 1'b0;
            writeback_reg<= 1'b0;
        end else begin
            case (wr_state)
                WR_IDLE: begin
                    awready_o <= 1'b0;
                    wready_o  <= 1'b0;
                    bvalid_o  <= 1'b0;
                    if (awvalid_i) begin
                        awaddr_lat <= awaddr_i;
                        awready_o  <= 1'b1;
                        wr_state   <= WR_ADDR;
                    end
                end

                WR_ADDR: begin
                    awready_o <= 1'b0;
                    wready_o  <= 1'b1;
                    wr_state  <= WR_DATA;
                end

                WR_DATA: begin
                    if (wvalid_i) begin
                        wready_o  <= 1'b0;
                        wdata_lat <= wdata_i;
                        wstrb_lat <= wstrb_i;

                        // Determine if full write (all strobe bits set)
                        logic full_write;
                        full_write = &wstrb_i;

                        // Default response
                        bresp_lat <= 2'b00;

                        // Decode address and update registers
                        case (awaddr_lat[11:0])
                            BEAT_OFFSET: begin
                                if (full_write) begin
                                    beat_reg  <= wdata_i[19:0];
                                    bresp_lat <= 2'b00;
                                end else begin
                                    bresp_lat <= 2'b00; // partial write, no update
                                end
                            end

                            START_OFFSET: begin
                                if (full_write) begin
                                    start_reg <= wdata_i[0];
                                    bresp_lat <= 2'b00;
                                end else begin
                                    bresp_lat <= 2'b00;
                                end
                            end

                            DONE_OFFSET: begin
                                if (full_write) begin
                                    if (wdata_i[0]) begin
                                        done_reg <= 1'b0;
                                    end
                                    bresp_lat <= 2'b00;
                                end else begin
                                    bresp_lat <= 2'b00;
                                end
                            end

                            WRITEBACK_OFFSET: begin
                                if (full_write) begin
                                    writeback_reg <= wdata_i[0];
                                    bresp_lat     <= 2'b00;
                                end else begin
                                    bresp_lat <= 2'b00;
                                end
                            end

                            ID_OFFSET: begin
                                // Read-only register: return SLVERR
                                bresp_lat <= 2'b10;
                            end

                            default: begin
                                // Invalid address
                                bresp_lat <= 2'b10;
                            end
                        endcase

                        bvalid_o  <= 1'b1;
                        bresp_o   <= bresp_lat;
                        wr_state  <= WR_RESP;
                    end
                end

                WR_RESP: begin
                    bresp_o <= bresp_lat;
                    if (bready_i) begin
                        bvalid_o  <= 1'b0;
                        wr_state  <= WR_IDLE;
                    end
                end

                default: begin
                    wr_state <= WR_IDLE;
                end
            endcase
        end
    end

    // -----------------------------------------------------------------------
    // Read State Machine
    // -----------------------------------------------------------------------
    always_ff @(posedge clk_i or negedge rst_n_i) begin
        if (!rst_n_i) begin
            rd_state   <= RD_IDLE;
            arready_o  <= 1'b0;
            rvalid_o   <= 1'b0;
            rdata_o    <= '0;
            rresp_o    <= 2'b00;
            araddr_lat <= '0;
        end else begin
            case (rd_state)
                RD_IDLE: begin
                    arready_o <= 1'b0;
                    rvalid_o  <= 1'b0;
                    if (arvalid_i) begin
                        araddr_lat <= araddr_i;
                        arready_o  <= 1'b1;
                        rd_state   <= RD_ADDR;
                    end
                end

                RD_ADDR: begin
                    arready_o <= 1'b0;

                    // Decode read address and prepare data
                    case (araddr_lat[11:0])
                        BEAT_OFFSET: begin
                            rdata_o  <= {{(DATA_WIDTH-20){1'b0}}, beat_reg};
                            rresp_o  <= 2'b00;
                        end

                        START_OFFSET: begin
                            rdata_o  <= {{(DATA_WIDTH-1){1'b0}}, start_reg};
                            rresp_o  <= 2'b00;
                        end

                        DONE_OFFSET: begin
                            rdata_o  <= {{(DATA_WIDTH-1){1'b0}}, done_reg};
                            rresp_o  <= 2'b00;
                        end

                        WRITEBACK_OFFSET: begin
                            rdata_o  <= {{(DATA_WIDTH-1){1'b0}}, writeback_reg};
                            rresp_o  <= 2'b00;
                        end

                        ID_OFFSET: begin
                            rdata_o  <= {{(DATA_WIDTH-32){1'b0}}, ID_VALUE};
                            rresp_o  <= 2'b00;
                        end

                        default: begin
                            rdata_o  <= '0;
                            rresp_o  <= 2'b10;
                        end
                    endcase

                    rvalid_o <= 1'b1;
                    rd_state <= RD_DATA;
                end

                RD_DATA: begin
                    if (rready_i) begin
                        rvalid_o <= 1'b0;
                        rd_state <= RD_IDLE;
                    end
                end

                default: begin
                    rd_state <= RD_IDLE;
                end
            endcase
        end
    end

    // -----------------------------------------------------------------------
    // Output assignments
    // -----------------------------------------------------------------------
    assign beat_o      = beat_reg;
    assign start_o     = start_reg;
    assign writeback_o = writeback_reg;

endmodule

output.rtl/bcd_to_excess_3.sv:
module bcd_to_excess_3 (
    input  logic [3:0] bcd,
    output logic [3:0] excess3,
    output logic       error
);

    always_comb begin
        if (bcd > 4'd9) begin
            excess3 = 4'b0000;
            error   = 1'b1;
        end else begin
            excess3 = bcd + 4'd3;
            error   = 1'b0;
        end
    end

endmodule

output.rtl/binary_to_one_hot_decoder.v:
module binary_to_one_hot_decoder #(
    parameter BINARY_WIDTH = 5,
    parameter OUTPUT_WIDTH = 32
)(
    input  [BINARY_WIDTH-1:0] binary_in,
    output [OUTPUT_WIDTH-1:0] one_hot_out
);

    assign one_hot_out = (binary_in < OUTPUT_WIDTH) ? ({{(OUTPUT_WIDTH-1){1'b0}}, 1'b1} << binary_in) : {OUTPUT_WIDTH{1'b0}};

endmodule

output.rtl/caesar_cipher.sv:
module caesar_cipher (
    input  logic [7:0] input_char,
    input  logic [3:0] key,
    output logic [7:0] output_char
);

    always_comb begin
        if (input_char >= 8'd65 && input_char <= 8'd90) begin
            // Uppercase letter A-Z
            output_char = ((input_char - 8'd65 + {4'b0000, key}) % 8'd26) + 8'd65;
        end else if (input_char >= 8'd97 && input_char <= 8'd122) begin
            // Lowercase letter a-z
            output_char = ((input_char - 8'd97 + {4'b0000, key}) % 8'd26) + 8'd97;
        end else begin
            // Non-alphabetic character
            output_char = input_char;
        end
    end

endmodule

output.rtl/axis_joiner.sv:
module axis_joiner (
    input  logic        clk,
    input  logic        rst,

    // AXI Stream Input 1
    input  logic [7:0]  s_axis_tdata_1,
    input  logic        s_axis_tvalid_1,
    output logic        s_axis_tready_1,
    input  logic        s_axis_tlast_1,

    // AXI Stream Input 2
    input  logic [7:0]  s_axis_tdata_2,
    input  logic        s_axis_tvalid_2,
    output logic        s_axis_tready_2,
    input  logic        s_axis_tlast_2,

    // AXI Stream Input 3
    input  logic [7:0]  s_axis_tdata_3,
    input  logic        s_axis_tvalid_3,
    output logic        s_axis_tready_3,
    input  logic        s_axis_tlast_3,

    // AXI Stream Output
    output logic [7:0]  m_axis_tdata,
    output logic        m_axis_tvalid,
    input  logic        m_axis_tready,
    output logic        m_axis_tlast,
    output logic [1:0]  m_axis_tuser,

    // Status
    output logic        busy
);

    // FSM States
    typedef enum logic [1:0] {
        STATE_IDLE = 2'b00,
        STATE_1    = 2'b01,
        STATE_2    = 2'b10,
        STATE_3    = 2'b11
    } state_t;

    // TAG IDs
    localparam logic [1:0] TAG_ID_1 = 2'h1;
    localparam logic [1:0] TAG_ID_2 = 2'h2;
    localparam logic [1:0] TAG_ID_3 = 2'h3;

    state_t current_state, next_state;

    // Internal registers for buffering
    logic [7:0] temp_data;
    logic        temp_valid;
    logic        temp_last;
    logic [1:0]  temp_user;
    logic        temp_flag;

    // MUX signals
    logic [7:0]  mux_tdata;
    logic        mux_tvalid;
    logic        mux_tlast;
    logic [1:0]  mux_tuser;

    // FSM Sequential Logic
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            current_state <= STATE_IDLE;
        end else begin
            current_state <= next_state;
        end
    end

    // FSM Next State Logic
    always_comb begin
        next_state = current_state;
        case (current_state)
            STATE_IDLE: begin
                if (s_axis_tvalid_1)
                    next_state = STATE_1;
                else if (s_axis_tvalid_2)
                    next_state = STATE_2;
                else if (s_axis_tvalid_3)
                    next_state = STATE_3;
                else
                    next_state = STATE_IDLE;
            end
            STATE_1: begin
                // Stay in STATE_1 until tlast is transferred
                if (s_axis_tvalid_1 && s_axis_tlast_1 && (m_axis_tready || !temp_flag))
                    next_state = STATE_IDLE;
                else if (temp_flag && temp_last && m_axis_tready)
                    next_state = STATE_IDLE;
            end
            STATE_2: begin
                if (s_axis_tvalid_2 && s_axis_tlast_2 && (m_axis_tready || !temp_flag))
                    next_state = STATE_IDLE;
                else if (temp_flag && temp_last && m_axis_tready)
                    next_state = STATE_IDLE;
            end
            STATE_3: begin
                if (s_axis_tvalid_3 && s_axis_tlast_3 && (m_axis_tready || !temp_flag))
                    next_state = STATE_IDLE;
                else if (temp_flag && temp_last && m_axis_tready)
                    next_state = STATE_IDLE;
            end
            default: next_state = STATE_IDLE;
        endcase
    end

    // MUX: Select input based on current state
    always_comb begin
        case (current_state)
            STATE_1: begin
                mux_tdata  = s_axis_tdata_1;
                mux_tvalid = s_axis_tvalid_1;
                mux_tlast  = s_axis_tlast_1;
                mux_tuser  = TAG_ID_1;
            end
            STATE_2: begin
                mux_tdata  = s_axis_tdata_2;
                mux_tvalid = s_axis_tvalid_2;
                mux_tlast  = s_axis_tlast_2;
                mux_tuser  = TAG_ID_2;
            end
            STATE_3: begin
                mux_tdata  = s_axis_tdata_3;
                mux_tvalid = s_axis_tvalid_3;
                mux_tlast  = s_axis_tlast_3;
                mux_tuser  = TAG_ID_3;
            end
            default: begin
                mux_tdata  = 8'h00;
                mux_tvalid = 1'b0;
                mux_tlast  = 1'b0;
                mux_tuser  = 2'h0;
            end
        endcase
    end

    // Buffering Logic and Output Assignment
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            temp_data  <= 8'h00;
            temp_valid <= 1'b0;
            temp_last  <= 1'b0;
            temp_user  <= 2'h0;
            temp_flag  <= 1'b0;
        end else begin
            if (temp_flag) begin
                // We have buffered data waiting to be sent
                if (m_axis_tready) begin
                    // Buffered data has been consumed
                    temp_flag  <= 1'b0;
                    temp_valid <= 1'b0;
                end
            end else begin
                // No buffered data
                if (mux_tvalid && !m_axis_tready && current_state != STATE_IDLE) begin
                    // Need to buffer the data since downstream is not ready
                    temp_data  <= mux_tdata;
                    temp_valid <= mux_tvalid;
                    temp_last  <= mux_tlast;
                    temp_user  <= mux_tuser;
                    temp_flag  <= 1'b1;
                end
            end
        end
    end

