module car_parking_system #(
    parameter TOTAL_SPACES = 12
)(
    input  logic clk,
    input  logic reset,
    input  logic vehicle_entry_sensor,
    input  logic vehicle_exit_sensor,
    output logic [$clog2(TOTAL_SPACES)-1:0] available_spaces,
    output logic [$clog2(TOTAL_SPACES)-1:0] count_car,
    output logic led_status,
    output logic [6:0] seven_seg_display_available_tens,
    output logic [6:0] seven_seg_display_available_units,
    output logic [6:0] seven_seg_display_count_tens,
    output logic [6:0] seven_seg_display_count_units
);

    // FSM State Encoding
    typedef enum logic [1:0] {
        IDLE            = 2'b00,
        ENTRY_PROCESSING = 2'b01,
        EXIT_PROCESSING  = 2'b10,
        FULL            = 2'b11
    } state_t;

    state_t current_state, next_state;

    // Internal registers
    logic [$clog2(TOTAL_SPACES):0] avail_spaces_reg;
    logic [$clog2(TOTAL_SPACES):0] count_car_reg;

    // 7-segment encoding function
    // MSB = segment A, LSB = segment G
    // Segments: A B C D E F G
    function automatic [6:0] seven_seg_encode(input [3:0] digit);
        case (digit)
            4'd0: seven_seg_encode = 7'b1111110; // 0
            4'd1: seven_seg_encode = 7'b0110000; // 1
            4'd2: seven_seg_encode = 7'b1101101; // 2
            4'd3: seven_seg_encode = 7'b1111001; // 3
            4'd4: seven_seg_encode = 7'b0110011; // 4
            4'd5: seven_seg_encode = 7'b1011011; // 5
            4'd6: seven_seg_encode = 7'b1011111; // 6
            4'd7: seven_seg_encode = 7'b1110000; // 7
            4'd8: seven_seg_encode = 7'b1111111; // 8
            4'd9: seven_seg_encode = 7'b1111011; // 9
            default: seven_seg_encode = 7'b0000000;
        endcase
    endfunction

    // FSM State Register (synchronous with async reset)
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            current_state <= IDLE;
        end else begin
            current_state <= next_state;
        end
    end

    // FSM Next State Logic
    always_comb begin
        next_state = current_state;
        case (current_state)
            IDLE: begin
                if (vehicle_entry_sensor && !vehicle_exit_sensor) begin
                    if (avail_spaces_reg > 0) begin
                        next_state = ENTRY_PROCESSING;
                    end else begin
                        next_state = FULL;
                    end
                end else if (vehicle_exit_sensor && !vehicle_entry_sensor) begin
                    if (count_car_reg > 0) begin
                        next_state = EXIT_PROCESSING;
                    end else begin
                        next_state = IDLE;
                    end
                end else begin
                    next_state = IDLE;
                end
            end
            ENTRY_PROCESSING: begin
                next_state = IDLE;
            end
            EXIT_PROCESSING: begin
                next_state = IDLE;
            end
            FULL: begin
                if (vehicle_exit_sensor) begin
                    next_state = EXIT_PROCESSING;
                end else begin
                    next_state = IDLE;
                end
            end
            default: next_state = IDLE;
        endcase
    end

    // Datapath: Update counters
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            avail_spaces_reg <= TOTAL_SPACES;
            count_car_reg    <= 0;
        end else begin
            case (current_state)
                ENTRY_PROCESSING: begin
                    if (avail_spaces_reg > 0) begin
                        avail_spaces_reg <= avail_spaces_reg - 1;
                        count_car_reg    <= count_car_reg + 1;
                    end
                end
                EXIT_PROCESSING: begin
                    if (count_car_reg > 0) begin
                        avail_spaces_reg <= avail_spaces_reg + 1;
                        count_car_reg    <= count_car_reg - 1;
                    end
                end
                default: begin
                    avail_spaces_reg <= avail_spaces_reg;
                    count_car_reg    <= count_car_reg;
                end
            endcase
        end
    end

    // Output assignments
    assign available_spaces = avail_spaces_reg[$clog2(TOTAL_SPACES)-1:0];
    assign count_car        = count_car_reg[$clog2(TOTAL_SPACES)-1:0];
    assign led_status       = (avail_spaces_reg > 0) ? 1'b1 : 1'b0;

    // 7-segment display for available spaces
    logic [3:0] avail_tens, avail_units;
    logic [3:0] count_tens, count_units;

    always_comb begin
        avail_tens  = (avail_spaces_reg / 10) % 10;
        avail_units = avail_spaces_reg % 10;
        count_tens  = (count_car_reg / 10) % 10;
        count_units = count_car_reg % 10;
    end

    assign seven_seg_display_available_tens  = seven_seg_encode(avail_tens);
    assign seven_seg_display_available_units = seven_seg_encode(avail_units);
    assign seven_seg_display_count_tens      = seven_seg_encode(count_tens);
    assign seven_seg_display_count_units     = seven_seg_encode(count_units);

endmodule

output.rtl/signed_comparator.sv:
// -----------------------------------------------------------------------------
// Module: signed_unsigned_comparator
// Description: A fully parameterized combinational comparator that supports
//              two comparison modes:
//              - Signed Mode   (i_mode = 1): Interprets inputs as signed integers
//              - Magnitude Mode (i_mode = 0): Ignores sign bit, treats as unsigned
//
// Parameters:
//   WIDTH : Bit-width of the input operands (default: 5)
//
// Inputs:
//   i_A      : WIDTH-bit input operand A
//   i_B      : WIDTH-bit input operand B
//   i_enable : Enable signal (active high); when low, all outputs are deasserted
//   i_mode   : Mode select; high = signed mode, low = magnitude mode
//
// Outputs:
//   o_greater : High when i_A > i_B (and i_enable is high)
//   o_less    : High when i_A < i_B (and i_enable is high)
//   o_equal   : High when i_A == i_B (and i_enable is high)
// -----------------------------------------------------------------------------

module signed_unsigned_comparator #(
    parameter int WIDTH = 5
)(
    input  logic [WIDTH-1:0] i_A,
    input  logic [WIDTH-1:0] i_B,
    input  logic             i_enable,
    input  logic             i_mode,
    output logic             o_greater,
    output logic             o_less,
    output logic             o_equal
);

    // Internal signals for signed and unsigned interpretations
    logic signed   [WIDTH-1:0] A_signed;
    logic signed   [WIDTH-1:0] B_signed;
    logic unsigned [WIDTH-2:0] A_magnitude;
    logic unsigned [WIDTH-2:0] B_magnitude;

    // Assign signed views of the inputs
    assign A_signed   = $signed(i_A);
    assign B_signed   = $signed(i_B);

    // Magnitude: strip the MSB (sign bit) and compare remaining bits
    assign A_magnitude = i_A[WIDTH-2:0];
    assign B_magnitude = i_B[WIDTH-2:0];

    // Combinational comparison logic
    always_comb begin
        // Default: all outputs deasserted
        o_greater = 1'b0;
        o_less    = 1'b0;
        o_equal   = 1'b0;

        if (i_enable) begin
            if (i_mode) begin
                // -----------------------------------------------
                // Signed Mode: MSB is the sign bit
                // -----------------------------------------------
                if (A_signed > B_signed) begin
                    o_greater = 1'b1;
                    o_less    = 1'b0;
                    o_equal   = 1'b0;
                end else if (A_signed < B_signed) begin
                    o_greater = 1'b0;
                    o_less    = 1'b1;
                    o_equal   = 1'b0;
                end else begin
                    // A_signed == B_signed
                    o_greater = 1'b0;
                    o_less    = 1'b0;
                    o_equal   = 1'b1;
                end
            end else begin
                // -----------------------------------------------
                // Magnitude Mode: ignore the sign bit (MSB),
                // compare only the lower (WIDTH-1) bits
                // -----------------------------------------------
                if (A_magnitude > B_magnitude) begin
                    o_greater = 1'b1;
                    o_less    = 1'b0;
                    o_equal   = 1'b0;
                end else if (A_magnitude < B_magnitude) begin
                    o_greater = 1'b0;
                    o_less    = 1'b1;
                    o_equal   = 1'b0;
                end else begin
                    // A_magnitude == B_magnitude
                    o_greater = 1'b0;
                    o_less    = 1'b0;
                    o_equal   = 1'b1;
                end
            end
        end
        // When i_enable is low, outputs remain 0 (default)
    end

endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter #(
    parameter int DATA_WIDTH = 16,
    parameter int COEFF_WIDTH = 16,
    parameter int NUM_TAPS = 8,
    parameter int NBW_MULT = DATA_WIDTH + COEFF_WIDTH
)(
    input  logic                                        clk,
    input  logic                                        reset,
    input  logic [DATA_WIDTH*NUM_TAPS-1:0]              data_in,
    input  logic                                        valid_in,
    input  logic [COEFF_WIDTH*NUM_TAPS-1:0]             coeffs,
    output logic [NBW_MULT+$clog2(NUM_TAPS)-1:0]        data_out,
    output logic                                        valid_out
);

    // Internal registered arrays
    logic signed [DATA_WIDTH-1:0]  data_reg  [0:NUM_TAPS-1];
    logic signed [COEFF_WIDTH-1:0] coeff_reg [0:NUM_TAPS-1];

    // Intermediate multiplication results
    logic signed [NBW_MULT-1:0] mult_results [0:NUM_TAPS-1];

    // Summation result
    logic signed [NBW_MULT+$clog2(NUM_TAPS)-1:0] sum_result;

    // Sequential: Register input data and coefficients when valid_in is high
    always_ff @(posedge clk) begin
        if (reset) begin
            for (int i = 0; i < NUM_TAPS; i++) begin
                data_reg[i]  <= '0;
                coeff_reg[i] <= '0;
            end
        end else if (valid_in) begin
            for (int i = 0; i < NUM_TAPS; i++) begin
                data_reg[i]  <= signed'(data_in[i*DATA_WIDTH +: DATA_WIDTH]);
                coeff_reg[i] <= signed'(coeffs[i*COEFF_WIDTH +: COEFF_WIDTH]);
            end
        end
    end

    // Sequential: Register valid_out
    always_ff @(posedge clk) begin
        if (reset) begin
            valid_out <= 1'b0;
        end else begin
            valid_out <= valid_in;
        end
    end

    // Combinational: Element-wise multiplication with reversed coefficients
    // data_reg[i] * coeff_reg[NUM_TAPS-1-i]
    always_comb begin
        for (int i = 0; i < NUM_TAPS; i++) begin
            mult_results[i] = data_reg[i] * coeff_reg[NUM_TAPS-1-i];
        end
    end

    // Combinational: Summation of all multiplication results
    always_comb begin
        sum_result = '0;
        for (int i = 0; i < NUM_TAPS; i++) begin
            sum_result = sum_result + {{($clog2(NUM_TAPS)){mult_results[i][NBW_MULT-1]}}, mult_results[i]};
        end
    end

    // Combinational: Output assignment
    assign data_out = sum_result;

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor (
    input  wire        i_clk,
    input  wire        i_rst_n,
    input  wire        i_enable,
    input  wire        i_clear,
    input  wire        i_ack,
    input  wire        i_fault,
    input  wire [4:0]  i_vector_1,
    input  wire [4:0]  i_vector_2,
    input  wire [4:0]  i_vector_3,
    input  wire [4:0]  i_vector_4,
    input  wire [4:0]  i_vector_5,
    input  wire [4:0]  i_vector_6,
    output reg         o_ready,
    output reg         o_error,
    output reg  [1:0]  o_fsm_status,
    output reg  [7:0]  o_vector_1,
    output reg  [7:0]  o_vector_2,
    output reg  [7:0]  o_vector_3,
    output reg  [7:0]  o_vector_4
);

    // State encoding
    localparam [1:0] IDLE    = 2'b00;
    localparam [1:0] PROCESS = 2'b01;
    localparam [1:0] READY   = 2'b10;
    localparam [1:0] FAULT   = 2'b11;

    reg [1:0] current_state;

    // 32-bit concatenation bus
    wire [31:0] concat_bus;
    assign concat_bus = {i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11};

    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            current_state <= IDLE;
            o_ready       <= 1'b0;
            o_error       <= 1'b0;
            o_fsm_status  <= IDLE;
            o_vector_1    <= 8'h00;
            o_vector_2    <= 8'h00;
            o_vector_3    <= 8'h00;
            o_vector_4    <= 8'h00;
        end else begin
            case (current_state)
                IDLE: begin
                    o_ready      <= 1'b0;
                    o_error      <= 1'b0;
                    o_vector_1   <= 8'h00;
                    o_vector_2   <= 8'h00;
                    o_vector_3   <= 8'h00;
                    o_vector_4   <= 8'h00;
                    if (i_fault) begin
                        current_state <= FAULT;
                        o_fsm_status  <= FAULT;
                        o_error       <= 1'b1;
                    end else if (i_enable) begin
                        current_state <= PROCESS;
                        o_fsm_status  <= PROCESS;
                    end
                end

                PROCESS: begin
                    if (i_fault) begin
                        current_state <= FAULT;
                        o_fsm_status  <= FAULT;
                        o_error       <= 1'b1;
                        o_vector_1    <= 8'h00;
                        o_vector_2    <= 8'h00;
                        o_vector_3    <= 8'h00;
                        o_vector_4    <= 8'h00;
                    end else begin
                        // Perform concatenation and splitting
                        o_vector_1    <= concat_bus[31:24];
                        o_vector_2    <= concat_bus[23:16];
                        o_vector_3    <= concat_bus[15:8];
                        o_vector_4    <= concat_bus[7:0];
                        current_state <= READY;
                        o_fsm_status  <= READY;
                    end
                end

                READY: begin
                    if (i_fault) begin
                        current_state <= FAULT;
                        o_fsm_status  <= FAULT;
                        o_error       <= 1'b1;
                        o_ready       <= 1'b0;
                        o_vector_1    <= 8'h00;
                        o_vector_2    <= 8'h00;
                        o_vector_3    <= 8'h00;
                        o_vector_4    <= 8'h00;
                    end else begin
                        o_ready <= 1'b1;
                        if (i_ack) begin
                            current_state <= IDLE;
                            o_fsm_status  <= IDLE;
                            o_ready       <= 1'b0;
                        end
                    end
                end

                FAULT: begin
                    o_error    <= 1'b1;
                    o_ready    <= 1'b0;
                    o_vector_1 <= 8'h00;
                    o_vector_2 <= 8'h00;
                    o_vector_3 <= 8'h00;
                    o_vector_4 <= 8'h00;
                    if (i_clear && !i_fault) begin
                        current_state <= IDLE;
                        o_fsm_status  <= IDLE;
                        o_error       <= 1'b0;
                    end
                end

                default: begin
                    current_state <= IDLE;
                    o_fsm_status  <= IDLE;
                    o_ready       <= 1'b0;
                    o_error       <= 1'b0;
                    o_vector_1    <= 8'h00;
                    o_vector_2    <= 8'h00;
                    o_vector_3    <= 8'h00;
                    o_vector_4    <= 8'h00;
                end
            endcase
        end
    end

endmodule

output.rtl/convolutional_encoder.sv:
module convolutional_encoder (
    input  logic clk,
    input  logic rst,
    input  logic data_in,
    output logic encoded_bit1,
    output logic encoded_bit2
);

    // Shift register to hold previous bits (constraint length K=3, so 2 memory bits)
    logic [1:0] shift_reg;

    // Update shift register on clock edge
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            shift_reg    <= 2'b00;
            encoded_bit1 <= 1'b0;
            encoded_bit2 <= 1'b0;
        end else begin
            // Shift register: shift_reg[1] holds bit from 2 clocks ago,
            // shift_reg[0] holds bit from 1 clock ago
            shift_reg[1] <= shift_reg[0];
            shift_reg[0] <= data_in;

            // g1 = "111" => x^2 + x + 1 => XOR of data_in, shift_reg[0], shift_reg[1]
            encoded_bit1 <= data_in ^ shift_reg[0] ^ shift_reg[1];

            // g2 = "101" => x^2 + 1 => XOR of data_in and shift_reg[1]
            encoded_bit2 <= data_in ^ shift_reg[1];
        end
    end

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection #(
    parameter int N          = 8,
    parameter int DATA_WIDTH = 16,
    parameter int DEC_FACTOR = 4
)(
    input  logic                              clk,
    input  logic                              reset,
    input  logic                              valid_in,
    input  logic [DATA_WIDTH*N-1:0]           data_in,
    output logic                              valid_out,
    output logic [DATA_WIDTH*(N/DEC_FACTOR)-1:0] data_out,
    output logic [DATA_WIDTH-1:0]             peak_value
);

    localparam int DEC_N = N / DEC_FACTOR;

    // Registered input data
    logic [DATA_WIDTH*N-1:0] data_reg;

    // Unpacked input samples
    logic signed [DATA_WIDTH-1:0] samples [0:N-1];

    // Decimated samples
    logic signed [DATA_WIDTH-1:0] dec_samples [0:DEC_N-1];

    // 1) Input Data Registering
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_reg <= '0;
        end else begin
            data_reg <= data_in;
        end
    end

    // 2) Input Unpacking (combinational)
    // data_in is packed as {sample[0], sample[1], ..., sample[N-1]}
    // where sample[0] occupies the most significant bits
    always_comb begin
        for (int i = 0; i < N; i++) begin
            samples[i] = signed'(data_reg[(N-1-i)*DATA_WIDTH +: DATA_WIDTH]);
        end
    end

    // 3) Decimation (combinational)
    // Select every DEC_FACTOR-th sample starting from index 0
    always_comb begin
        for (int i = 0; i < DEC_N; i++) begin
            dec_samples[i] = samples[i * DEC_FACTOR];
        end
    end

    // 4) Peak Detection (combinational)
    always_comb begin
        peak_value = dec_samples[0];
        for (int i = 1; i < DEC_N; i++) begin
            if (dec_samples[i] > signed'(peak_value)) begin
                peak_value = dec_samples[i];
            end
        end
    end

    // 5) Output Packing (combinational)
    always_comb begin
        for (int i = 0; i < DEC_N; i++) begin
            data_out[(DEC_N-1-i)*DATA_WIDTH +: DATA_WIDTH] = dec_samples[i];
        end
    end

    // 6) Validation Control (sequential)
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            valid_out <= 1'b0;
        end else begin
            valid_out <= valid_in;
        end
    end

endmodule

output.rtl/fsm_linear_reg.sv:
module fsm_linear_reg #(
    parameter DATA_WIDTH = 16
)(
    input  logic                        clk,
    input  logic                        reset,
    input  logic                        start,
    input  logic signed [DATA_WIDTH-1:0] x_in,
    input  logic signed [DATA_WIDTH-1:0] w_in,
    input  logic signed [DATA_WIDTH-1:0] b_in,
    output logic signed [2*DATA_WIDTH-1:0] result1,
    output logic signed [DATA_WIDTH:0]     result2,
    output logic                           done
);

    // State encoding
    typedef enum logic [1:0] {
        IDLE    = 2'b00,
        COMPUTE = 2'b01,
        DONE    = 2'b10
    } state_t;

    state_t current_state, next_state;

    // Internal computation signals
    logic signed [2*DATA_WIDTH-1:0] result1_next;
    logic signed [DATA_WIDTH:0]     result2_next;

    // State register (synchronous with async reset)
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            current_state <= IDLE;
        end else begin
            current_state <= next_state;
        end
    end

    // Next state logic
    always_comb begin
        case (current_state)
            IDLE:    next_state = start ? COMPUTE : IDLE;
            COMPUTE: next_state = DONE;
            DONE:    next_state = IDLE;
            default: next_state = IDLE;
        endcase
    end

    // Combinational computation
    always_comb begin
        // result1 = w_in * x_in >>> 1
        result1_next = ({{DATA_WIDTH{w_in[DATA_WIDTH-1]}}, w_in} * {{DATA_WIDTH{x_in[DATA_WIDTH-1]}}, x_in}) >>> 1;
        // result2 = b_in + (x_in >>> 2)
        result2_next = {{1{b_in[DATA_WIDTH-1]}}, b_in} + {{1{x_in[DATA_WIDTH-1]}}, x_in} >>> 2;
    end

    // Output registers
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            result1 <= '0;
            result2 <= '0;
            done    <= 1'b0;
        end else begin
            case (current_state)
                IDLE: begin
                    result1 <= '0;
                    result2 <= '0;
                    done    <= 1'b0;
                end
                COMPUTE: begin
                    result1 <= result1_next;
                    result2 <= result2_next;
                    done    <= 1'b0;
                end
                DONE: begin
                    done <= 1'b1;
                end
                default: begin
                    result1 <= '0;
                    result2 <= '0;
                    done    <= 1'b0;
                end
            endcase
        end
    end

endmodule

output.rtl/data_width_converter.sv:
module data_width_converter (
    input  logic        clk,
    input  logic        reset,
    input  logic [31:0] data_in,
    input  logic        data_valid,
    output logic [127:0] o_data_out,
    output logic        o_data_out_valid
);

    logic [31:0] buffer [0:3];
    logic [1:0]  count;

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            count            <= 2'd0;
            o_data_out       <= 128'd0;
            o_data_out_valid <= 1'b0;
            buffer[0]        <= 32'd0;
            buffer[1]        <= 32'd0;
            buffer[2]        <= 32'd0;
            buffer[3]        <= 32'd0;
        end else begin
            o_data_out_valid <= 1'b0;

            if (data_valid) begin
                buffer[count] <= data_in;

                if (count == 2'd3) begin
                    o_data_out       <= {buffer[0], buffer[1], buffer[2], data_in};
                    o_data_out_valid <= 1'b1;
                    count            <= 2'd0;
                end else begin
                    count <= count + 2'd1;
                end
            end
        end
    end

endmodule

output.rtl/data_bus_controller.sv:
module data_bus_controller #(
  parameter AFINITY = 0
  )(
  input         clk      ,
  input         rst_n    ,

  output        m0_read  ,
  input         m0_valid ,
  input [31:0]  m0_data  ,

  output        m1_read  ,
  input         m1_valid ,
  input [31:0]  m1_data  ,

  input         s_read   ,
  output        s_valid  ,
  output [31:0] s_data 
);

  // Internal registered outputs
  reg        s_valid_reg;
  reg [31:0] s_data_reg;

  // Combinational logic to determine which master wins
  // and drive slave outputs
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      s_valid_reg <= 1'b0;
      s_data_reg  <= 32'd0;
    end else begin
      // Both masters valid at the same cycle - use AFINITY
      if (m0_valid && m1_valid) begin
        if (AFINITY == 0) begin
          // m0 wins
          if (s_read) begin
            s_valid_reg <= 1'b1;
            s_data_reg  <= m0_data;
          end else begin
            s_valid_reg <= 1'b0;
            s_data_reg  <= 32'd0;
          end
        end else begin
          // m1 wins
          if (s_read) begin
            s_valid_reg <= 1'b1;
            s_data_reg  <= m1_data;
          end else begin
            s_valid_reg <= 1'b0;
            s_data_reg  <= 32'd0;
          end
        end
      end
      // Only m0 valid
      else if (m0_valid && !m1_valid) begin
        if (s_read) begin
          s_valid_reg <= 1'b1;
          s_data_reg  <= m0_data;
        end else begin
          s_valid_reg <= 1'b0;
          s_data_reg  <= 32'd0;
        end
      end
      // Only m1 valid
      else if (!m0_valid && m1_valid) begin
        if (s_read) begin
          s_valid_reg <= 1'b1;
          s_data_reg  <= m1_data;
        end else begin
          s_valid_reg <= 1'b0;
          s_data_reg  <= 32'd0;
        end
      end
      // Neither valid
      else begin
        s_valid_reg <= 1'b0;
        s_data_reg  <= 32'd0;
      end
    end
  end

  // Slave outputs
  assign s_valid = s_valid_reg;
  assign s_data  = s_data_reg;

  // Master ready signals depend on slave ready
  // m0 is ready when slave is ready and m0 is the selected master (or only master)
  // m1 is ready when slave is ready and m1 is the selected master (or only master)
  assign m0_read = s_read && (
                    (m0_valid && !m1_valid) ||
                    (m0_valid &&  m1_valid && (AFINITY == 0))
                  );

  assign m1_read = s_read && (
                    (!m0_valid && m1_valid) ||
                    ( m0_valid && m1_valid && (AFINITY == 1))
                  );

endmodule

output.rtl/dbi_enc.sv:
module dbi_enc (
    input  logic        clk,
    input  logic        rst_n,
    input  logic [39:0] data_in,
    output logic [39:0] data_out,
    output logic [1:0]  dbi_cntrl
);

    // Internal signals
    logic [19:0] group1_in;
    logic [19:0] group0_in;

    logic [19:0] prev_group1;
    logic [19:0] prev_group0;

    logic [19:0] xor_group1;
    logic [19:0] xor_group0;

    logic [4:0]  toggle_count1;
    logic [4:0]  toggle_count0;

    logic        ctrl1;
    logic        ctrl0;

    logic [19:0] encoded_group1;
    logic [19:0] encoded_group0;

    // Split incoming data into two 20-bit groups
    assign group1_in = data_in[39:20]; // MSBs
    assign group0_in = data_in[19:0];  // LSBs

    // XOR current data with previous data to find toggles
    assign xor_group1 = group1_in ^ prev_group1;
    assign xor_group0 = group0_in ^ prev_group0;

    // Count number of toggled bits in each group
    integer i;
    always_comb begin
        toggle_count1 = 5'd0;
        toggle_count0 = 5'd0;
        for (i = 0; i < 20; i = i + 1) begin
            toggle_count1 = toggle_count1 + {4'b0, xor_group1[i]};
            toggle_count0 = toggle_count0 + {4'b0, xor_group0[i]};
        end
    end

    // Determine control bits
    assign ctrl1 = (toggle_count1 > 5'd10) ? 1'b1 : 1'b0;
    assign ctrl0 = (toggle_count0 > 5'd10) ? 1'b1 : 1'b0;

    // Encode data based on control bits
    assign encoded_group1 = ctrl1 ? ~group1_in : group1_in;
    assign encoded_group0 = ctrl0 ? ~group0_in : group0_in;

    // Combinational data_out and dbi_cntrl (registered below)
    // data_out and dbi_cntrl are registered outputs

    // Sequential logic: register outputs and previous data
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            data_out   <= 40'h00_0000_0000;
            dbi_cntrl  <= 2'b00;
            prev_group1 <= 20'h00000;
            prev_group0 <= 20'h00000;
        end else begin
            dbi_cntrl  <= {ctrl1, ctrl0};
            data_out   <= {encoded_group1, encoded_group0};
            prev_group1 <= encoded_group1;
            prev_group0 <= encoded_group0;
        end
    end

endmodule

output.rtl/digital_dice_roller.sv:
module digital_dice_roller (
    input  logic       clk,
    input  logic       reset_n,
    input  logic       button,
    output logic [2:0] dice_value
);

    // FSM State Encoding
    typedef enum logic [1:0] {
        IDLE    = 2'b00,
        ROLLING = 2'b01
    } state_t;

    state_t current_state, next_state;

    // Internal counter register
    logic [2:0] counter;

    // State register (sequential)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            current_state <= IDLE;
        end else begin
            current_state <= next_state;
        end
    end

    // Next state logic (combinational)
    always_comb begin
        case (current_state)
            IDLE: begin
                if (button)
                    next_state = ROLLING;
                else
                    next_state = IDLE;
            end
            ROLLING: begin
                if (!button)
                    next_state = IDLE;
                else
                    next_state = ROLLING;
            end
            default: next_state = IDLE;
        endcase
    end

    // Counter logic (sequential)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            counter <= 3'd1;
        end else begin
            if (current_state == ROLLING) begin
                if (counter >= 3'd6)
                    counter <= 3'd1;
                else
                    counter <= counter + 3'd1;
            end
        end
    end

    // Output logic (sequential)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            dice_value <= 3'd0;
        end else begin
            if (current_state == ROLLING) begin
                dice_value <= counter;
            end
            // In IDLE state, dice_value holds its last value
        end
    end

endmodule

output.rtl/sync_pos_neg_edge_detector.sv:
module sync_pos_neg_edge_detector (
    input  logic i_clk,
    input  logic i_rstb,
    input  logic i_detection_signal,
    output logic o_positive_edge_detected,
    output logic o_negative_edge_detected
);

    logic detection_signal_prev;

    always_ff @(posedge i_clk or negedge i_rstb) begin
        if (!i_rstb) begin
            detection_signal_prev    <= 1'b0;
        end else begin
            detection_signal_prev    <= i_detection_signal;
        end
    end

    assign o_positive_edge_detected = i_detection_signal & ~detection_signal_prev;
    assign o_negative_edge_detected = ~i_detection_signal & detection_signal_prev;

endmodule

output.rtl/dig_stopwatch.sv:
module dig_stopwatch #(
    parameter int CLK_FREQ = 50_000_000
)(
    input  logic        clk,
    input  logic        reset,
    input  logic        start_stop,
    output logic [5:0]  seconds,
    output logic [5:0]  minutes,
    output logic        hour
);

    // Clock divider counter
    // We need to count CLK_FREQ cycles to produce a one-second pulse
    // Counter goes from 0 to CLK_FREQ-1
    localparam int COUNTER_MAX = CLK_FREQ - 1;

    // Determine the width needed for the counter
    localparam int COUNTER_WIDTH = $clog2(CLK_FREQ);

    logic [COUNTER_WIDTH-1:0] clk_div_counter;
    logic one_sec_pulse;

    // Clock divider: counts input clock cycles, produces pulse when one second elapses
    // The counter pauses when start_stop is low (stopwatch is paused)
    // But we need to hold partial progress when paused
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            clk_div_counter <= '0;
            one_sec_pulse   <= 1'b0;
        end else begin
            one_sec_pulse <= 1'b0; // default: pulse is low
            if (start_stop) begin
                if (hour) begin
                    // Stopwatch has reached one hour, hold state
                    clk_div_counter <= '0;
                end else begin
                    if (clk_div_counter == COUNTER_MAX[COUNTER_WIDTH-1:0]) begin
                        clk_div_counter <= '0;
                        one_sec_pulse   <= 1'b1;
                    end else begin
                        clk_div_counter <= clk_div_counter + 1'b1;
                    end
                end
            end
            // When start_stop is low, hold clk_div_counter (partial progress preserved)
        end
    end

    // Seconds, minutes, hour counters
    // Update on the rising edge of one_sec_pulse (which is a single clk-period pulse)
    // Since one_sec_pulse is already synchronized to clk edges, we just check it
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            seconds <= 6'd0;
            minutes <= 6'd0;
            hour    <= 1'b0;
        end else begin
            if (one_sec_pulse && !hour) begin
                if (seconds == 6'd59) begin
                    seconds <= 6'd0;
                    if (minutes == 6'd59) begin
                        minutes <= 6'd0;
                        hour    <= 1'b1;
                    end else begin
                        minutes <= minutes + 1'b1;
                    end
                end else begin
                    seconds <= seconds + 1'b1;
                end
            end
        end
    end

endmodule

output.rtl/ethernet_parser.v:
module ethernet_parser (
    input  wire        clk,
    input  wire        rst,
    input  wire        vld,
    input  wire        sof,
    input  wire [31:0] data,
    input  wire        eof,
    output wire        ack,
    output reg  [15:0] field,
    output reg         field_vld
);

    // State encoding
    localparam IDLE       = 2'd0;
    localparam EXTRACTING = 2'd1;
    localparam DONE       = 2'd2;
    localparam FAIL_FINAL = 2'd3;

    reg [1:0]  state;
    reg [3:0]  beat_cnt;
    reg [15:0] temp_extracted_field;

    // ACK is always high
    assign ack = 1'b1;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state                <= IDLE;
            beat_cnt             <= 4'd0;
            field                <= 16'd0;
            field_vld            <= 1'b0;
            temp_extracted_field <= 16'd0;
        end else begin
            case (state)
                IDLE: begin
                    field_vld <= 1'b0;
                    field     <= 16'd0;
                    beat_cnt  <= 4'd0;
                    if (vld && sof) begin
                        beat_cnt <= 4'd1;
                        state    <= EXTRACTING;
                    end
                end

                EXTRACTING: begin
                    if (vld) begin
                        if (beat_cnt == 4'd1) begin
                            temp_extracted_field <= data[31:16];
                            beat_cnt             <= beat_cnt + 1'b1;
                            state                <= DONE;
                        end else begin
                            beat_cnt <= beat_cnt + 1'b1;
                        end
                    end
                    if (eof) begin
                        state <= IDLE;
                    end
                end

                DONE: begin
                    field     <= temp_extracted_field;
                    field_vld <= 1'b1;
                    if (vld) begin
                        beat_cnt <= beat_cnt + 1'b1;
                    end
                    if (eof) begin
                        state <= FAIL_FINAL;
                    end
                end

                FAIL_FINAL: begin
                    field_vld <= 1'b0;
                    state     <= IDLE;
                end

                default: begin
                    state <= IDLE;
                end
            endcase
        end
    end

endmodule

output.rtl/fibonacci_series.sv:
module fibonacci_series (
    input  logic        clk,
    input  logic        rst,
    output logic [31:0] fib_out,
    output logic        overflow_flag
);

    logic [31:0] RegA, RegB;
    logic [32:0] next_fib;
    logic        overflow_detected;

    always_ff @(posedge clk) begin
        if (rst) begin
            RegA             <= 32'd0;
            RegB             <= 32'd1;
            fib_out          <= 32'd0;
            overflow_flag    <= 1'b0;
            overflow_detected <= 1'b0;
        end else begin
            if (overflow_detected) begin
                // One cycle after overflow detection: set flag, propagate last value, restart
                overflow_flag    <= 1'b1;
                fib_out          <= 32'd0;
                RegA             <= 32'd0;
                RegB             <= 32'd1;
                overflow_detected <= 1'b0;
            end else begin
                next_fib = {1'b0, RegA} + {1'b0, RegB};

                if (next_fib[32]) begin
                    // Overflow detected: propagate RegB to output, set overflow_detected
                    fib_out          <= RegB;
                    overflow_detected <= 1'b1;
                    overflow_flag    <= 1'b0;
                    // Keep RegA and RegB as they are until reset next cycle
                    RegA             <= RegA;
                    RegB             <= RegB;
                end else begin
                    overflow_flag    <= 1'b0;
                    fib_out          <= RegB;
                    RegA             <= RegB;
                    RegB             <= next_fib[31:0];
                    overflow_detected <= 1'b0;
                end
            end
        end
    end

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
// First-Bit Decoder RTL Module
// Returns the index of the lowest bit set in a vector

module cvdp_copilot_decode_firstbit #(
    parameter int InWidth_g = 32,
    parameter int InReg_g   = 1,
    parameter int OutReg_g  = 1,
    parameter int PlRegs_g  = 1
) (
    input  logic                          Clk,
    input  logic                          Rst,
    input  logic [InWidth_g-1:0]          In_Data,
    input  logic                          In_Valid,
    output logic [$clog2(InWidth_g)-1:0]  Out_FirstBit,
    output logic                          Out_Found,
    output logic                          Out_Valid
);

    // Local parameters
    localparam int BinBits_c   = $clog2(InWidth_g);
    // Round up to nearest power of two
    localparam int PowTwoWidth_c = 2**BinBits_c;

    // -------------------------------------------------------------------------
    // Input Register Stage
    // -------------------------------------------------------------------------
    logic [InWidth_g-1:0] data_in;
    logic                 valid_in;

    generate
        if (InReg_g == 1) begin : gen_in_reg
            always_ff @(posedge Clk or posedge Rst) begin
                if (Rst) begin
                    data_in  <= '0;
                    valid_in <= 1'b0;
                end else begin
                    data_in  <= In_Data;
                    valid_in <= In_Valid;
                end
            end
        end else begin : gen_no_in_reg
            assign data_in  = In_Data;
            assign valid_in = In_Valid;
        end
    endgenerate

    // -------------------------------------------------------------------------
    // Pad input to nearest power of two (set extra bits to 0 so they won't
    // be detected as first set bit)
    // -------------------------------------------------------------------------
    logic [PowTwoWidth_c-1:0] data_padded;
    always_comb begin
        data_padded = '0;
        data_padded[InWidth_g-1:0] = data_in;
    end

    // -------------------------------------------------------------------------
    // Pipeline stages for first-bit detection
    //
    // The detection is split across (PlRegs_g + 1) stages.
    // Each stage handles a portion of the bits.
    //
    // Strategy:
    //   We use a tree-based approach. At each pipeline stage we look at groups
    //   of bits and determine the lowest set bit index, propagating partial
    //   results through the pipeline.
    //
    // For simplicity and correctness across all PlRegs_g values, we implement
    // the following approach:
    //   - Stage 0 through PlRegs_g: we carry along a "remaining mask" and
    //     an "accumulated index" and "found" flag.
    //   - At each registered stage boundary, we resolve some of the bits.
    //
    // Simpler approach: compute the full first-bit result combinatorially,
    // then pipe the valid signal through PlRegs_g registers.
    // The combinatorial result is registered at the output if OutReg_g=1.
    // -------------------------------------------------------------------------

    // Combinatorial first-bit detection on padded data
    logic [BinBits_c-1:0] firstbit_comb;
    logic                  found_comb;

    always_comb begin
        firstbit_comb = '0;
        found_comb    = 1'b0;
        for (int i = PowTwoWidth_c-1; i >= 0; i--) begin
            if (i < InWidth_g && data_padded[i]) begin
                firstbit_comb = BinBits_c'(i);
                found_comb    = 1'b1;
            end
        end
    end

    // Pipeline registers for data (firstbit and found) and valid
    // We have PlRegs_g pipeline stages between input and output register
    // Total latency = InReg_g + PlRegs_g + OutReg_g cycles

    // Pipeline arrays
    logic [BinBits_c-1:0] pl_firstbit [0:PlRegs_g];
    logic                  pl_found    [0:PlRegs_g];
    logic                  pl_valid    [0:PlRegs_g];

    // Stage 0 is directly from combinatorial logic (uses registered input if InReg_g=1)
    assign pl_firstbit[0] = firstbit_comb;
    assign pl_found[0]    = found_comb;
    assign pl_valid[0]    = valid_in;

    // Pipeline stages 1 through PlRegs_g
    generate
        for (genvar s = 1; s <= PlRegs_g; s++) begin : gen_pl_stages
            always_ff @(posedge Clk or posedge Rst) begin
                if (Rst) begin
                    pl_firstbit[s] <= '0;
                    pl_found[s]    <= 1'b0;
                    pl_valid[s]    <= 1'b0;
                end else begin
                    pl_firstbit[s] <= pl_firstbit[s-1];
                    pl_found[s]    <= pl_found[s-1];
                    pl_valid[s]    <= pl_valid[s-1];
                end
            end
        end
    endgenerate

    // -------------------------------------------------------------------------
    // Output Register Stage
    // -------------------------------------------------------------------------
    generate
        if (OutReg_g == 1) begin : gen_out_reg
            always_ff @(posedge Clk or posedge Rst) begin
                if (Rst) begin
                    Out_FirstBit <= '0;
                    Out_Found    <= 1'b0;
                    Out_Valid    <= 1'b0;
                end else begin
                    Out_FirstBit <= pl_firstbit[PlRegs_g];
                    Out_Found    <= pl_found[PlRegs_g];
                    Out_Valid    <= pl_valid[PlRegs_g];
                end
            end
        end else begin : gen_no_out_reg
            assign Out_FirstBit = pl_firstbit[PlRegs_g];
            assign Out_Found    = pl_found[PlRegs_g];
            assign Out_Valid    = pl_valid[PlRegs_g];
        end
    endgenerate

endmodule

output.rtl/factorial.sv:
module factorial (
    input  logic        clk,
    input  logic        arst_n,
    input  logic [4:0]  num_in,
    input  logic        start,
    output logic        busy,
    output logic [63:0] fact,
    output logic        done
);

    // FSM State Encoding
    typedef enum logic [1:0] {
        IDLE = 2'b00,
        BUSY = 2'b01,
        DONE = 2'b10
    } state_t;

    state_t current_state, next_state;

    // Internal registers
    logic [4:0]  counter;
    logic [4:0]  num_reg;
    logic [63:0] result;

    // State register (sequential)
    always_ff @(posedge clk or negedge arst_n) begin
        if (!arst_n) begin
            current_state <= IDLE;
        end else begin
            current_state <= next_state;
        end
    end

    // Datapath registers
    always_ff @(posedge clk or negedge arst_n) begin
        if (!arst_n) begin
            counter  <= 5'd0;
            num_reg  <= 5'd0;
            result   <= 64'd1;
            fact     <= 64'd0;
        end else begin
            case (current_state)
                IDLE: begin
                    if (start) begin
                        num_reg <= num_in;
                        result  <= 64'd1;
                        // Handle factorial of 0 or 1
                        if (num_in == 5'd0 || num_in == 5'd1) begin
                            counter <= 5'd0;
                        end else begin
                            counter <= num_in;
                        end
                    end
                end

                BUSY: begin
                    if (counter > 5'd0) begin
                        result  <= result * counter;
                        counter <= counter - 5'd1;
                    end
                end

                DONE: begin
                    fact    <= result;
                    result  <= 64'd1;
                    counter <= 5'd0;
                    num_reg <= 5'd0;
                end

                default: begin
                    counter <= 5'd0;
                    num_reg <= 5'd0;
                    result  <= 64'd1;
                end
            endcase
        end
    end

    // Next state logic (combinational)
    always_comb begin
        next_state = current_state;
        case (current_state)
            IDLE: begin
                if (start) begin
                    // If input is 0 or 1, factorial is computed immediately (0 cycles)
                    // We still need to go through BUSY for at least the defined behavior
                    // but since num_in=0 or 1 means 0 iterations needed
                    next_state = BUSY;
                end
            end

            BUSY: begin
                // Stay in BUSY until all iterations done (counter reaches 0)
                if (counter == 5'd0) begin
                    next_state = DONE;
                end else begin
                    next_state = BUSY;
                end
            end

            DONE: begin
                next_state = IDLE;
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // Output logic
    always_comb begin
        busy = 1'b0;
        done = 1'b0;
        case (current_state)
            IDLE: begin
                busy = 1'b0;
                done = 1'b0;
            end
            BUSY: begin
                busy = 1'b1;
                done = 1'b0;
            end
            DONE: begin
                busy = 1'b0;
                done = 1'b1;
            end
            default: begin
                busy = 1'b0;
                done = 1'b0;
            end
        endcase
    end

endmodule

output.rtl/apb_controller.sv:
module apb_controller (
    input  logic        clk,
    input  logic        reset_n,

    // Event select signals
    input  logic        select_a_i,
    input  logic        select_b_i,
    input  logic        select_c_i,

    // Event A address and data
    input  logic [31:0] addr_a_i,
    input  logic [31:0] data_a_i,

    // Event B address and data
    input  logic [31:0] addr_b_i,
    input  logic [31:0] data_b_i,

    // Event C address and data
    input  logic [31:0] addr_c_i,
    input  logic [31:0] data_c_i,

    // APB interface
    input  logic        apb_pready_i,
    output logic        apb_psel_o,
    output logic        apb_penable_o,
    output logic        apb_pwrite_o,
    output logic [31:0] apb_paddr_o,
    output logic [31:0] apb_pwdata_o
);

    // State encoding
    typedef enum logic [1:0] {
        IDLE   = 2'b00,
        SETUP  = 2'b01,
        ACCESS = 2'b10
    } state_t;

    state_t current_state, next_state;

    // Internal registers for captured address and data
    logic [31:0] captured_addr;
    logic [31:0] captured_data;

    // Timeout counter
    logic [3:0] timeout_cnt;
    logic        timeout;

    // Assign timeout when counter reaches 15
    assign timeout = (timeout_cnt == 4'hF);

    // State register
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            current_state <= IDLE;
        end else begin
            current_state <= next_state;
        end
    end

    // Capture address and data in IDLE when select signals are asserted
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            captured_addr <= 32'h0;
            captured_data <= 32'h0;
        end else begin
            if (current_state == IDLE) begin
                if (select_a_i) begin
                    captured_addr <= addr_a_i;
                    captured_data <= data_a_i;
                end else if (select_b_i) begin
                    captured_addr <= addr_b_i;
                    captured_data <= data_b_i;
                end else if (select_c_i) begin
                    captured_addr <= addr_c_i;
                    captured_data <= data_c_i;
                end
            end
        end
    end

    // Timeout counter
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            timeout_cnt <= 4'h0;
        end else begin
            if (current_state == ACCESS) begin
                if (apb_pready_i || timeout) begin
                    timeout_cnt <= 4'h0;
                end else begin
                    timeout_cnt <= timeout_cnt + 4'h1;
                end
            end else begin
                timeout_cnt <= 4'h0;
            end
        end
    end

    // Next state logic
    always_comb begin
        next_state = current_state;
        case (current_state)
            IDLE: begin
                if (select_a_i || select_b_i || select_c_i) begin
                    next_state = SETUP;
                end else begin
                    next_state = IDLE;
                end
            end
            SETUP: begin
                next_state = ACCESS;
            end
            ACCESS: begin
                if (apb_pready_i || timeout) begin
                    next_state = IDLE;
                end else begin
                    next_state = ACCESS;
                end
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // Output logic
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            apb_psel_o    <= 1'b0;
            apb_penable_o <= 1'b0;
            apb_pwrite_o  <= 1'b0;
            apb_paddr_o   <= 32'h0;
            apb_pwdata_o  <= 32'h0;
        end else begin
            case (next_state)
                IDLE: begin
                    apb_psel_o    <= 1'b0;
                    apb_penable_o <= 1'b0;
                    apb_pwrite_o  <= 1'b0;
                    apb_paddr_o   <= 32'h0;
                    apb_pwdata_o  <= 32'h0;
                end
                SETUP: begin
                    apb_psel_o    <= 1'b1;
                    apb_penable_o <= 1'b0;
                    apb_pwrite_o  <= 1'b1;
                    // Use captured values (already captured in IDLE on this same clock edge)
                    // Need to use the values that will be captured
                    if (current_state == IDLE) begin
                        if (select_a_i) begin
                            apb_paddr_o  <= addr_a_i;
                            apb_pwdata_o <= data_a_i;
                        end else if (select_b_i) begin
                            apb_paddr_o  <= addr_b_i;
                            apb_pwdata_o <= data_b_i;
                        end else if (select_c_i) begin
                            apb_paddr_o  <= addr_c_i;
                            apb_pwdata_o <= data_c_i;
                        end
                    end else begin
                        apb_paddr_o  <= captured_addr;
                        apb_pwdata_o <= captured_data;
                    end
                end
                ACCESS: begin
                    apb_psel_o    <= 1'b1;
                    apb_penable_o <= 1'b1;
                    apb_pwrite_o  <= 1'b1;
                    apb_paddr_o   <= captured_addr;
                    apb_pwdata_o  <= captured_data;
                end
                default: begin
                    apb_psel_o    <= 1'b0;
                    apb_penable_o <= 1'b0;
                    apb_pwrite_o  <= 1'b0;
                    apb_paddr_o   <= 32'h0;
                    apb_pwdata_o  <= 32'h0;
                end
            endcase
        end
    end

endmodule

output.rtl/fsm_seq_detector.sv:
// rtl/fsm_seq_detector.sv
// FSM Sequence Detector for sequence "10110001"

module fsm_seq_detector (
    input  bit     clk_in,
    input  logic   rst_in,
    input  logic   seq_in,
    output logic   seq_detected
);

    // State type definition
    typedef enum logic [2:0] {
        S0 = 3'b000,  // Initial state, waiting for '1'
        S1 = 3'b001,  // Received '1'
        S2 = 3'b010,  // Received '10'
        S3 = 3'b011,  // Received '101'
        S4 = 3'b100,  // Received '1011'
        S5 = 3'b101,  // Received '10110'
        S6 = 3'b110,  // Received '101100'
        S7 = 3'b111   // Received '1011000'
    } state_t;

    state_t cur_state, next_state;
    logic   seq_detected_w;

    // Sequential block: state register and output register
    always_ff @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            cur_state    <= S0;
            seq_detected <= 1'b0;
        end else begin
            cur_state    <= next_state;
            seq_detected <= seq_detected_w;
        end
    end

    // Combinational block: next state logic and output logic
    // Sequence to detect: 1 0 1 1 0 0 0 1
    //                     S0->S1->S2->S3->S4->S5->S6->S7->detect
    always_comb begin
        // Default values
        next_state     = S0;
        seq_detected_w = 1'b0;

        case (cur_state)
            S0: begin
                // Waiting for first bit '1'
                if (seq_in == 1'b1)
                    next_state = S1;
                else
                    next_state = S0;
            end

            S1: begin
                // Received '1', waiting for '0'
                if (seq_in == 1'b0)
                    next_state = S2;
                else
                    next_state = S1; // '1' again, stay at S1
            end

            S2: begin
                // Received '10', waiting for '1'
                if (seq_in == 1'b1)
                    next_state = S3;
                else
                    next_state = S0; // '0', go back to S0
            end

            S3: begin
                // Received '101', waiting for '1'
                if (seq_in == 1'b1)
                    next_state = S4;
                else
                    next_state = S2; // '0', received '10' suffix, go to S2
            end

            S4: begin
                // Received '1011', waiting for '0'
                if (seq_in == 1'b0)
                    next_state = S5;
                else
                    next_state = S1; // '1', only last '1' counts, go to S1
            end

            S5: begin
                // Received '10110', waiting for '0'
                if (seq_in == 1'b0)
                    next_state = S6;
                else
                    next_state = S3; // '1', received '101' suffix, go to S3
            end

            S6: begin
                // Received '101100', waiting for '0'
                if (seq_in == 1'b0)
                    next_state = S7;
                else
                    next_state = S3; // '1', received '101' suffix, go to S3
            end

            S7: begin
                // Received '1011000', waiting for '1'
                if (seq_in == 1'b1) begin
                    next_state     = S1;  // Sequence detected! Last '1' can be start of new sequence
                    seq_detected_w = 1'b1;
                end else begin
                    next_state = S0; // '0', no overlap possible, go to S0
                end
            end

            default: begin
                next_state     = S0;
                seq_detected_w = 1'b0;
            end
        endcase
    end

endmodule

output.rtl/fifo_async.sv:
module fifo_async #(
    parameter DATA_WIDTH = 8,
    parameter DEPTH      = 16
) (
    // Write domain
    input  logic                  w_clk,
    input  logic                  w_rst,
    input  logic                  w_inc,
    input  logic [DATA_WIDTH-1:0] w_data,
    output logic                  w_full,

    // Read domain
    input  logic                  r_clk,
    input  logic                  r_rst,
    input  logic                  r_inc,
    output logic                  r_empty,
    output logic [DATA_WIDTH-1:0] r_data
);

    // Address width (log2 of DEPTH)
    localparam ADDR_WIDTH = $clog2(DEPTH);
    // Pointer width has one extra bit for overflow detection
    localparam PTR_WIDTH  = ADDR_WIDTH + 1;

    // Memory
    logic [DATA_WIDTH-1:0] mem [0:DEPTH-1];

    // Write pointer (binary and Gray)
    logic [PTR_WIDTH-1:0] w_ptr_bin;
    logic [PTR_WIDTH-1:0] w_ptr_gray;
    logic [PTR_WIDTH-1:0] w_ptr_bin_next;
    logic [PTR_WIDTH-1:0] w_ptr_gray_next;

    // Read pointer (binary and Gray)
    logic [PTR_WIDTH-1:0] r_ptr_bin;
    logic [PTR_WIDTH-1:0] r_ptr_gray;
    logic [PTR_WIDTH-1:0] r_ptr_bin_next;
    logic [PTR_WIDTH-1:0] r_ptr_gray_next;

    // Synchronized pointers (2FF synchronizers)
    // Read pointer synchronized into write clock domain
    logic [PTR_WIDTH-1:0] r_ptr_gray_sync1_w;
    logic [PTR_WIDTH-1:0] r_ptr_gray_sync2_w;
    // Write pointer synchronized into read clock domain
    logic [PTR_WIDTH-1:0] w_ptr_gray_sync1_r;
    logic [PTR_WIDTH-1:0] w_ptr_gray_sync2_r;

    // -------------------------------------------------------------------------
    // Write pointer logic
    // -------------------------------------------------------------------------
    always_ff @(posedge w_clk or posedge w_rst) begin
        if (w_rst) begin
            w_ptr_bin  <= '0;
            w_ptr_gray <= '0;
        end else begin
            w_ptr_bin  <= w_ptr_bin_next;
            w_ptr_gray <= w_ptr_gray_next;
        end
    end

    assign w_ptr_bin_next  = (w_inc && !w_full) ? (w_ptr_bin + 1'b1) : w_ptr_bin;
    assign w_ptr_gray_next = (w_ptr_bin_next >> 1) ^ w_ptr_bin_next;

    // -------------------------------------------------------------------------
    // Read pointer logic
    // -------------------------------------------------------------------------
    always_ff @(posedge r_clk or posedge r_rst) begin
        if (r_rst) begin
            r_ptr_bin  <= '0;
            r_ptr_gray <= '0;
        end else begin
            r_ptr_bin  <= r_ptr_bin_next;
            r_ptr_gray <= r_ptr_gray_next;
        end
    end

    assign r_ptr_bin_next  = (r_inc && !r_empty) ? (r_ptr_bin + 1'b1) : r_ptr_bin;
    assign r_ptr_gray_next = (r_ptr_bin_next >> 1) ^ r_ptr_bin_next;

    // -------------------------------------------------------------------------
    // Memory write
    // -------------------------------------------------------------------------
    always_ff @(posedge w_clk) begin
        if (w_inc && !w_full) begin
            mem[w_ptr_bin[ADDR_WIDTH-1:0]] <= w_data;
        end
    end

    // -------------------------------------------------------------------------
    // Memory read (asynchronous)
    // -------------------------------------------------------------------------
    assign r_data = mem[r_ptr_bin[ADDR_WIDTH-1:0]];

    // -------------------------------------------------------------------------
    // Synchronize read pointer into write clock domain (2FF)
    // -------------------------------------------------------------------------
    always_ff @(posedge w_clk or posedge w_rst) begin
        if (w_rst) begin
            r_ptr_gray_sync1_w <= '0;
            r_ptr_gray_sync2_w <= '0;
        end else begin
            r_ptr_gray_sync1_w <= r_ptr_gray;
            r_ptr_gray_sync2_w <= r_ptr_gray_sync1_w;
        end
    end

    // -------------------------------------------------------------------------
    // Synchronize write pointer into read clock domain (2FF)
    // -------------------------------------------------------------------------
    always_ff @(posedge r_clk or posedge r_rst) begin
        if (r_rst) begin
            w_ptr_gray_sync1_r <= '0;
            w_ptr_gray_sync2_r <= '0;
        end else begin
            w_ptr_gray_sync1_r <= w_ptr_gray;
            w_ptr_gray_sync2_r <= w_ptr_gray_sync1_r;
        end
    end

    // -------------------------------------------------------------------------
    // Full flag generation (write clock domain)
    // Full when MSBs differ and all other bits are equal
    // -------------------------------------------------------------------------
    assign w_full = (w_ptr_gray[PTR_WIDTH-1]   != r_ptr_gray_sync2_w[PTR_WIDTH-1]) &&
                    (w_ptr_gray[PTR_WIDTH-2]   != r_ptr_gray_sync2_w[PTR_WIDTH-2]) &&
                    (w_ptr_gray[PTR_WIDTH-3:0] == r_ptr_gray_sync2_w[PTR_WIDTH-3:0]);

    // -------------------------------------------------------------------------
    // Empty flag generation (read clock domain)
    // Empty when write and read pointers are exactly the same
    // -------------------------------------------------------------------------
    assign r_empty = (r_ptr_gray == w_ptr_gray_sync2_r);

endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,
    parameter FILO_DEPTH = 16
)(
    input  logic                    clk,
    input  logic                    reset,
    input  logic                    push,
    input  logic                    pop,
    input  logic [DATA_WIDTH-1:0]   data_in,
    output logic [DATA_WIDTH-1:0]   data_out,
    output logic                    full,
    output logic                    empty
);

    // Internal memory array
    logic [DATA_WIDTH-1:0] mem [0:FILO_DEPTH-1];

    // Stack pointer - points to the next empty location
    logic [$clog2(FILO_DEPTH):0] top;

    // Feedthrough register
    logic [DATA_WIDTH-1:0] feedthrough_data;
    logic                  feedthrough_valid;

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            top              <= 0;
            full             <= 1'b0;
            empty            <= 1'b1;
            feedthrough_valid <= 1'b0;
            feedthrough_data  <= '0;
        end else begin
            feedthrough_valid <= 1'b0;

            // Feedthrough: FILO is empty and both push and pop asserted
            if (empty && push && pop) begin
                feedthrough_data  <= data_in;
                feedthrough_valid <= 1'b1;
                // top remains 0, empty remains 1, full remains 0
            end
            // Push only (not full)
            else if (push && !pop && !full) begin
                mem[top] <= data_in;
                top      <= top + 1;
                empty    <= 1'b0;
                if (top + 1 == FILO_DEPTH) begin
                    full <= 1'b1;
                end
            end
            // Pop only (not empty)
            else if (pop && !push && !empty) begin
                top  <= top - 1;
                full <= 1'b0;
                if (top - 1 == 0) begin
                    empty <= 1'b1;
                end
            end
            // Push and pop simultaneously, buffer not empty
            else if (push && pop && !empty) begin
                // Pop the top element and push new data at same position
                // Net effect: replace top element, top doesn't change
                // Actually: pop decrements top, push increments - net 0
                // But we store new data at current top-1 position? 
                // Let's think: pop first then push
                // pop: top goes to top-1, then push: store at top-1, top goes back to top
                // Net: replace top-1 element with new data, top unchanged
                mem[top-1] <= data_in;
                // top stays the same
                // full and empty stay the same
            end
        end
    end

    // Output logic
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out <= '0;
        end else begin
            if (empty && push && pop) begin
                // feedthrough - will be captured next cycle or we handle combinatorially
                data_out <= data_in;
            end else if (pop && !push && !empty) begin
                data_out <= mem[top-1];
            end else if (push && pop && !empty) begin
                // Simultaneous push/pop when not empty: output the current top
                data_out <= mem[top-1];
            end
        end
    end

endmodule

output.rtl/gcd_top.sv:
// GCD Control Path Module
module gcd_controlpath #(
    parameter WIDTH = 4
)(
    input  logic        clk,
    input  logic        rst,
    input  logic        go,
    input  logic        equal,
    input  logic        greater_than,
    output logic [1:0]  controlpath_state,
    output logic        done
);

    // State encoding
    localparam S0 = 2'b00; // IDLE
    localparam S1 = 2'b01; // DONE
    localparam S2 = 2'b10; // A > B
    localparam S3 = 2'b11; // B > A

    logic [1:0] state, next_state;

    // State register
    always_ff @(posedge clk) begin
        if (rst) begin
            state <= S0;
        end else begin
            state <= next_state;
        end
    end

    // Next state logic
    always_comb begin
        case (state)
            S0: begin
                if (go) begin
                    if (equal)
                        next_state = S1;
                    else if (greater_than)
                        next_state = S2;
                    else
                        next_state = S3;
                end else begin
                    next_state = S0;
                end
            end
            S1: begin
                next_state = S0;
            end
            S2: begin
                if (equal)
                    next_state = S1;
                else if (greater_than)
                    next_state = S2;
                else
                    next_state = S3;
            end
            S3: begin
                if (equal)
                    next_state = S1;
                else if (greater_than)
                    next_state = S2;
                else
                    next_state = S3;
            end
            default: begin
                next_state = S0;
            end
        endcase
    end

    // Output logic - synchronized to positive edge of clock
    always_ff @(posedge clk) begin
        if (rst) begin
            controlpath_state <= S0;
            done              <= 1'b0;
        end else begin
            controlpath_state <= next_state;
            done              <= (next_state == S1) ? 1'b1 : 1'b0;
        end
    end

endmodule


// GCD Datapath Module
module gcd_datapath #(
    parameter WIDTH = 4
)(
    input  logic              clk,
    input  logic              rst,
    input  logic [WIDTH-1:0]  A,
    input  logic [WIDTH-1:0]  B,
    input  logic [1:0]        controlpath_state,
    output logic [WIDTH-1:0]  OUT,
    output logic              equal,
    output logic              greater_than
);

    // State encoding (matching controlpath)
    localparam S0 = 2'b00;
    localparam S1 = 2'b01;
    localparam S2 = 2'b10;
    localparam S3 = 2'b11;

    logic [WIDTH-1:0] A_ff, B_ff;

    // Comparison logic
    // In S0 state, use input A and B directly
    // In other states, use registered A_ff and B_ff
    always_comb begin
        if (controlpath_state == S0) begin
            equal        = (A == B);
            greater_than = (A > B);
        end else begin
            equal        = (A_ff == B_ff);
            greater_than = (A_ff > B_ff);
        end
    end

    // Datapath register updates and output
    always_ff @(posedge clk) begin
        if (rst) begin
            A_ff <= '0;
            B_ff <= '0;
            OUT  <= '0;
        end else begin
            case (controlpath_state)
                S0: begin
                    // Latch inputs when in IDLE (go will have been asserted)
                    A_ff <= A;
                    B_ff <= B;
                end
                S1: begin
                    // Computation complete, output the GCD
                    OUT <= A_ff;
                end
                S2: begin
                    // A > B: subtract B from A
                    A_ff <= A_ff - B_ff;
                end
                S3: begin
                    // B > A: subtract A from B
                    B_ff <= B_ff - A_ff;
                end
                default: begin
                    A_ff <= A_ff;
                    B_ff <= B_ff;
                end
            endcase
        end
    end

endmodule


// GCD Top Module
module gcd_top #(
    parameter WIDTH = 4
)(
    input  logic              clk,
    input  logic              rst,
    input  logic [WIDTH-1:0]  A,
    input  logic [WIDTH-1:0]  B,
    input  logic              go,
    output logic [WIDTH-1:0]  OUT,
    output logic              done
);

    logic [1:0] controlpath_state;
    logic       equal;
    logic       greater_than;

    // Instantiate control path
    gcd_controlpath #(
        .WIDTH(WIDTH)
    ) u_controlpath (
        .clk               (clk),
        .rst               (rst),
        .go                (go),
        .equal             (equal),
        .greater_than      (greater_than),
        .controlpath_state (controlpath_state),
        .done              (done)
    );

    // Instantiate datapath
    gcd_datapath #(
        .WIDTH(WIDTH)
    ) u_datapath (
        .clk               (clk),
        .rst               (rst),
        .A                 (A),
        .B                 (B),
        .controlpath_state (controlpath_state),
        .OUT               (OUT),
        .equal             (equal),
        .greater_than      (greater_than)
    );

endmodule

output.rtl/hamming_code_tx_for_4bit.sv:
module hamming_code_tx_for_4bit (
    input  logic [3:0] data_in,
    output logic [7:0] data_out
);

    // Redundant bit fixed to 0
    assign data_out[0] = 1'b0;

    // Parity bit p1: covers data_in[0], data_in[1], data_in[3]
    assign data_out[1] = data_in[0] ^ data_in[1] ^ data_in[3];

    // Parity bit p2: covers data_in[0], data_in[2], data_in[3]
    assign data_out[2] = data_in[0] ^ data_in[2] ^ data_in[3];

    // Data bit d1
    assign data_out[3] = data_in[0];

    // Parity bit p4: covers data_in[1], data_in[2], data_in[3]
    assign data_out[4] = data_in[1] ^ data_in[2] ^ data_in[3];

    // Data bits d2, d3, d4
    assign data_out[5] = data_in[1];
    assign data_out[6] = data_in[2];
    assign data_out[7] = data_in[3];

endmodule

output.rtl/gf_multiplier.sv:
module gf_multiplier (
    input  logic [3:0] A,
    input  logic [3:0] B,
    output logic [3:0] result
);

    always_comb begin
        logic [4:0] multiplicand;
        logic [3:0] res;

        res = 4'b0000;
        multiplicand = {1'b0, A};

        // Iteration for each bit of B
        // Bit 0
        if (B[0]) begin
            res = res ^ multiplicand[3:0];
        end
        // Shift multiplicand left by 1
        multiplicand = {multiplicand[3:0], 1'b0};
        // Check MSB (bit 4) for polynomial reduction
        if (multiplicand[4]) begin
            multiplicand = multiplicand ^ 5'b10011;
        end

        // Bit 1
        if (B[1]) begin
            res = res ^ multiplicand[3:0];
        end
        // Shift multiplicand left by 1
        multiplicand = {multiplicand[3:0], 1'b0};
        if (multiplicand[4]) begin
            multiplicand = multiplicand ^ 5'b10011;
        end

        // Bit 2
        if (B[2]) begin
            res = res ^ multiplicand[3:0];
        end
        // Shift multiplicand left by 1
        multiplicand = {multiplicand[3:0], 1'b0};
        if (multiplicand[4]) begin
            multiplicand = multiplicand ^ 5'b10011;
        end

        // Bit 3
        if (B[3]) begin
            res = res ^ multiplicand[3:0];
        end
        // Shift multiplicand left by 1 (not needed after last iteration but kept for consistency)
        multiplicand = {multiplicand[3:0], 1'b0};
        if (multiplicand[4]) begin
            multiplicand = multiplicand ^ 5'b10011;
        end

        result = res;
    end

endmodule

output.rtl/hamming_code_receiver.sv:
module hamming_code_receiver (
    input  logic [7:0] data_in,
    output logic [3:0] data_out
);

    logic c1, c2, c3;
    logic [7:0] corrected;

    // Even parity checks
    assign c3 = data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
    assign c2 = data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
    assign c1 = data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

    // Error correction
    always_comb begin
        corrected = data_in;
        if ({c1, c2, c3} != 3'b000) begin
            corrected[{c1, c2, c3}] = ~data_in[{c1, c2, c3}];
        end
    end

    // Output assignment: data bits are at positions 7, 6, 5, 3
    assign data_out = {corrected[7], corrected[6], corrected[5], corrected[3]};

endmodule

output.rtl/hill_cipher.sv:
// rtl/hill_cipher.sv

module hill_cipher (
    input  logic        clk,
    input  logic        reset,
    input  logic        start,
    input  logic [14:0] plaintext,
    input  logic [44:0] key,
    output logic [14:0] ciphertext,
    output logic        done
);

    // FSM States
    typedef enum logic [1:0] {
        IDLE    = 2'b00,
        COMPUTE = 2'b01,
        OUTPUT  = 2'b10
    } state_t;

    state_t state, next_state;

    // Key matrix elements
    logic [4:0] K00, K01, K02;
    logic [4:0] K10, K11, K12;
    logic [4:0] K20, K21, K22;

    // Plaintext vector elements
    logic [4:0] P0, P1, P2;

    // Intermediate ciphertext values (wider to handle multiplication)
    logic [14:0] C0_raw, C1_raw, C2_raw;
    logic [4:0]  C0, C1, C2;

    // Internal registers
    logic [14:0] plaintext_reg;
    logic [44:0] key_reg;

    // Cycle counter for latency
    logic [1:0] cycle_count;

    // Extract key elements
    assign K00 = key_reg[44:40];
    assign K01 = key_reg[39:35];
    assign K02 = key_reg[34:30];
    assign K10 = key_reg[29:25];
    assign K11 = key_reg[24:20];
    assign K12 = key_reg[19:15];
    assign K20 = key_reg[14:10];
    assign K21 = key_reg[9:5];
    assign K22 = key_reg[4:0];

    // Extract plaintext elements
    assign P0 = plaintext_reg[14:10];
    assign P1 = plaintext_reg[9:5];
    assign P2 = plaintext_reg[4:0];

    // Matrix multiplication
    assign C0_raw = (K00 * P0) + (K01 * P1) + (K02 * P2);
    assign C1_raw = (K10 * P0) + (K11 * P1) + (K12 * P2);
    assign C2_raw = (K20 * P0) + (K21 * P1) + (K22 * P2);

    // Modulo 26
    assign C0 = C0_raw % 26;
    assign C1 = C1_raw % 26;
    assign C2 = C2_raw % 26;

    // FSM - State register
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            state       <= IDLE;
            cycle_count <= 2'b00;
            plaintext_reg <= 15'b0;
            key_reg       <= 45'b0;
            ciphertext    <= 15'b0;
            done          <= 1'b0;
        end else begin
            case (state)
                IDLE: begin
                    done <= 1'b0;
                    if (start) begin
                        plaintext_reg <= plaintext;
                        key_reg       <= key;
                        cycle_count   <= 2'b00;
                        state         <= COMPUTE;
                    end
                end

                COMPUTE: begin
                    if (cycle_count == 2'b01) begin
                        state       <= OUTPUT;
                        cycle_count <= 2'b00;
                    end else begin
                        cycle_count <= cycle_count + 1'b1;
                    end
                end

                OUTPUT: begin
                    ciphertext <= {C0, C1, C2};
                    done       <= 1'b1;
                    state      <= IDLE;
                end

                default: begin
                    state <= IDLE;
                end
            endcase
        end
    end

endmodule

output.rtl/matrix_multiplier.sv:
module matrix_multiplier #(
    parameter ROW_A          = 4,
    parameter COL_A          = 4,
    parameter ROW_B          = 4,
    parameter COL_B          = 4,
    parameter INPUT_DATA_WIDTH  = 8,
    parameter OUTPUT_DATA_WIDTH = INPUT_DATA_WIDTH * 2 + $clog2(COL_A)
) (
    input  logic [(ROW_A * COL_A * INPUT_DATA_WIDTH) - 1 : 0] matrix_a,
    input  logic [(ROW_B * COL_B * INPUT_DATA_WIDTH) - 1 : 0] matrix_b,
    output logic [(ROW_A * COL_B * OUTPUT_DATA_WIDTH) - 1 : 0] matrix_c
);

    // Internal arrays for unpacked representation
    logic [INPUT_DATA_WIDTH-1:0]  a [0:ROW_A-1][0:COL_A-1];
    logic [INPUT_DATA_WIDTH-1:0]  b [0:ROW_B-1][0:COL_B-1];
    logic [OUTPUT_DATA_WIDTH-1:0] c [0:ROW_A-1][0:COL_B-1];

    // Unpack matrix_a from flattened input
    // matrix_a = {a[ROW_A-1][COL_A-1], ..., a[0][0]}
    // Element a[row][col] is at index (row * COL_A + col)
    always_comb begin
        for (int row = 0; row < ROW_A; row++) begin
            for (int col = 0; col < COL_A; col++) begin
                a[row][col] = matrix_a[(row * COL_A + col) * INPUT_DATA_WIDTH +: INPUT_DATA_WIDTH];
            end
        end
    end

    // Unpack matrix_b from flattened input
    // matrix_b = {b[ROW_B-1][COL_B-1], ..., b[0][0]}
    // Element b[row][col] is at index (row * COL_B + col)
    always_comb begin
        for (int row = 0; row < ROW_B; row++) begin
            for (int col = 0; col < COL_B; col++) begin
                b[row][col] = matrix_b[(row * COL_B + col) * INPUT_DATA_WIDTH +: INPUT_DATA_WIDTH];
            end
        end
    end

    // Compute matrix multiplication c = a * b
    always_comb begin
        for (int i = 0; i < ROW_A; i++) begin
            for (int j = 0; j < COL_B; j++) begin
                c[i][j] = '0;
                for (int k = 0; k < COL_A; k++) begin
                    c[i][j] = c[i][j] + (OUTPUT_DATA_WIDTH)'(a[i][k]) * (OUTPUT_DATA_WIDTH)'(b[k][j]);
                end
            end
        end
    end

    // Pack output matrix_c into flattened output
    // matrix_c = {c[ROW_A-1][COL_B-1], ..., c[0][0]}
    // Element c[row][col] is at index (row * COL_B + col)
    always_comb begin
        for (int row = 0; row < ROW_A; row++) begin
            for (int col = 0; col < COL_B; col++) begin
                matrix_c[(row * COL_B + col) * OUTPUT_DATA_WIDTH +: OUTPUT_DATA_WIDTH] = c[row][col];
            end
        end
    end

endmodule

output.rtl/hebb_gates.sv:
// rtl/hebb_gates.sv

// Gate target submodule
module gate_target (
    input  logic signed [3:0] a,
    input  logic signed [3:0] b,
    input  logic [1:0] gate_select,
    output logic signed [3:0] target
);
    always_comb begin
        case (gate_select)
            2'b00: begin // AND gate
                if (a == 4'sb0001 && b == 4'sb0001)
                    target = 4'sb0001;
                else
                    target = 4'sbffff; // -1
            end
            2'b01: begin // OR gate
                if (a == 4'sbffff && b == 4'sbffff)
                    target = 4'sbffff; // -1
                else
                    target = 4'sb0001;
            end
            2'b10: begin // NAND gate
                if (a == 4'sb0001 && b == 4'sb0001)
                    target = 4'sbffff; // -1
                else
                    target = 4'sb0001;
            end
            2'b11: begin // NOR gate
                if (a == 4'sbffff && b == 4'sbffff)
                    target = 4'sb0001;
                else
                    target = 4'sbffff; // -1
            end
            default: target = 4'sb0000;
        endcase
    end
endmodule

// Main Hebbian rule module
module hebbian_rule (
    input  logic        clk,
    input  logic        rst,
    input  logic        start,
    input  logic signed [3:0] a,
    input  logic signed [3:0] b,
    input  logic [1:0]  gate_select,
    output logic signed [3:0] w1,
    output logic signed [3:0] w2,
    output logic signed [3:0] bias,
    output logic [3:0]  present_state,
    output logic [3:0]  next_state
);

    // State encoding
    localparam [3:0] 
        State_0  = 4'd0,
        State_1  = 4'd1,
        State_2  = 4'd2,
        State_3  = 4'd3,
        State_4  = 4'd4,
        State_5  = 4'd5,
        State_6  = 4'd6,
        State_7  = 4'd7,
        State_8  = 4'd8,
        State_9  = 4'd9,
        State_10 = 4'd10;

    // Internal registers
    logic signed [3:0] x1, x2;
    logic signed [3:0] target;
    logic signed [3:0] delta_w1, delta_w2, delta_b;
    logic [1:0]        iter; // iteration counter for 4 input combinations

    // Training input combinations (bipolar: 1 and -1)
    // Combinations: (1,1), (1,-1), (-1,1), (-1,-1)
    logic signed [3:0] train_a [0:3];
    logic signed [3:0] train_b [0:3];

    // Gate target instance
    logic signed [3:0] gt_target;
    logic signed [3:0] gt_a, gt_b;

    gate_target gt_inst (
        .a(gt_a),
        .b(gt_b),
        .gate_select(gate_select),
        .target(gt_target)
    );

    // Training vectors
    always_comb begin
        train_a[0] = 4'sb0001;  //  1
        train_a[1] = 4'sb0001;  //  1
        train_a[2] = 4'sbffff;  // -1
        train_a[3] = 4'sbffff;  // -1

        train_b[0] = 4'sb0001;  //  1
        train_b[1] = 4'sbffff;  // -1
        train_b[2] = 4'sb0001;  //  1
        train_b[3] = 4'sbffff;  // -1
    end

    // Gate target inputs selection based on iteration
    always_comb begin
        if (present_state == State_2 || present_state == State_3 ||
            present_state == State_4 || present_state == State_5 ||
            present_state == State_6) begin
            gt_a = train_a[iter];
            gt_b = train_b[iter];
        end else begin
            gt_a = a;
            gt_b = b;
        end
    end

    // FSM present state register
    always_ff @(posedge clk or negedge rst) begin
        if (!rst) begin
            present_state <= State_0;
            iter <= 2'd0;
            w1   <= 4'sb0000;
            w2   <= 4'sb0000;
            bias <= 4'sb0000;
            x1   <= 4'sb0000;
            x2   <= 4'sb0000;
            target <= 4'sb0000;
            delta_w1 <= 4'sb0000;
            delta_w2 <= 4'sb0000;
            delta_b  <= 4'sb0000;
        end else begin
            present_state <= next_state;

            case (present_state)
                State_0: begin
                    // Initialize weights and bias
                    w1   <= 4'sb0000;
                    w2   <= 4'sb0000;
                    bias <= 4'sb0000;
                    iter <= 2'd0;
                end

                State_1: begin
                    // Capture inputs for current iteration
                    x1 <= train_a[iter];
                    x2 <= train_b[iter];
                end

                State_2: begin
                    // Compute target using gate_target module
                    target <= gt_target;
                end

                State_3: begin
                    // Additional target assignment step
                    target <= gt_target;
                end

                State_4: begin
                    target <= gt_target;
                end

                State_5: begin
                    target <= gt_target;
                end

                State_6: begin
                    target <= gt_target;
                end

                State_7: begin
                    // Compute deltas
                    delta_w1 <= x1 * target;
                    delta_w2 <= x2 * target;
                    delta_b  <= target;
                end

                State_8: begin
                    // Update weights and bias
                    w1   <= w1 + delta_w1;
                    w2   <= w2 + delta_w2;
                    bias <= bias + delta_b;
                end

                State_9: begin
                    // Increment iteration counter
                    iter <= iter + 2'd1;
                end

                State_10: begin
                    // Training complete, stay or reset
                    iter <= 2'd0;
                end

                default: begin
                    // do nothing
                end
            endcase
        end
    end

    // Next state logic (Moore FSM)
    always_comb begin
        case (present_state)
            State_0: begin
                if (start)
                    next_state = State_1;
                else
                    next_state = State_0;
            end

            State_1: begin
                next_state = State_2;
            end

            State_2: begin
                next_state = State_3;
            end

            State_3: begin
                next_state = State_4;
            end

            State_4: begin
                next_state = State_5;
            end

            State_5: begin
                next_state = State_6;
            end

            State_6: begin
                next_state = State_7;
            end

            State_7: begin
                next_state = State_8;
            end

            State_8: begin
                next_state = State_9;
            end

            State_9: begin
                // Check if we've processed all 4 input combinations
                if (iter == 2'd3)
                    next_state = State_10;
                else
                    next_state = State_1;
            end

            State_10: begin
                next_state = State_0;
            end

            default: begin
                next_state = State_0;
            end
        endcase
    end

endmodule

output.rtl/moving_average.v:
module moving_average (
    input  wire        clk,
    input  wire        reset,
    input  wire [11:0] data_in,
    output reg  [11:0] data_out
);

    // Memory buffer to store last 8 samples
    reg [11:0] buffer [0:7];

    // Index to track current position in circular buffer
    reg [2:0] index;

    // Sum register - needs enough bits to hold sum of 8 12-bit values
    // Max sum = 8 * 4095 = 32760, needs 15 bits
    reg [14:0] sum;

    integer i;

    always @(posedge clk) begin
        if (reset) begin
            // Clear all buffer entries
            for (i = 0; i < 8; i = i + 1) begin
                buffer[i] <= 12'b0;
            end
            index   <= 3'b0;
            sum     <= 15'b0;
            data_out <= 12'b0;
        end else begin
            // Update sum: subtract old value at current index, add new value
            sum <= sum - buffer[index] + data_in;

            // Store new sample in buffer at current index
            buffer[index] <= data_in;

            // Advance index (wraps around 0-7)
            index <= index + 1;

            // Output is sum divided by 8 (right shift by 3)
            data_out <= (sum - buffer[index] + data_in) >> 3;
        end
    end

endmodule

output.rtl/nbit_swizzling.sv:
module nbit_swizzling #(
    parameter DATA_WIDTH = 64
) (
    input  logic [DATA_WIDTH-1:0] data_in,
    input  logic [1:0]            sel,
    output logic [DATA_WIDTH-1:0] data_out
);

    // Local parameters for segment sizes
    localparam HALF_WIDTH    = DATA_WIDTH / 2;
    localparam QUARTER_WIDTH = DATA_WIDTH / 4;
    localparam EIGHTH_WIDTH  = DATA_WIDTH / 8;

    // Function to reverse bits of a given width
    function automatic logic [DATA_WIDTH-1:0] reverse_bits;
        input logic [DATA_WIDTH-1:0] in_data;
        input integer                width;
        input integer                offset;
        integer i;
        begin
            reverse_bits = in_data;
            for (i = 0; i < width; i++) begin
                reverse_bits[offset + i] = in_data[offset + width - 1 - i];
            end
        end
    endfunction

    always_comb begin
        case (sel)
            2'b00: begin
                // Reverse entire input
                integer i;
                for (i = 0; i < DATA_WIDTH; i++) begin
                    data_out[i] = data_in[DATA_WIDTH-1-i];
                end
            end
            2'b01: begin
                // Divide into 2 halves and reverse each half separately
                integer i;
                for (i = 0; i < HALF_WIDTH; i++) begin
                    data_out[i]             = data_in[HALF_WIDTH-1-i];
                    data_out[HALF_WIDTH+i]  = data_in[DATA_WIDTH-1-i];
                end
            end
            2'b10: begin
                // Divide into 4 quarters and reverse each quarter separately
                integer i;
                for (i = 0; i < QUARTER_WIDTH; i++) begin
                    data_out[i]                      = data_in[QUARTER_WIDTH-1-i];
                    data_out[QUARTER_WIDTH+i]        = data_in[2*QUARTER_WIDTH-1-i];
                    data_out[2*QUARTER_WIDTH+i]      = data_in[3*QUARTER_WIDTH-1-i];
                    data_out[3*QUARTER_WIDTH+i]      = data_in[4*QUARTER_WIDTH-1-i];
                end
            end
            2'b11: begin
                // Divide into 8 sections and reverse each section separately
                integer i;
                for (i = 0; i < EIGHTH_WIDTH; i++) begin
                    data_out[i]                = data_in[EIGHTH_WIDTH-1-i];
                    data_out[EIGHTH_WIDTH+i]   = data_in[2*EIGHTH_WIDTH-1-i];
                    data_out[2*EIGHTH_WIDTH+i] = data_in[3*EIGHTH_WIDTH-1-i];
                    data_out[3*EIGHTH_WIDTH+i] = data_in[4*EIGHTH_WIDTH-1-i];
                    data_out[4*EIGHTH_WIDTH+i] = data_in[5*EIGHTH_WIDTH-1-i];
                    data_out[5*EIGHTH_WIDTH+i] = data_in[6*EIGHTH_WIDTH-1-i];
                    data_out[6*EIGHTH_WIDTH+i] = data_in[7*EIGHTH_WIDTH-1-i];
                    data_out[7*EIGHTH_WIDTH+i] = data_in[8*EIGHTH_WIDTH-1-i];
                end
            end
            default: begin
                data_out = data_in;
            end
        endcase
    end

endmodule

output.rtl/load_store_unit.sv:
module load_store_unit (
    // Clock and Reset
    input  logic        clk,
    input  logic        rst_n,

    // Data-Cache Interface
    output logic        dmem_req_o,
    input  logic        dmem_gnt_i,
    output logic [31:0] dmem_req_addr_o,
    output logic        dmem_req_we_o,
    output logic [3:0]  dmem_req_be_o,
    output logic [31:0] dmem_req_wdata_o,
    input  logic        dmem_rvalid_i,
    input  logic [31:0] dmem_rsp_rdata_i,

    // Execution Stage Interface
    input  logic        ex_if_req_i,
    input  logic        ex_if_we_i,
    input  logic [1:0]  ex_if_type_i,
    input  logic [31:0] ex_if_wdata_i,
    input  logic [31:0] ex_if_addr_base_i,
    input  logic [31:0] ex_if_addr_offset_i,
    output logic        ex_if_ready_o,

    // Writeback Interface
    output logic [31:0] wb_if_rdata_o,
    output logic        wb_if_rvalid_o
);

    // Internal state machine
    typedef enum logic [2:0] {
        IDLE        = 3'b000,
        MEM_REQ     = 3'b001,
        WAIT_GNT    = 3'b010,
        WAIT_RVALID = 3'b011,
        COMPLETE    = 3'b100
    } state_t;

    state_t state, next_state;

    // Registered signals
    logic        req_we_r;
    logic [1:0]  req_type_r;
    logic [31:0] req_addr_r;
    logic [31:0] req_wdata_r;
    logic [3:0]  req_be_r;

    // Combinational signals
    logic [31:0] eff_addr;
    logic [1:0]  addr_lsb;
    logic [3:0]  byte_enable;
    logic        misaligned;
    logic        accepted;

    // Effective address calculation
    assign eff_addr = ex_if_addr_base_i + ex_if_addr_offset_i;
    assign addr_lsb = eff_addr[1:0];

    // Byte enable and misalignment detection
    always_comb begin
        byte_enable = 4'b0000;
        misaligned  = 1'b0;

        case (ex_if_type_i)
            2'b00: begin // Byte access
                case (addr_lsb)
                    2'b00: byte_enable = 4'b0001;
                    2'b01: byte_enable = 4'b0010;
                    2'b10: byte_enable = 4'b0100;
                    2'b11: byte_enable = 4'b1000;
                    default: byte_enable = 4'b0000;
                endcase
                misaligned = 1'b0;
            end
            2'b01: begin // Halfword access
                if (addr_lsb == 2'b00) begin
                    byte_enable = 4'b0011;
                    misaligned  = 1'b0;
                end else if (addr_lsb == 2'b10) begin
                    byte_enable = 4'b1100;
                    misaligned  = 1'b0;
                end else begin
                    byte_enable = 4'b0000;
                    misaligned  = 1'b1;
                end
            end
            2'b10: begin // Word access
                if (addr_lsb == 2'b00) begin
                    byte_enable = 4'b1111;
                    misaligned  = 1'b0;
                end else begin
                    byte_enable = 4'b0000;
                    misaligned  = 1'b1;
                end
            end
            default: begin
                byte_enable = 4'b0000;
                misaligned  = 1'b1;
            end
        endcase
    end

    // Request accepted when LSU is ready, request is asserted, and not misaligned
    assign accepted = ex_if_ready_o & ex_if_req_i & ~misaligned;

    // State register
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // Next state logic
    always_comb begin
        next_state = state;
        case (state)
            IDLE: begin
                if (accepted) begin
                    next_state = MEM_REQ;
                end
            end
            MEM_REQ: begin
                // dmem_req_o is asserted, wait for grant
                if (dmem_gnt_i) begin
                    if (req_we_r) begin
                        // Store: complete after grant
                        next_state = COMPLETE;
                    end else begin
                        // Load: wait for rvalid
                        next_state = WAIT_RVALID;
                    end
                end else begin
                    next_state = WAIT_GNT;
                end
            end
            WAIT_GNT: begin
                if (dmem_gnt_i) begin
                    if (req_we_r) begin
                        next_state = COMPLETE;
                    end else begin
                        next_state = WAIT_RVALID;
                    end
                end
            end
            WAIT_RVALID: begin
                if (dmem_rvalid_i) begin
                    next_state = COMPLETE;
                end
            end
            COMPLETE: begin
                next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    // Registered control signals for memory request
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            req_we_r    <= 1'b0;
            req_type_r  <= 2'b00;
            req_addr_r  <= 32'b0;
            req_wdata_r <= 32'b0;
            req_be_r    <= 4'b0;
        end else begin
            if (accepted) begin
                req_we_r    <= ex_if_we_i;
                req_type_r  <= ex_if_type_i;
                req_addr_r  <= eff_addr;
                req_wdata_r <= ex_if_wdata_i;
                req_be_r    <= byte_enable;
            end
        end
    end

    // dmem_req_o: asserted in MEM_REQ and WAIT_GNT states
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            dmem_req_o       <= 1'b0;
            dmem_req_we_o    <= 1'b0;
            dmem_req_addr_o  <= 32'b0;
            dmem_req_be_o    <= 4'b0;
            dmem_req_wdata_o <= 32'b0;
        end else begin
            case (state)
                IDLE: begin
                    if (accepted) begin
                        // Will transition to MEM_REQ, setup memory signals
                        dmem_req_o       <= 1'b1;
                        dmem_req_we_o    <= ex_if_we_i;
                        dmem_req_addr_o  <= eff_addr;
                        dmem_req_be_o    <= byte_enable;
                        dmem_req_wdata_o <= ex_if_wdata_i;
                    end else begin
                        dmem_req_o       <= 1'b0;
                        dmem_req_we_o    <= 1'b0;
                        dmem_req_addr_o  <= 32'b0;
                        dmem_req_be_o    <= 4'b0;
                        dmem_req_wdata_o <= 32'b0;
                    end
                end
                MEM_REQ: begin
                    if (dmem_gnt_i) begin
                        // Deassert request after grant
                        dmem_req_o       <= 1'b0;
                        dmem_req_we_o    <= 1'b0;
                        dmem_req_addr_o  <= 32'b0;
                        dmem_req_be_o    <= 4'b0;
                        dmem_req_wdata_o <= 32'b0;
                    end
                    // else keep signals asserted
                end
                WAIT_GNT: begin
                    if (dmem_gnt_i) begin
                        dmem_req_o       <= 1'b0;
                        dmem_req_we_o    <= 1'b0;
                        dmem_req_addr_o  <= 32'b0;
                        dmem_req_be_o    <= 4'b0;
                        dmem_req_wdata_o <= 32'b0;
                    end
                    // else keep signals asserted
                end
                WAIT_RVALID: begin
                    // Already cleared, keep cleared
                    dmem_req_o       <= 1'b0;
                    dmem_req_we_o    <= 1'b0;
                    dmem_req_addr_o  <= 32'b0;
                    dmem_req_be_o    <= 4'b0;
                    dmem_req_wdata_o <= 32'b0;
                end
                COMPLETE: begin
                    dmem_req_o       <= 1'b0;
                    dmem_req_we_o    <= 1'b0;
                    dmem_req_addr_o  <= 32'b0;
                    dmem_req_be_o    <= 4'b0;
                    dmem_req_wdata_o <= 32'b0;
                end
                default: begin
                    dmem_req_o       <= 1'b0;
                    dmem_req_we_o    <= 1'b0;
                    dmem_req_addr_o  <= 32'b0;
                    dmem_req_be_o    <= 4'b0;
                    dmem_req_wdata_o <= 32'b0;
                end
            endcase
        end
    end

    // ex_if_ready_o: asserted in IDLE and COMPLETE states
    // Deasserted with one-cycle latency after accepting a request
    // Re-asserted with one-cycle latency after transaction completes
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ex_if_ready_o <= 1'b1;
        end else begin
            case (state)
                IDLE: begin
                    if (accepted) begin
                        ex_if_ready_o <= 1'b0;
                    end else begin
                        ex_if_ready_o <= 1'b1;
                    end
                end
                MEM_REQ: begin
                    ex_if_ready_o <= 1'b0;
                end
                WAIT_GNT: begin
                    ex_if_ready_o <= 1'b0;
                end
                WAIT_RVALID: begin
                    ex_if_ready_o <= 1'b0;
                end
                COMPLETE: begin
                    // Re-assert ready after complete (one cycle latency)
                    ex_if_ready_o <= 1'b1;
                end
                default: begin
                    ex_if_ready_o <= 1'b1;
                end
            endcase
        end
    end

    // Writeback interface
    // wb_if_rvalid_o asserted one cycle after dmem_rvalid_i
    // wb_if_rdata_o updated one cycle after dmem_rvalid_i, maintained until next load
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wb_if_rvalid_o <= 1'b0;
            wb_if_rdata_o  <= 32'b0;
        end else begin
            // Default: deassert rvalid
            wb_if_rvalid_o <= 1'b0;

            if (state == WAIT_RVALID && dmem_rvalid_i) begin
                wb_if_rvalid_o <= 1'b1;
                wb_if_rdata_o  <= dmem_rsp_rdata_i;
            end
        end
    end

endmodule

output.rtl/palindrome_detect.sv:
module palindrome_detect #( 
parameter N=3
) (
input clk,
input reset,
input bit_stream,
output palindrome_detected
);

// Shift register to store the last N bits
reg [N-1:0] shift_reg;

// Shift in the new bit at every clock cycle
always @(posedge clk) begin
    if (reset) begin
        shift_reg <= {N{1'b0}};
    end else begin
        shift_reg <= {shift_reg[N-2:0], bit_stream};
    end
end

// Check if the current N-bit window is a palindrome
// A 3-bit palindrome: bit[2] == bit[0] (middle bit can be anything)
// shift_reg[N-1] is the oldest bit, shift_reg[0] is the newest bit
reg palindrome_reg;

always @(posedge clk) begin
    if (reset) begin
        palindrome_reg <= 1'b0;
    end else begin
        // Check palindrome condition for N=3: first bit equals last bit
        // After shift, shift_reg = {old[N-2:0], bit_stream}
        // We need to check the window after the new bit is shifted in
        // The window will be: {shift_reg[N-2:0], bit_stream}
        // For N=3: window[2]=shift_reg[1], window[1]=shift_reg[0], window[0]=bit_stream
        // Palindrome if window[2] == window[0], i.e., shift_reg[1] == bit_stream
        palindrome_reg <= (shift_reg[N-2] == bit_stream);
    end
end

assign palindrome_detected = palindrome_reg;

endmodule

output.rtl/cvdp_copilot_perf_counters.sv:
// Performance Counter Module
// Counts events triggered by CPU pipeline and has software-controlled reset

module cvdp_copilot_perf_counters #(
    parameter CNT_W = 32  // Counter width, parameterizable
) (
    input  logic             clk,        // Clock signal
    input  logic             reset,      // Active-high asynchronous reset
    input  logic             sw_req_i,   // Software request signal
    input  logic             cpu_trig_i, // CPU trigger signal
    output logic [CNT_W-1:0] p_count_o   // Performance counter output
);

    // Internal counter register
    logic [CNT_W-1:0] count_q;

    // Counter logic: increment on cpu_trig_i, reset after sw_req_i read
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            count_q <= {CNT_W{1'b0}};
        end else if (sw_req_i) begin
            // After software reads, reset counter to zero
            // But if cpu_trig_i is also active at the same time,
            // we still reset (read takes priority for reset, but count starts fresh)
            if (cpu_trig_i) begin
                count_q <= {{(CNT_W-1){1'b0}}, 1'b1};
            end else begin
                count_q <= {CNT_W{1'b0}};
            end
        end else if (cpu_trig_i) begin
            count_q <= count_q + {{(CNT_W-1){1'b0}}, 1'b1};
        end
    end

    // Output logic: only output counter value when software requests it
    // Otherwise output zero
    always_comb begin
        if (sw_req_i) begin
