// Module: cvdp_prbs_gen
// Description: PRBS Generator and Checker module
// Supports both generator mode (CHECK_MODE=0) and checker mode (CHECK_MODE=1)

module cvdp_prbs_gen #(
    parameter integer CHECK_MODE  = 0,   // 0: Generator, 1: Checker
    parameter integer POLY_LENGTH = 31,  // Length of polynomial (LFSR stages)
    parameter integer POLY_TAP    = 3,   // Tap position for feedback XOR
    parameter integer WIDTH       = 16   // Data bus width
) (
    input  logic             clk,
    input  logic             rst,
    input  logic [WIDTH-1:0] data_in,
    output logic [WIDTH-1:0] data_out
);

    // PRBS shift register
    logic [POLY_LENGTH-1:0] prbs_reg;

    // Combinational signals for next state computation
    logic [POLY_LENGTH-1:0] prbs_next [0:WIDTH];
    logic [WIDTH-1:0]       data_out_comb;
    logic                   feedback_bit;

    // Initialize prbs_next[0] to current prbs_reg
    // Then compute WIDTH iterations

    integer i;

    always_comb begin
        // Start with current register state
        prbs_next[0] = prbs_reg;

        for (i = 0; i < WIDTH; i = i + 1) begin
            // Feedback bit: XOR of bit at POLY_LENGTH-1 (MSB, position POLY_LENGTH)
            // and bit at POLY_TAP-1 (position POLY_TAP)
            feedback_bit = prbs_next[i][POLY_LENGTH-1] ^ prbs_next[i][POLY_TAP-1];

            // Shift register: shift right (towards LSB), insert feedback at MSB
            prbs_next[i+1] = {feedback_bit, prbs_next[i][POLY_LENGTH-1:1]};

            if (CHECK_MODE == 0) begin
                // Generator mode: output is the feedback bit (new MSB)
                data_out_comb[i] = feedback_bit;
            end else begin
                // Checker mode: compare input bit with expected PRBS bit
                // Expected bit is the same feedback_bit as in generator mode
                data_out_comb[i] = data_in[i] ^ feedback_bit;
            end
        end
    end

    // Sequential logic
    always_ff @(posedge clk) begin
        if (rst) begin
            prbs_reg  <= {POLY_LENGTH{1'b1}};
            data_out  <= {WIDTH{1'b1}};
        end else begin
            prbs_reg  <= prbs_next[WIDTH];
            data_out  <= data_out_comb;
        end
    end

endmodule

output.rtl/secure_read_write_bus_interface.v:
// secure_read_write_bus_interface.v
// Parameterized read/write bus interface with 8-bit configurable key authorization

module secure_read_write_bus_interface #(
    parameter p_configurable_key = 8'hAA,
    parameter p_data_width       = 8,
    parameter p_addr_width       = 8
)(
    input  wire [p_addr_width-1:0] i_addr,
    input  wire [p_data_width-1:0] i_data_in,
    input  wire [7:0]              i_key_in,
    input  wire                    i_read_write_enable,
    input  wire                    i_capture_pulse,
    input  wire                    i_reset_bar,
    output reg  [p_data_width-1:0] o_data_out,
    output reg                     o_error
);

    // Internal memory array: 2^p_addr_width locations, each p_data_width bits wide
    reg [p_data_width-1:0] mem [0:(1<<p_addr_width)-1];

    integer idx;

    always @(posedge i_capture_pulse or negedge i_reset_bar) begin
        if (!i_reset_bar) begin
            // Asynchronous active-low reset: clear outputs and memory
            o_data_out <= {p_data_width{1'b0}};
            o_error    <= 1'b0;
            for (idx = 0; idx < (1<<p_addr_width); idx = idx + 1) begin
                mem[idx] <= {p_data_width{1'b0}};
            end
        end else begin
            if (i_key_in == p_configurable_key[7:0]) begin
                // Authorized access
                o_error <= 1'b0;
                if (i_read_write_enable == 1'b0) begin
                    // Write operation
                    mem[i_addr] <= i_data_in;
                    o_data_out  <= {p_data_width{1'b0}};
                end else begin
                    // Read operation
                    o_data_out <= mem[i_addr];
                end
            end else begin
                // Unauthorized access
                o_error    <= 1'b1;
                o_data_out <= {p_data_width{1'b0}};
            end
        end
    end

endmodule

output.rtl/restore_division.sv:
module restoring_division #(
    parameter WIDTH = 6
)(
    input  logic             clk,
    input  logic             rst,
    input  logic             start,
    input  logic [WIDTH-1:0] dividend,
    input  logic [WIDTH-1:0] divisor,
    output logic [WIDTH-1:0] quotient,
    output logic [WIDTH-1:0] remainder,
    output logic             valid
);

    // Determine number of iterations needed
    // If WIDTH is power of 2, use WIDTH cycles; otherwise WIDTH+1 cycles
    function automatic integer is_power_of_2(input integer n);
        return (n > 0) && ((n & (n - 1)) == 0);
    endfunction

    localparam ITER = is_power_of_2(WIDTH) ? WIDTH : WIDTH + 1;
    localparam CNT_WIDTH = $clog2(ITER + 1);

    // Internal registers
    logic [WIDTH-1:0]   dividend_reg;
    logic [WIDTH-1:0]   divisor_reg;
    logic [WIDTH-1:0]   remainder_reg;
    logic [WIDTH-1:0]   quotient_reg;
    logic [CNT_WIDTH-1:0] count;
    logic               running;

    // Subtraction result (one extra bit for sign detection)
    logic [WIDTH:0]     sub_result;
    logic [WIDTH-1:0]   shifted_remainder;

    always_ff @(posedge clk or negedge rst) begin
        if (!rst) begin
            dividend_reg  <= '0;
            divisor_reg   <= '0;
            remainder_reg <= '0;
            quotient_reg  <= '0;
            quotient      <= '0;
            remainder     <= '0;
            valid         <= 1'b0;
            count         <= '0;
            running       <= 1'b0;
        end else begin
            valid <= 1'b0;

            if (start && !running) begin
                // Initialize
                dividend_reg  <= dividend;
                divisor_reg   <= divisor;
                remainder_reg <= '0;
                quotient_reg  <= '0;
                count         <= '0;
                running       <= 1'b1;
            end else if (running) begin
                if (count < ITER[CNT_WIDTH-1:0]) begin
                    // Shift remainder left and append MSB of dividend_reg
                    shifted_remainder = {remainder_reg[WIDTH-2:0], dividend_reg[WIDTH-1]};
                    // Shift dividend left
                    dividend_reg <= {dividend_reg[WIDTH-2:0], 1'b0};

                    // Subtract divisor
                    sub_result = {1'b0, shifted_remainder} - {1'b0, divisor_reg};

                    if (sub_result[WIDTH] == 1'b0) begin
                        // Result is non-negative, keep it
                        remainder_reg <= sub_result[WIDTH-1:0];
                        quotient_reg  <= {quotient_reg[WIDTH-2:0], 1'b1};
                    end else begin
                        // Result is negative, restore remainder
                        remainder_reg <= shifted_remainder;
                        quotient_reg  <= {quotient_reg[WIDTH-2:0], 1'b0};
                    end

                    count <= count + 1'b1;
                end else begin
                    // Done
                    quotient  <= quotient_reg;
                    remainder <= remainder_reg;
                    valid     <= 1'b1;
                    running   <= 1'b0;
                end
            end
        end
    end

endmodule

