output.rtl/secure_read_write_register_bank.v:
// rtl/secure_read_write_register_bank.v

module secure_read_write_register_bank #(
    parameter p_address_width  = 8,
    parameter p_data_width     = 8,
    parameter p_unlock_code_0  = 8'hAB,
    parameter p_unlock_code_1  = 8'hCD
)(
    input  wire [p_address_width-1:0] i_addr,
    input  wire [p_data_width-1:0]    i_data_in,
    input  wire                        i_read_write_enable,
    input  wire                        i_capture_pulse,
    input  wire                        i_rst_n,
    output reg  [p_data_width-1:0]    o_data_out
);

    // Register bank memory
    // Total addressable space = 2^p_address_width
    localparam MEM_DEPTH = (1 << p_address_width);

    reg [p_data_width-1:0] mem [0:MEM_DEPTH-1];

    // Unlock state machine states
    // State 0: Locked, waiting for unlock code 0 at address 0
    // State 1: Got code 0 at address 0, waiting for code 1 at address 1
    // State 2: Unlocked
    localparam STATE_LOCKED       = 2'b00;
    localparam STATE_GOT_CODE_0   = 2'b01;
    localparam STATE_UNLOCKED     = 2'b10;

    reg [1:0] unlock_state;

    integer i;

    always @(posedge i_capture_pulse or negedge i_rst_n) begin
        if (!i_rst_n) begin
            // Asynchronous reset
            unlock_state <= STATE_LOCKED;
            o_data_out   <= {p_data_width{1'b0}};
            // Optionally clear memory on reset - not specified, so leave as is
        end else begin
            // Default output
            o_data_out <= {p_data_width{1'b0}};

            if (!i_read_write_enable) begin
                // Write operation
                case (i_addr)
                    {{(p_address_width-1){1'b0}}, 1'b0}: begin
                        // Address 0 write
                        // Write to memory[0]
                        mem[0] <= i_data_in;
                        // Check unlock code 0
                        if (i_data_in == p_unlock_code_0[p_data_width-1:0]) begin
                            unlock_state <= STATE_GOT_CODE_0;
                        end else begin
                            // Wrong code, lock
                            unlock_state <= STATE_LOCKED;
                        end
                        o_data_out <= {p_data_width{1'b0}};
                    end

                    {{(p_address_width-1){1'b0}}, 1'b1}: begin
                        // Address 1 write
                        // Write to memory[1]
                        mem[1] <= i_data_in;
                        // Check unlock sequence
                        if (unlock_state == STATE_GOT_CODE_0 && i_data_in == p_unlock_code_1[p_data_width-1:0]) begin
                            unlock_state <= STATE_UNLOCKED;
                        end else begin
                            // Wrong code or wrong sequence, lock
                            unlock_state <= STATE_LOCKED;
                        end
                        o_data_out <= {p_data_width{1'b0}};
                    end

                    default: begin
                        // Other addresses
                        if (unlock_state == STATE_UNLOCKED) begin
                            mem[i_addr] <= i_data_in;
                        end
                        // If locked, do not write, output stays 0
                        o_data_out <= {p_data_width{1'b0}};
                    end
                endcase
            end else begin
                // Read operation
                case (i_addr)
                    {{(p_address_width-1){1'b0}}, 1'b0}: begin
                        // Address 0 is write-only, cannot be read
                        o_data_out <= {p_data_width{1'b0}};
                    end

                    {{(p_address_width-1){1'b0}}, 1'b1}: begin
                        // Address 1 is write-only, cannot be read
                        o_data_out <= {p_data_width{1'b0}};
                    end

                    default: begin
                        if (unlock_state == STATE_UNLOCKED) begin
                            o_data_out <= mem[i_addr];
                        end else begin
                            // Locked: output 0
                            o_data_out <= {p_data_width{1'b0}};
                        end
                    end
                endcase
            end
        end
    end

endmodule

output.rtl/SetBitStreamCalculator.v:
// rtl/SetBitStreamCalculator.v

module SetBitStreamCalculator #(
    parameter p_max_set_bit_count_width = 8
)(
    input  wire i_bit_in,
    input  wire i_clk,
    input  wire i_ready,
    input  wire i_rst_n,
    output reg  [p_max_set_bit_count_width-1:0] o_set_bit_count
);

    // Maximum saturation value
    localparam MAX_COUNT = {p_max_set_bit_count_width{1'b1}};

    // Register to hold previous value of i_ready for edge detection
    reg r_ready_prev;

    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            o_set_bit_count <= {p_max_set_bit_count_width{1'b0}};
            r_ready_prev    <= 1'b0;
        end else begin
            // Update previous ready
            r_ready_prev <= i_ready;

            // Detect rising edge of i_ready: reset count
            if (i_ready && !r_ready_prev) begin
                // Rising edge of i_ready: reset count, ignore first bit
                o_set_bit_count <= {p_max_set_bit_count_width{1'b0}};
            end else if (i_ready && r_ready_prev) begin
                // i_ready is high and was high previously: count i_bit_in
                if (i_bit_in) begin
                    if (o_set_bit_count == MAX_COUNT) begin
                        // Saturate
                        o_set_bit_count <= MAX_COUNT;
                    end else begin
                        o_set_bit_count <= o_set_bit_count + 1'b1;
                    end
                end
            end
            // If i_ready is low, retain current count
        end
    end

endmodule

output.rtl/perceptron_gates.sv:
// rtl/perceptron_gates.sv

module gate_target (
    input  logic [1:0] gate_select,
    output logic signed [3:0] o_1, o_2, o_3, o_4
);
    always_comb begin
        case (gate_select)
            2'b00: begin // AND Gate
                o_1 = 4'sd1;
                o_2 = -4'sd1;
                o_3 = -4'sd1;
                o_4 = -4'sd1;
            end
            2'b01: begin // OR Gate
                o_1 = 4'sd1;
                o_2 = 4'sd1;
                o_3 = 4'sd1;
                o_4 = -4'sd1;
            end
            2'b10: begin // NAND Gate
                o_1 = 4'sd1;
                o_2 = 4'sd1;
                o_3 = 4'sd1;
                o_4 = -4'sd1;
            end
            2'b11: begin // NOR Gate
                o_1 = 4'sd1;
                o_2 = -4'sd1;
                o_3 = -4'sd1;
                o_4 = -4'sd1;
            end
            default: begin
                o_1 = 4'sd0;
                o_2 = 4'sd0;
                o_3 = 4'sd0;
                o_4 = 4'sd0;
            end
        endcase
    end
endmodule


module perceptron_gates (
    input  logic        clk,
    input  logic        rst_n,
    input  logic signed [3:0] x1,
    input  logic signed [3:0] x2,
    input  logic        learning_rate,
    input  logic signed [3:0] threshold,
    input  logic [1:0]  gate_select,

    output logic signed [3:0] percep_w1,
    output logic signed [3:0] percep_w2,
    output logic signed [3:0] percep_bias,
    output logic [3:0]        present_addr,
    output logic              stop,
    output logic [2:0]        input_index,
    output logic signed [3:0] y_in,
    output logic signed [3:0] y,
    output logic signed [3:0] prev_percep_wt_1,
    output logic signed [3:0] prev_percep_wt_2,
    output logic signed [3:0] prev_percep_bias
);

    // Microcode ROM: 6 instructions
    // Each instruction is just an address/action identifier
    // We'll define actions as parameters
    localparam ACTION_INIT        = 4'd0;
    localparam ACTION_COMPUTE     = 4'd1;
    localparam ACTION_SELECT_TGT  = 4'd2;
    localparam ACTION_UPDATE      = 4'd3;
    localparam ACTION_CHECK_CONV  = 4'd4;
    localparam ACTION_NEXT_EPOCH  = 4'd5;

    // Microcode ROM: sequence of 6 actions
    logic [3:0] microcode_rom [0:5];
    initial begin
        microcode_rom[0] = ACTION_INIT;
        microcode_rom[1] = ACTION_COMPUTE;
        microcode_rom[2] = ACTION_SELECT_TGT;
        microcode_rom[3] = ACTION_UPDATE;
        microcode_rom[4] = ACTION_CHECK_CONV;
        microcode_rom[5] = ACTION_NEXT_EPOCH;
    end

    // Gate target outputs
    logic signed [3:0] t1, t2, t3, t4;
    gate_target u_gate_target (
        .gate_select(gate_select),
        .o_1(t1),
        .o_2(t2),
        .o_3(t3),
        .o_4(t4)
    );

    // Internal registers
    logic signed [3:0] target;
    logic signed [3:0] wt1_update, wt2_update, bias_update;
    logic signed [3:0] percep_wt1, percep_wt2, percep_b;
    logic signed [7:0] y_in_full;

    // Address register
    logic [3:0] addr_reg;
    logic [3:0] current_action;

    assign present_addr = addr_reg;
    assign current_action = microcode_rom[addr_reg];

    // Sequential address update
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            addr_reg <= 4'd0;
        end else begin
            if (!stop) begin
                if (addr_reg == 4'd5)
                    addr_reg <= 4'd1; // After NEXT_EPOCH, go back to COMPUTE
                else
                    addr_reg <= addr_reg + 4'd1;
            end
        end
    end

    // Main datapath
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            percep_w1        <= 4'sd0;
            percep_w2        <= 4'sd0;
            percep_bias      <= 4'sd0;
            percep_wt1       <= 4'sd0;
            percep_wt2       <= 4'sd0;
            percep_b         <= 4'sd0;
            y_in             <= 4'sd0;
            y                <= 4'sd0;
            target           <= 4'sd0;
            wt1_update       <= 4'sd0;
            wt2_update       <= 4'sd0;
            bias_update      <= 4'sd0;
            prev_percep_wt_1 <= 4'sd0;
            prev_percep_wt_2 <= 4'sd0;
            prev_percep_bias <= 4'sd0;
            input_index      <= 3'd0;
            stop             <= 1'b0;
        end else begin
            if (!stop) begin
                case (current_action)
                    ACTION_INIT: begin
                        // Initialize weights and bias to zero
                        percep_w1        <= 4'sd0;
                        percep_w2        <= 4'sd0;
                        percep_bias      <= 4'sd0;
                        percep_wt1       <= 4'sd0;
                        percep_wt2       <= 4'sd0;
                        percep_b         <= 4'sd0;
                        wt1_update       <= 4'sd0;
                        wt2_update       <= 4'sd0;
                        bias_update      <= 4'sd0;
                        prev_percep_wt_1 <= 4'sd0;
                        prev_percep_wt_2 <= 4'sd0;
                        prev_percep_bias <= 4'sd0;
                        input_index      <= 3'd0;
                        y_in             <= 4'sd0;
                        y                <= 4'sd0;
                        target           <= 4'sd0;
                    end

                    ACTION_COMPUTE: begin
                        // Compute y_in = bias + x1*w1 + x2*w2
                        y_in_full = {{4{percep_w1[3]}}, percep_w1} + 
                                    (x1 * percep_w1) + 
                                    (x2 * percep_w2) + 
                                    {{4{percep_bias[3]}}, percep_bias};
                        // Simplified: y_in = bias + x1*w1 + x2*w2
                        y_in <= percep_bias + (x1 * percep_w1) + (x2 * percep_w2);

                        // Compute y based on threshold
                        begin
                            logic signed [3:0] computed_yin;
                            computed_yin = percep_bias + (x1 * percep_w1) + (x2 * percep_w2);
                            if (computed_yin > threshold)
                                y <= 4'sd1;
                            else if (computed_yin < -threshold)
                                y <= -4'sd1;
                            else
                                y <= 4'sd0;
                        end
                    end

                    ACTION_SELECT_TGT: begin
                        // Select target based on input_index and gate_select
                        case (input_index)
                            3'd0: target <= t1;
                            3'd1: target <= t2;
                            3'd2: target <= t3;
                            3'd3: target <= t4;
                            default: target <= 4'sd0;
                        endcase
                    end

                    ACTION_UPDATE: begin
                        // Update weights and bias if y != target
                        if (y != target) begin
                            wt1_update  <= learning_rate ? x1 * target : 4'sd0;
                            wt2_update  <= learning_rate ? x2 * target : 4'sd0;
                            bias_update <= learning_rate ? target : 4'sd0;
                        end else begin
                            wt1_update  <= 4'sd0;
                            wt2_update  <= 4'sd0;
                            bias_update <= 4'sd0;
                        end

                        // Apply updates
                        begin
                            logic signed [3:0] wu1, wu2, bu;
                            if (y != target) begin
                                wu1 = learning_rate ? x1 * target : 4'sd0;
                                wu2 = learning_rate ? x2 * target : 4'sd0;
                                bu  = learning_rate ? target : 4'sd0;
                            end else begin
                                wu1 = 4'sd0;
                                wu2 = 4'sd0;
                                bu  = 4'sd0;
                            end
                            percep_w1   <= percep_w1   + wu1;
                            percep_w2   <= percep_w2   + wu2;
                            percep_bias <= percep_bias + bu;
                        end
                    end

                    ACTION_CHECK_CONV: begin
                        // Check convergence: compare current updates with previous
                        if ((wt1_update == prev_percep_wt_1) &&
                            (wt2_update == prev_percep_wt_2) &&
                            (bias_update == prev_percep_bias)) begin
                            // Check if we've gone through all inputs
                            if (input_index == 3'd3) begin
                                stop <= 1'b1;
                            end
                        end else begin
                            // Not converged, update previous values
                            prev_percep_wt_1 <= wt1_update;
                            prev_percep_wt_2 <= wt2_update;
                            prev_percep_bias <= bias_update;
                        end
                    end

                    ACTION_NEXT_EPOCH: begin
                        // Increment input index and prepare for next iteration
                        if (input_index == 3'd3) begin
                            input_index <= 3'd0;
                            // Reset previous updates for new epoch tracking
                            prev_percep_wt_1 <= 4'sd0;
                            prev_percep_wt_2 <= 4'sd0;
                            prev_percep_bias <= 4'sd0;
                        end else begin
                            input_index <= input_index + 3'd1;
                        end
                    end

                    default: begin
                        // Do nothing
                    end
                endcase
            end
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo #(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
) (
    input  logic                  clock,
    input  logic                  reset,
    input  logic                  write_en,
    input  logic                  read_en,
    input  logic [DATA_WIDTH-1:0] data_in,
    output logic                  empty,
    output logic                  full,
    output logic [DATA_WIDTH-1:0] data_out
);

    localparam DEPTH = 2**ADDR_WIDTH;

    logic [DATA_WIDTH-1:0] mem [0:DEPTH-1];
    logic [ADDR_WIDTH:0]   stack_ptr; // One extra bit to detect full/empty

    // Full and empty signals
    assign empty = (stack_ptr == 0);
    assign full  = (stack_ptr == DEPTH);

    integer i;

    always_ff @(posedge clock) begin
        if (reset) begin
            stack_ptr <= 0;
            data_out  <= {DATA_WIDTH{1'b0}};
            for (i = 0; i < DEPTH; i = i + 1) begin
                mem[i] <= {DATA_WIDTH{1'b0}};
            end
        end else begin
            // Write operation
            if (write_en && !full) begin
                mem[stack_ptr] <= data_in;
                stack_ptr <= stack_ptr + 1;
            end

            // Read operation
            if (read_en && !empty) begin
                data_out  <= mem[stack_ptr - 1];
                stack_ptr <= stack_ptr - 1;
            end
        end
    end

endmodule

output.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter int N     = 8,
    parameter int WIDTH = 8
)(
    input  logic                  clk,
    input  logic                  rst,
    input  logic                  start,
    input  logic [N*WIDTH-1:0]    in_data,
    output logic                  done,
    output logic [N*WIDTH-1:0]    out_data
);

    // State encoding
    typedef enum logic [1:0] {
        IDLE    = 2'b00,
        SORTING = 2'b01,
        DONE    = 2'b10
    } state_t;

    state_t state, next_state;

    // Internal array
    logic [WIDTH-1:0] arr [0:N-1];

    // Counters
    // Total passes = N*(N-1), each pass does one comparison
    // We need a counter to track which comparison we're on
    // Total comparisons = N*(N-1)
    // Index into the "flat" list of comparisons
    // For bubble sort: pass p (0 to N-2), compare index i (0 to N-2-p)
    // But we're doing N*(N-1) total passes (comparisons)

    // Counter for total steps: N*(N-1) steps
    localparam int TOTAL_STEPS = N * (N - 1);
    localparam int CNT_WIDTH   = $clog2(TOTAL_STEPS + 1);

    logic [CNT_WIDTH-1:0] step_cnt;

    // For each step, we need to know which pair to compare
    // We'll use pass and index counters
    // pass: 0 to N-2, index: 0 to N-2-pass
    // But we do exactly N*(N-1) steps total (not early termination)
    // Let's track pass_cnt and idx_cnt

    localparam int PASS_CNT_WIDTH = $clog2(N);
    localparam int IDX_CNT_WIDTH  = $clog2(N);

    logic [PASS_CNT_WIDTH-1:0] pass_cnt;
    logic [IDX_CNT_WIDTH-1:0]  idx_cnt;

    // Temporary for swap
    logic [WIDTH-1:0] temp;

    integer k;

    // State register
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            state    <= IDLE;
            done     <= 1'b0;
            step_cnt <= '0;
            pass_cnt <= '0;
            idx_cnt  <= '0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done     <= 1'b0;
                    step_cnt <= '0;
                    pass_cnt <= '0;
                    idx_cnt  <= '0;
                    if (start) begin
                        // Load input data into internal array
                        for (k = 0; k < N; k++) begin
                            arr[k] <= in_data[k*WIDTH +: WIDTH];
                        end
                    end
                end

                SORTING: begin
                    done <= 1'b0;
                    // Perform one comparison/swap per cycle
                    // Current comparison: arr[idx_cnt] vs arr[idx_cnt+1]
                    if (arr[idx_cnt] > arr[idx_cnt + 1]) begin
                        // Swap
                        arr[idx_cnt]     <= arr[idx_cnt + 1];
                        arr[idx_cnt + 1] <= arr[idx_cnt];
                    end

                    // Advance counters
                    step_cnt <= step_cnt + 1'b1;

                    // Advance idx_cnt and pass_cnt
                    // In a standard bubble sort pass p, we go from idx=0 to idx=N-2-p
                    // When idx_cnt reaches N-2-pass_cnt, move to next pass
                    if (idx_cnt >= (N - 2 - pass_cnt)) begin
                        idx_cnt  <= '0;
                        pass_cnt <= pass_cnt + 1'b1;
                    end else begin
                        idx_cnt <= idx_cnt + 1'b1;
                    end
                end

                DONE: begin
                    done <= 1'b1;
                    // Write sorted array to output
                    for (k = 0; k < N; k++) begin
                        out_data[k*WIDTH +: WIDTH] <= arr[k];
                    end
                end

                default: begin
                    done <= 1'b0;
                end
            endcase
        end
    end

    // Next state logic
    always_comb begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
                else
                    next_state = IDLE;
            end

            SORTING: begin
                // Done after N*(N-1) steps
                if (step_cnt == (TOTAL_STEPS - 1))
                    next_state = DONE;
                else
                    next_state = SORTING;
            end

            DONE: begin
                // done is pulsed for 1 cycle, go back to IDLE
                next_state = IDLE;
            end

            default: next_state = IDLE;
        endcase
    end

endmodule

output.rtl/ttc_counter_lite.sv:
// ttc_counter_lite.sv
// Lightweight Timer/Counter with AXI-Lite register interface

module ttc_counter_lite (
    input  logic        clk,
    input  logic        reset,
    input  logic [3:0]  axi_addr,
    input  logic [31:0] axi_wdata,
    input  logic        axi_write_en,
    input  logic        axi_read_en,
    output logic [31:0] axi_rdata,
    output logic        interrupt
);

    // Internal registers
    logic [15:0] count;
    logic [15:0] match_value;
    logic [15:0] reload_value;
    logic        enable;
    logic        interval_mode;
    logic        interrupt_enable;
    logic        match_flag;
    logic        interrupt_status;

    // Address definitions
    localparam ADDR_COUNT   = 4'h0;
    localparam ADDR_MATCH   = 4'h1;
    localparam ADDR_RELOAD  = 4'h2;
    localparam ADDR_CTRL    = 4'h3;
    localparam ADDR_STATUS  = 4'h4;

    // Write logic
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            match_value      <= 16'hFFFF;
            reload_value     <= 16'h0000;
            enable           <= 1'b0;
            interval_mode    <= 1'b0;
            interrupt_enable <= 1'b0;
        end else if (axi_write_en) begin
            case (axi_addr)
                ADDR_MATCH: begin
                    match_value <= axi_wdata[15:0];
                end
                ADDR_RELOAD: begin
                    reload_value <= axi_wdata[15:0];
                end
                ADDR_CTRL: begin
                    enable           <= axi_wdata[0];
                    interval_mode    <= axi_wdata[1];
                    interrupt_enable <= axi_wdata[2];
                end
                default: begin
                    // No action for other addresses
                end
            endcase
        end
    end

    // Counter logic
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            count      <= 16'h0000;
            match_flag <= 1'b0;
        end else begin
            if (enable) begin
                if (count == match_value) begin
                    match_flag <= 1'b1;
                    if (interval_mode) begin
                        count <= reload_value;
                    end else begin
                        count <= count; // Hold at match value
                    end
                end else begin
                    match_flag <= 1'b0;
                    count      <= count + 16'h1;
                end
            end else begin
                match_flag <= 1'b0;
            end
        end
    end

    // Interrupt status logic
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            interrupt_status <= 1'b0;
        end else begin
            // Clear interrupt when status register is written
            if (axi_write_en && (axi_addr == ADDR_STATUS)) begin
                interrupt_status <= 1'b0;
            end else if (match_flag && interrupt_enable) begin
                interrupt_status <= 1'b1;
            end
        end
    end

    // Interrupt output
    assign interrupt = interrupt_status & interrupt_enable;

    // Read logic
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            axi_rdata <= 32'h0000_0000;
        end else if (axi_read_en) begin
            case (axi_addr)
                ADDR_COUNT: begin
                    axi_rdata <= {16'h0000, count};
                end
                ADDR_MATCH: begin
                    axi_rdata <= {16'h0000, match_value};
                end
                ADDR_RELOAD: begin
                    axi_rdata <= {16'h0000, reload_value};
                end
                ADDR_CTRL: begin
                    axi_rdata <= {29'h0000_0000, interrupt_enable, interval_mode, enable};
                end
                ADDR_STATUS: begin
                    axi_rdata <= {31'h0000_0000, interrupt_status};
                end
                default: begin
                    axi_rdata <= 32'h0000_0000;
                end
            endcase
        end else begin
            axi_rdata <= 32'h0000_0000;
        end
    end

endmodule

output.rtl/sync_serial_communication_top.sv:
// rtl/sync_serial_communication_top.sv

module tx_block (
    input  logic        clk,
    input  logic        reset_n,
    input  logic [63:0] data_in,
    input  logic [2:0]  sel,
    output logic        serial_out,
    output logic        done,
    output logic        serial_clk
);

    logic [6:0]  bit_count;
    logic [6:0]  total_bits;
    logic [63:0] shift_reg;
    logic        transmitting;

    always_comb begin
        case (sel)
            3'h1: total_bits = 7'd8;
            3'h2: total_bits = 7'd16;
            3'h3: total_bits = 7'd32;
            3'h4: total_bits = 7'd64;
            default: total_bits = 7'd0;
        endcase
    end

    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            serial_out   <= 1'b0;
            done         <= 1'b0;
            bit_count    <= 7'd0;
            shift_reg    <= 64'd0;
            transmitting <= 1'b0;
        end else begin
            if (!transmitting && !done) begin
                if (total_bits > 0) begin
                    // Load data and start transmission
                    case (sel)
                        3'h1: shift_reg <= {56'h0, data_in[7:0]};
                        3'h2: shift_reg <= {48'h0, data_in[15:0]};
                        3'h3: shift_reg <= {32'h0, data_in[31:0]};
                        3'h4: shift_reg <= data_in[63:0];
                        default: shift_reg <= 64'd0;
                    endcase
                    bit_count    <= 7'd0;
                    transmitting <= 1'b1;
                    done         <= 1'b0;
                end
            end else if (transmitting) begin
                if (bit_count < total_bits) begin
                    // Transmit MSB first
                    serial_out <= shift_reg[total_bits - 1 - bit_count];
                    bit_count  <= bit_count + 1;
                end
                if (bit_count == total_bits - 1) begin
                    // Last bit being transmitted
                end
                if (bit_count == total_bits) begin
                    transmitting <= 1'b0;
                    done         <= 1'b1;
                    serial_out   <= 1'b0;
                end
            end else if (done) begin
                done <= 1'b0;
            end
        end
    end

    // Gated clock: only active during transmission
    assign serial_clk = clk & transmitting;

endmodule


module rx_block (
    input  logic        clk,
    input  logic        reset_n,
    input  logic        data_in,
    input  logic [2:0]  sel,
    input  logic        serial_clk,
    output logic [63:0] data_out,
    output logic        done
);

    logic [6:0]  bit_count;
    logic [6:0]  total_bits;
    logic [63:0] shift_reg;
    logic        prev_serial_clk;
    logic        serial_clk_posedge;
    logic        receiving;
    logic        was_receiving;

    always_comb begin
        case (sel)
            3'h1: total_bits = 7'd8;
            3'h2: total_bits = 7'd16;
            3'h3: total_bits = 7'd32;
            3'h4: total_bits = 7'd64;
            default: total_bits = 7'd0;
        endcase
    end

    assign serial_clk_posedge = serial_clk & ~prev_serial_clk;

    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            data_out         <= 64'd0;
            done             <= 1'b0;
            bit_count        <= 7'd0;
            shift_reg        <= 64'd0;
            prev_serial_clk  <= 1'b0;
            receiving        <= 1'b0;
            was_receiving    <= 1'b0;
        end else begin
            prev_serial_clk <= serial_clk;
            done <= 1'b0;

            if (serial_clk_posedge && total_bits > 0) begin
                receiving <= 1'b1;
                was_receiving <= 1'b1;
                // Shift in data MSB first
                shift_reg <= {shift_reg[62:0], data_in};
                bit_count <= bit_count + 1;

                if (bit_count == total_bits - 1) begin
                    // This is the last bit
                    receiving <= 1'b0;
                end
            end

            // Detect end of reception: serial_clk goes low after receiving
            if (was_receiving && !serial_clk && !prev_serial_clk && !receiving) begin
                // Reconstruct data_out
                case (sel)
                    3'h0: data_out <= 64'h0;
                    3'h1: data_out <= {56'h0, shift_reg[7:0]};
                    3'h2: data_out <= {48'h0, shift_reg[15:0]};
                    3'h3: data_out <= {32'h0, shift_reg[31:0]};
                    3'h4: data_out <= shift_reg[63:0];
                    default: data_out <= 64'h0;
                endcase
                done         <= 1'b1;
                was_receiving <= 1'b0;
                bit_count    <= 7'd0;
                shift_reg    <= 64'd0;
            end
        end
    end

endmodule


module sync_serial_communication_top (
    input  logic        clk,
    input  logic        reset_n,
    input  logic [63:0] data_in,
    input  logic [2:0]  sel,
    output logic [63:0] data_out,
    output logic        done
);

    logic serial_data;
    logic serial_clk;
    logic tx_done;

    tx_block tx_inst (
        .clk        (clk),
        .reset_n    (reset_n),
        .data_in    (data_in),
        .sel        (sel),
        .serial_out (serial_data),
        .done       (tx_done),
        .serial_clk (serial_clk)
    );

    rx_block rx_inst (
        .clk        (clk),
        .reset_n    (reset_n),
        .data_in    (serial_data),
        .sel        (sel),
        .serial_clk (serial_clk),
        .data_out   (data_out),
        .done       (done)
    );

endmodule

output.rtl/thermostat.v:
// rtl/thermostat.v

module thermostat (
    input  wire       i_clk,
    input  wire       i_rst,
    input  wire [5:0] i_temp_feedback,
    input  wire       i_fan_on,
    input  wire       i_enable,
    input  wire       i_fault,
    input  wire       i_clr,
    output reg        o_heater_full,
    output reg        o_heater_medium,
    output reg        o_heater_low,
    output reg        o_aircon_full,
    output reg        o_aircon_medium,
    output reg        o_aircon_low,
    output reg        o_fan,
    output reg  [2:0] o_state
);

    // Temperature feedback bit aliases
    wire i_full_cold   = i_temp_feedback[5];
    wire i_medium_cold = i_temp_feedback[4];
    wire i_low_cold    = i_temp_feedback[3];
    wire i_low_hot     = i_temp_feedback[2];
    wire i_medium_hot  = i_temp_feedback[1];
    wire i_full_hot    = i_temp_feedback[0];

    // State encoding
    localparam [2:0] HEAT_LOW  = 3'b000;
    localparam [2:0] HEAT_MED  = 3'b001;
    localparam [2:0] HEAT_FULL = 3'b010;
    localparam [2:0] AMBIENT   = 3'b011;
    localparam [2:0] COOL_LOW  = 3'b100;
    localparam [2:0] COOL_MED  = 3'b101;
    localparam [2:0] COOL_FULL = 3'b110;

    // Internal FSM state register
    reg [2:0] state;
    reg [2:0] next_state;

    // Internal fault latch
    reg fault_latched;

    // Next state logic (combinational)
    always @(*) begin
        if (i_clr) begin
            next_state = AMBIENT;
        end else if (!i_enable) begin
            next_state = AMBIENT;
        end else begin
            // Evaluate temperature feedback
            if (i_full_cold) begin
                next_state = HEAT_FULL;
            end else if (i_medium_cold) begin
                next_state = HEAT_MED;
            end else if (i_low_cold) begin
                next_state = HEAT_LOW;
            end else if (i_full_hot) begin
                next_state = COOL_FULL;
            end else if (i_medium_hot) begin
                next_state = COOL_MED;
            end else if (i_low_hot) begin
                next_state = COOL_LOW;
            end else begin
                next_state = AMBIENT;
            end
        end
    end

    // Sequential logic: state register and fault latch
    always @(posedge i_clk or negedge i_rst) begin
        if (!i_rst) begin
            state         <= AMBIENT;
            fault_latched <= 1'b0;
        end else begin
            // Handle fault latching and clearing
            if (i_fault) begin
                fault_latched <= 1'b1;
            end else if (i_clr) begin
                fault_latched <= 1'b0;
                state         <= AMBIENT;
            end

            // Update state only when not faulted
            if (!fault_latched && !i_fault) begin
                state <= next_state;
            end
        end
    end

    // Output logic (synchronous with async reset)
    always @(posedge i_clk or negedge i_rst) begin
        if (!i_rst) begin
            o_heater_full   <= 1'b0;
            o_heater_medium <= 1'b0;
            o_heater_low    <= 1'b0;
            o_aircon_full   <= 1'b0;
            o_aircon_medium <= 1'b0;
            o_aircon_low    <= 1'b0;
            o_fan           <= 1'b0;
            o_state         <= AMBIENT;
        end else begin
            // Default: clear all outputs
            o_heater_full   <= 1'b0;
            o_heater_medium <= 1'b0;
            o_heater_low    <= 1'b0;
            o_aircon_full   <= 1'b0;
            o_aircon_medium <= 1'b0;
            o_aircon_low    <= 1'b0;
            o_fan           <= 1'b0;

            if (i_fault || fault_latched) begin
                // Fault override: all outputs = 0
                o_heater_full   <= 1'b0;
                o_heater_medium <= 1'b0;
                o_heater_low    <= 1'b0;
                o_aircon_full   <= 1'b0;
                o_aircon_medium <= 1'b0;
                o_aircon_low    <= 1'b0;
                o_fan           <= 1'b0;
                o_state         <= state;
            end else if (!i_enable) begin
                // Disabled: all outputs = 0
                o_heater_full   <= 1'b0;
                o_heater_medium <= 1'b0;
                o_heater_low    <= 1'b0;
                o_aircon_full   <= 1'b0;
                o_aircon_medium <= 1'b0;
                o_aircon_low    <= 1'b0;
                o_fan           <= 1'b0;
                o_state         <= next_state;
            end else begin
                // Normal operation: drive outputs based on next_state
                o_state <= next_state;
                case (next_state)
                    HEAT_FULL: begin
                        o_heater_full   <= 1'b1;
                        o_heater_medium <= 1'b0;
                        o_heater_low    <= 1'b0;
                        o_aircon_full   <= 1'b0;
                        o_aircon_medium <= 1'b0;
                        o_aircon_low    <= 1'b0;
                        o_fan           <= 1'b1;
                    end
                    HEAT_MED: begin
                        o_heater_full   <= 1'b0;
                        o_heater_medium <= 1'b1;
                        o_heater_low    <= 1'b0;
                        o_aircon_full   <= 1'b0;
                        o_aircon_medium <= 1'b0;
                        o_aircon_low    <= 1'b0;
                        o_fan           <= 1'b1;
                    end
                    HEAT_LOW: begin
                        o_heater_full   <= 1'b0;
                        o_heater_medium <= 1'b0;
                        o_heater_low    <= 1'b1;
                        o_aircon_full   <= 1'b0;
                        o_aircon_medium <= 1'b0;
                        o_aircon_low    <= 1'b0;
                        o_fan           <= 1'b1;
                    end
                    COOL_FULL: begin
                        o_heater_full   <= 1'b0;
                        o_heater_medium <= 1'b0;
                        o_heater_low    <= 1'b0;
                        o_aircon_full   <= 1'b1;
                        o_aircon_medium <= 1'b0;
                        o_aircon_low    <= 1'b0;
                        o_fan           <= 1'b1;
                    end
                    COOL_MED: begin
                        o_heater_full   <= 1'b0;
                        o_heater_medium <= 1'b0;
                        o_heater_low    <= 1'b0;
                        o_aircon_full   <= 1'b0;
                        o_aircon_medium <= 1'b1;
                        o_aircon_low    <= 1'b0;
                        o_fan           <= 1'b1;
                    end
                    COOL_LOW: begin
                        o_heater_full   <= 1'b0;
                        o_heater_medium <= 1'b0;
                        o_heater_low    <= 1'b0;
                        o_aircon_full   <= 1'b0;
                        o_aircon_medium <= 1'b0;
                        o_aircon_low    <= 1'b1;
                        o_fan           <= 1'b1;
                    end
                    AMBIENT: begin
                        o_heater_full   <= 1'b0;
                        o_heater_medium <= 1'b0;
                        o_heater_low    <= 1'b0;
                        o_aircon_full   <= 1'b0;
                        o_aircon_medium <= 1'b0;
                        o_aircon_low    <= 1'b0;
                        o_fan           <= i_fan_on;
                    end
                    default: begin
                        o_heater_full   <= 1'b0;
                        o_heater_medium <= 1'b0;
                        o_heater_low    <= 1'b0;
                        o_aircon_full   <= 1'b0;
                        o_aircon_medium <= 1'b0;
                        o_aircon_low    <= 1'b0;
                        o_fan           <= i_fan_on;
                    end
                endcase
            end
        end
    end

endmodule

output.rtl/unpack_one_hot.v:
module unpack_one_hot (
    input  wire        sign,
    input  wire        size,
    input  wire [2:0]  one_hot_selector,
    input  wire [255:0] source_reg,
    output reg  [511:0] destination_reg
);

    integer i;

    always @(*) begin
        destination_reg = 512'b0;

        case (one_hot_selector)
            3'b001: begin
                // Each 1-bit segment of source_reg unpacked into 8-bit segment of destination_reg
                // source_reg has 256 bits -> 256 1-bit segments
                // destination_reg has 512 bits, but we only have 256 segments of 8 bits = 2048 bits
                // Wait - destination is 512 bits. 256 segments * 8 bits = 2048 bits. 
                // That doesn't fit. Let me reconsider.
                // Perhaps we only unpack the lower portion that fits.
                // 512 bits / 8 bits per element = 64 elements
                // So we take 64 1-bit segments from source_reg
                for (i = 0; i < 64; i = i + 1) begin
                    if (sign && source_reg[i]) begin
                        destination_reg[i*8 +: 8] = 8'hFF;
                    end else begin
                        destination_reg[i*8 +: 8] = {7'b0, source_reg[i]};
                    end
                end
            end

            3'b010: begin
                // Each 2-bit segment of source_reg unpacked into 8-bit segment of destination_reg
                // 512 bits / 8 bits per element = 64 elements
                // 64 elements * 2 bits = 128 bits from source_reg
                for (i = 0; i < 64; i = i + 1) begin
                    if (sign && source_reg[i*2 + 1]) begin
                        destination_reg[i*8 +: 8] = {{6{1'b1}}, source_reg[i*2 +: 2]};
                    end else begin
                        destination_reg[i*8 +: 8] = {6'b0, source_reg[i*2 +: 2]};
                    end
                end
            end

            3'b100: begin
                if (size) begin
                    // Each 8-bit segment of source_reg unpacked into 16-bit segment of destination_reg
                    // 512 bits / 16 bits per element = 32 elements
                    // 32 elements * 8 bits = 256 bits from source_reg (fits exactly)
                    for (i = 0; i < 32; i = i + 1) begin
                        if (sign && source_reg[i*8 + 7]) begin
                            destination_reg[i*16 +: 16] = {{8{1'b1}}, source_reg[i*8 +: 8]};
                        end else begin
                            destination_reg[i*16 +: 16] = {8'b0, source_reg[i*8 +: 8]};
                        end
                    end
                end else begin
                    // Each 4-bit segment of source_reg unpacked into 8-bit segment of destination_reg
                    // 512 bits / 8 bits per element = 64 elements
                    // 64 elements * 4 bits = 256 bits from source_reg (fits exactly)
                    for (i = 0; i < 64; i = i + 1) begin
                        if (sign && source_reg[i*4 + 3]) begin
                            destination_reg[i*8 +: 8] = {{4{1'b1}}, source_reg[i*4 +: 4]};
                        end else begin
                            destination_reg[i*8 +: 8] = {4'b0, source_reg[i*4 +: 4]};
                        end
                    end
                end
            end

            default: begin
                // Direct assignment of source_reg to destination_reg
                destination_reg = {256'b0, source_reg};
            end
        endcase
    end

endmodule

output.rtl/static_branch_predict.sv:
// Static Branch Predictor Module
// Predicts whether a branch or jump instruction will be taken based on the instruction encoding.

module static_branch_predict (
    input  logic [31:0] fetch_rdata_i,       // Fetched instruction data
    input  logic [31:0] fetch_pc_i,          // Program counter of the fetched instruction
    input  logic        fetch_valid_i,       // Validity of the fetched instruction (active HIGH)

    output logic        predict_branch_taken_o, // Predicted branch taken (active HIGH)
    output logic [31:0] predict_branch_pc_o     // Predicted target address
);

    // Localparams for opcodes
    localparam OPCODE_BRANCH = 7'h63;
    localparam OPCODE_JAL    = 7'h6F;
    localparam OPCODE_JALR   = 7'h67;

    // Alias for the input instruction
    logic [31:0] instr;
    assign instr = fetch_rdata_i;

    // Immediate values
    logic [31:0] imm_j_type;   // Sign-extended immediate for JAL (uncompressed)
    logic [31:0] imm_b_type;   // Sign-extended immediate for Branch (uncompressed)
    logic [31:0] imm_cj_type;  // Sign-extended immediate for compressed jump (C.J/C.JAL)
    logic [31:0] imm_cb_type;  // Sign-extended immediate for compressed branch (C.BEQZ/C.BNEZ)
    logic [31:0] branch_imm;   // Selected immediate based on instruction type

    // Instruction type signals
    logic instr_j;    // Uncompressed JAL or JALR
    logic instr_b;    // Uncompressed branch (BXXX)
    logic instr_cj;   // Compressed jump (C.J / C.JAL) in uncompressed form
    logic instr_cb;   // Compressed branch (C.BEQZ / C.BNEZ) in uncompressed form
    logic instr_b_taken; // Indicates if branch offset is negative (branch predicted taken)

    // -------------------------------------------------------------------------
    // Immediate Extraction and Sign Extension
    // -------------------------------------------------------------------------

    // JAL immediate: {instr[31], instr[19:12], instr[20], instr[30:21], 1'b0}
    assign imm_j_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0};

    // Branch immediate: {instr[31], instr[7], instr[30:25], instr[11:8], 1'b0}
    assign imm_b_type = {{19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0};

    // Compressed jump immediate (C.J/C.JAL converted to uncompressed JAL format)
    // The uncompressed equivalent has the same opcode as JAL (7'h6F)
    // but with a specific encoding in bits [31:7].
    // The immediate is reconstructed from the uncompressed JAL encoding:
    // imm_j_type already handles this since the decompressor produces a JAL-equivalent instruction.
    // For C.J/C.JAL, after decompression, the instruction follows the JAL format.
    // We use imm_j_type for both JAL and C.J/C.JAL.
    assign imm_cj_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0};

    // Compressed branch immediate (C.BEQZ/C.BNEZ converted to uncompressed BXXX format)
    // After decompression, the instruction follows the branch format.
    // We use imm_b_type for both BXXX and C.BEQZ/C.BNEZ.
    assign imm_cb_type = {{19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0};

    // -------------------------------------------------------------------------
    // Instruction Type Decoding
    // -------------------------------------------------------------------------

    // Uncompressed JAL or JALR detection
    // instr_j: opcode is JAL or JALR
    assign instr_j = fetch_valid_i & 
                     ((instr[6:0] == OPCODE_JAL) | (instr[6:0] == OPCODE_JALR));

    // Uncompressed branch detection (BXXX)
    // instr_b: opcode is BRANCH
    // We differentiate from compressed branches by checking that it's not a compressed instruction
    // and that bit[7] pattern matches.
    // For uncompressed branch: opcode = 7'h63, instr[1:0] = 2'b11
    assign instr_b = fetch_valid_i & 
                     (instr[6:0] == OPCODE_BRANCH) &
                     (instr[14] == 1'b0); // func3[2] = 0 means uncompressed (beq, bne, blt, bltu variants)
                                          // Actually, we need a better discriminator

    // -------------------------------------------------------------------------
    // Better discrimination between uncompressed and compressed instructions:
    // 
    // After decompression:
    // - C.J / C.JAL => JAL (opcode 7'h6F), with instr[7] = ~instr_c[15]
    //   - C.J (func3=101, rd=x0): instr[7] = ~0 = 1 -> instr[11:7] = 5'b00001 (rd=x0 but bit7=1?)
    //     Wait, let me re-read the encoding.
    //
    // From the spec, the uncompressed equivalent of C.J/C.JAL:
    // bit[7] = ~instr_c[15]
    // C.J: func3=101 => instr_c[15]=1 => instr[7] = ~1 = 0
    // C.JAL: func3=001 => instr_c[15]=0 => instr[7] = ~0 = 1
    //
    // For standard JAL: rd is in bits[11:7], which could have any value including 0 or 1 in bit[7].
    //
    // The key differentiator for compressed vs uncompressed in their decompressed form:
    // Looking at bits [11:8]:
    // - Compressed jump (C.J/C.JAL decompressed): instr[11:8] = 4'b0000
    // - Standard JAL: instr[11:8] = rd[4:1], which is part of the destination register
    //
    // For compressed branch (C.BEQZ/C.BNEZ decompressed):
    // instr[19:18] = 2'b01 (from the encoding table: bits[19:18] = 2'b01)
    // instr[17:15] = rs1' (3-bit register from compressed encoding, mapped to x8-x15)
    // instr[14:13] = 2'b00
    //
    // For standard branch: 
    // instr[19:15] = rs1 (5-bit register), instr[14:12] = func3
    //
    // The discriminator: 
    // Compressed branch decompressed has instr[14:13] = 2'b00 and instr[19:18] = 2'b01
    // 
    // Let me use the approach: identify compressed instructions by checking specific bit patterns
    // that differ from standard encodings.
    //
    // For C.J/C.JAL (decompressed to JAL):
    //   rd field [11:7]: 
    //     C.JAL: rd = x1 (5'b00001), so instr[11:8] = 4'b0000, instr[7] = 1
    //     C.J:   rd = x0 (5'b00000), so instr[11:8] = 4'b0000, instr[7] = 0
    //   So both C.J and C.JAL have instr[11:8] = 4'b0000
    //   Standard JAL can also have rd=x0 or rd=x1, so instr[11:8] could also be 4'b0000.
    //
    // Actually, looking more carefully at the decompressed C.J/C.JAL encoding:
    // instr[20:12] = {9{instr_c[12]}} which is the sign extension portion
    // This maps to imm[19:11] in the JAL format.
    // 
    // The key insight from the spec is that we should detect compressed vs uncompressed
    // based on the specific bit patterns defined in the decompressed format.
    //
    // For C.BEQZ/C.BNEZ decompressed:
    // - instr[24:20] = 5'b00000 (rs2 = x0)
    // - instr[19:18] = 2'b01
    // This means rs1[4:3] = 2'b01, which forces rs1 to be in range x8-x15.
    // Standard branches can have any rs1, so we can use instr[19:18] = 2'b01 AND 
    // instr[24:20] = 5'b00000 to identify decompressed C.BEQZ/C.BNEZ.
    //
    // For standard BXXX:
    // - rs2 = instr[24:20] can be anything, rs1 = instr[19:15] can be anything
    // - But we need to exclude the case where rs2=0 AND rs1[4:3]=01 (which is decompressed C.BXX)
    //
    // -------------------------------------------------------------------------

    // -------------------------------------------------------------------------
    // Redefine instruction type signals with better discrimination
    // -------------------------------------------------------------------------

    // Compressed jump (C.J / C.JAL) decompressed to JAL format:
    // opcode = 7'h6F AND instr[11:8] = 4'b0000
    // (rd is either x0 for C.J or x1 for C.JAL, both have rd[4:1] = 4'b0000)
    assign instr_cj = fetch_valid_i &
                      (instr[6:0] == OPCODE_JAL) &
                      (instr[11:8] == 4'b0000);

    // Compressed branch (C.BEQZ / C.BNEZ) decompressed to branch format:
    // opcode = 7'h63 AND rs2 = 5'b00000 AND rs1[4:3] = 2'b01
    assign instr_cb = fetch_valid_i &
                      (instr[6:0] == OPCODE_BRANCH) &
                      (instr[24:20] == 5'b00000) &
                      (instr[19:18] == 2'b01);

    // Uncompressed JAL: opcode = 7'h6F AND NOT compressed jump pattern
    // Uncompressed JALR: opcode = 7'h67
    assign instr_j = fetch_valid_i &
                     (((instr[6:0] == OPCODE_JAL) & ~(instr[11:8] == 4'b0000)) |
                      (instr[6:0] == OPCODE_JALR));

    // Uncompressed branch: opcode = 7'h63 AND NOT compressed branch pattern
    assign instr_b = fetch_valid_i &
                     (instr[6:0] == OPCODE_BRANCH) &
                     ~((instr[24:20] == 5'b00000) & (instr[19:18] == 2'b01));

    // -------------------------------------------------------------------------
    // Branch taken prediction
    // For branch instructions, predict taken if the offset is negative (sign bit = 1)
    // -------------------------------------------------------------------------
    // The sign bit for branch immediate is instr[31]
    assign instr_b_taken = instr[31];

    // -------------------------------------------------------------------------
    // Branch immediate selection
    // -------------------------------------------------------------------------
    always_comb begin
        if (instr_j) begin
            branch_imm = imm_j_type;
        end else if (instr_cj) begin
            branch_imm = imm_cj_type;
        end else if (instr_b) begin
            branch_imm = imm_b_type;
        end else if (instr_cb) begin
            branch_imm = imm_cb_type;
        end else begin
            branch_imm = 32'h0;
        end
    end

    // -------------------------------------------------------------------------
    // Output prediction logic
    // -------------------------------------------------------------------------
    assign predict_branch_taken_o = (instr_j | instr_cj) ? 1'b1 :
                                    (instr_b | instr_cb)  ? instr_b_taken :
                                    1'b0;

    assign predict_branch_pc_o = fetch_pc_i + branch_imm;

endmodule

output.rtl/vending_machine.sv:
module vending_machine (
    input  logic        clk,
    input  logic        rst,
    input  logic        item_button,
    input  logic [2:0]  item_selected,
    input  logic [3:0]  coin_input,
    input  logic        cancel,
    output logic        dispense_item,
    output logic        return_change,
    output logic [4:0]  item_price,
    output logic [4:0]  change_amount,
    output logic [2:0]  dispense_item_id,
    output logic        error,
    output logic        return_money
);

    // State encoding
    typedef enum logic [2:0] {
        IDLE               = 3'd0,
        ITEM_SELECTION     = 3'd1,
        PAYMENT_VALIDATION = 3'd2,
        DISPENSING_ITEM    = 3'd3,
        RETURN_CHANGE      = 3'd4,
        RETURN_MONEY       = 3'd5
    } state_t;

    state_t current_state, next_state;

    // Internal registers
    logic [4:0] coins_accumulated;
    logic [4:0] item_price_reg;
    logic [2:0] item_id_reg;
    logic [4:0] change_amount_reg;

    // Edge detection for item_button and cancel
    logic item_button_prev;
    logic cancel_prev;
    logic item_button_rise;
    logic cancel_rise;

    // Intermediate signals for next state logic
    logic [4:0] next_coins_accumulated;
    logic [4:0] next_item_price_reg;
    logic [2:0] next_item_id_reg;
    logic [4:0] next_change_amount_reg;

    // Rising edge detection
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            item_button_prev <= 1'b0;
            cancel_prev      <= 1'b0;
        end else begin
            item_button_prev <= item_button;
            cancel_prev      <= cancel;
        end
    end

    assign item_button_rise = item_button & ~item_button_prev;
    assign cancel_rise      = cancel & ~cancel_prev;

    // Item price lookup
    function automatic [4:0] get_item_price(input [2:0] item_id);
        case (item_id)
            3'b001: get_item_price = 5'd5;
            3'b010: get_item_price = 5'd10;
            3'b011: get_item_price = 5'd15;
            3'b100: get_item_price = 5'd20;
            default: get_item_price = 5'd0;
        endcase
    endfunction

    // Coin validity check
    function automatic logic is_valid_coin(input [3:0] coin);
        case (coin)
            4'd1, 4'd2, 4'd5, 4'd10: is_valid_coin = 1'b1;
            default: is_valid_coin = 1'b0;
        endcase
    endfunction

    // State register
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            current_state       <= IDLE;
            coins_accumulated   <= 5'd0;
            item_price_reg      <= 5'd0;
            item_id_reg         <= 3'd0;
            change_amount_reg   <= 5'd0;
        end else begin
            current_state       <= next_state;
            coins_accumulated   <= next_coins_accumulated;
            item_price_reg      <= next_item_price_reg;
            item_id_reg         <= next_item_id_reg;
            change_amount_reg   <= next_change_amount_reg;
        end
    end

    // Next state and output logic
    always_comb begin
        // Default outputs
        dispense_item       = 1'b0;
        return_change       = 1'b0;
        error               = 1'b0;
        return_money        = 1'b0;
        item_price          = item_price_reg;
        change_amount       = change_amount_reg;
        dispense_item_id    = item_id_reg;

        // Default next state values
        next_state              = current_state;
        next_coins_accumulated  = coins_accumulated;
        next_item_price_reg     = item_price_reg;
        next_item_id_reg        = item_id_reg;
        next_change_amount_reg  = change_amount_reg;

        case (current_state)
            IDLE: begin
                item_price       = 5'd0;
                change_amount    = 5'd0;
                dispense_item_id = 3'd0;

                if (item_button_rise) begin
                    next_state = ITEM_SELECTION;
                end else if (coin_input != 4'd0) begin
                    // Inserting coins without item selection
                    error = 1'b1;
                    next_state = RETURN_MONEY;
                end
            end

            ITEM_SELECTION: begin
                if (cancel_rise) begin
                    error = 1'b1;
                    next_state = RETURN_MONEY;
                end else if (item_selected != 3'b000) begin
                    // Item selection detected
                    if (item_selected >= 3'b001 && item_selected <= 3'b100) begin
                        next_item_id_reg    = item_selected;
                        next_item_price_reg = get_item_price(item_selected);
                        item_price          = get_item_price(item_selected);
                        next_state          = PAYMENT_VALIDATION;
                    end else begin
                        error      = 1'b1;
                        next_state = RETURN_MONEY;
                    end
                end
            end

            PAYMENT_VALIDATION: begin
                item_price = item_price_reg;

                if (cancel_rise) begin
                    error = 1'b1;
                    next_state = RETURN_MONEY;
                end else if (coin_input != 4'd0) begin
                    if (is_valid_coin(coin_input)) begin
                        next_coins_accumulated = coins_accumulated + {1'b0, coin_input};
                        if (coins_accumulated + {1'b0, coin_input} >= item_price_reg) begin
                            next_state = DISPENSING_ITEM;
                        end
                    end else begin
                        // Invalid coin
                        error        = 1'b1;
                        return_money = 1'b1;
                        next_state   = IDLE;
                        // Reset internal state
                        next_coins_accumulated = 5'd0;
                        next_item_price_reg    = 5'd0;
                        next_item_id_reg       = 3'd0;
                        next_change_amount_reg = 5'd0;
                    end
                end
            end

            DISPENSING_ITEM: begin
                dispense_item    = 1'b1;
                dispense_item_id = item_id_reg;
                item_price       = item_price_reg;

                if (coins_accumulated > item_price_reg) begin
                    next_change_amount_reg = coins_accumulated - item_price_reg;
                    next_state = RETURN_CHANGE;
                end else begin
                    // No change needed
                    next_state             = IDLE;
                    next_coins_accumulated = 5'd0;
                    next_item_price_reg    = 5'd0;
                    next_item_id_reg       = 3'd0;
                    next_change_amount_reg = 5'd0;
                end
            end

            RETURN_CHANGE: begin
                return_change = 1'b1;
                change_amount = change_amount_reg;
                item_price    = item_price_reg;

                next_state             = IDLE;
                next_coins_accumulated = 5'd0;
                next_item_price_reg    = 5'd0;
                next_item_id_reg       = 3'd0;
                next_change_amount_reg = 5'd0;
            end

            RETURN_MONEY: begin
                if (coins_accumulated > 5'd0) begin
                    return_money = 1'b1;
                end
                next_state             = IDLE;
                next_coins_accumulated = 5'd0;
                next_item_price_reg    = 5'd0;
                next_item_id_reg       = 3'd0;
                next_change_amount_reg = 5'd0;
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

endmodule

output.rtl/vga_controller.sv:
module vga_controller (
    input  logic        clock,
    input  logic        reset,
    input  logic [7:0]  color_in,
    output logic        hsync,
    output logic        vsync,
    output logic [7:0]  red,
    output logic [7:0]  green,
    output logic [7:0]  blue,
    output logic [9:0]  next_x,
    output logic [9:0]  next_y,
    output logic        sync,
    output logic        clk,
    output logic        blank
);

    // Horizontal timing parameters
    parameter H_ACTIVE = 640;
    parameter H_FRONT  = 16;
    parameter H_PULSE  = 96;
    parameter H_BACK   = 48;

    // Vertical timing parameters
    parameter V_ACTIVE = 480;
    parameter V_FRONT  = 10;
    parameter V_PULSE  = 2;
    parameter V_BACK   = 33;

    // State encoding for horizontal FSM
    typedef enum logic [1:0] {
        H_ACT  = 2'b00,
        H_FP   = 2'b01,
        H_SYNC = 2'b10,
        H_BP   = 2'b11
    } h_state_t;

    // State encoding for vertical FSM
    typedef enum logic [1:0] {
        V_ACT  = 2'b00,
        V_FP   = 2'b01,
        V_SYNC = 2'b10,
        V_BP   = 2'b11
    } v_state_t;

    h_state_t h_state;
    v_state_t v_state;

    logic [9:0] h_counter;
    logic [9:0] v_counter;
    logic       line_done;

    // VGA clock directly connected
    assign clk  = clock;
    // Sync fixed at 0
    assign sync = 1'b0;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_state   <= H_ACT;
            v_state   <= V_ACT;
            h_counter <= 10'd0;
            v_counter <= 10'd0;
            line_done <= 1'b0;
            hsync     <= 1'b1;
            vsync     <= 1'b1;
            red       <= 8'd0;
            green     <= 8'd0;
            blue      <= 8'd0;
            next_x    <= 10'd0;
            next_y    <= 10'd0;
            blank     <= 1'b0;
        end else begin
            // Default line_done
            line_done <= 1'b0;

            // Horizontal FSM
            case (h_state)
                H_ACT: begin
                    hsync <= 1'b1;
                    // Active display: output color
                    red   <= {color_in[7:5], 5'd0};
                    green <= {color_in[4:2], 5'd0};
                    blue  <= {color_in[1:0], 6'd0};
                    // next_x tracks pixel position
                    next_x <= h_counter;

                    if (h_counter == H_ACTIVE - 1) begin
                        h_counter <= 10'd0;
                        h_state   <= H_FP;
                    end else begin
                        h_counter <= h_counter + 10'd1;
                    end
                end

                H_FP: begin
                    hsync  <= 1'b1;
                    red    <= 8'd0;
                    green  <= 8'd0;
                    blue   <= 8'd0;
                    next_x <= 10'd0;

                    if (h_counter == H_FRONT - 1) begin
                        h_counter <= 10'd0;
                        h_state   <= H_SYNC;
                    end else begin
                        h_counter <= h_counter + 10'd1;
                    end
                end

                H_SYNC: begin
                    hsync  <= 1'b0;
                    red    <= 8'd0;
                    green  <= 8'd0;
                    blue   <= 8'd0;
                    next_x <= 10'd0;

                    if (h_counter == H_PULSE - 1) begin
                        h_counter <= 10'd0;
                        h_state   <= H_BP;
                    end else begin
                        h_counter <= h_counter + 10'd1;
                    end
                end

                H_BP: begin
                    hsync  <= 1'b1;
                    red    <= 8'd0;
                    green  <= 8'd0;
                    blue   <= 8'd0;
                    next_x <= 10'd0;

                    if (h_counter == H_BACK - 1) begin
                        h_counter <= 10'd0;
                        h_state   <= H_ACT;
                        line_done <= 1'b1;
                    end else begin
                        h_counter <= h_counter + 10'd1;
                    end
                end

                default: begin
                    h_state   <= H_ACT;
                    h_counter <= 10'd0;
                end
            endcase

            // Vertical FSM - advances when line_done (will be set next cycle, use current)
            // line_done is set this cycle when H_BP ends; we need to act on it
            // Since line_done is set in the same always_ff block, we need to check condition directly
            // Instead, check vertical transitions based on the horizontal state transition

            // We handle vertical transitions by checking if we are at the last cycle of H_BP
            if (h_state == H_BP && h_counter == H_BACK - 1) begin
                case (v_state)
                    V_ACT: begin
                        vsync  <= 1'b1;
                        next_y <= v_counter;

                        if (v_counter == V_ACTIVE - 1) begin
                            v_counter <= 10'd0;
                            v_state   <= V_FP;
                        end else begin
                            v_counter <= v_counter + 10'd1;
                        end
                    end

                    V_FP: begin
                        vsync  <= 1'b1;
                        next_y <= 10'd0;

                        if (v_counter == V_FRONT - 1) begin
                            v_counter <= 10'd0;
                            v_state   <= V_SYNC;
                        end else begin
                            v_counter <= v_counter + 10'd1;
                        end
                    end

                    V_SYNC: begin
                        vsync  <= 1'b0;
                        next_y <= 10'd0;

                        if (v_counter == V_PULSE - 1) begin
                            v_counter <= 10'd0;
                            v_state   <= V_BP;
                        end else begin
                            v_counter <= v_counter + 10'd1;
                        end
                    end

                    V_BP: begin
                        vsync  <= 1'b1;
                        next_y <= 10'd0;

                        if (v_counter == V_BACK - 1) begin
                            v_counter <= 10'd0;
                            v_state   <= V_ACT;
                        end else begin
                            v_counter <= v_counter + 10'd1;
                        end
                    end

                    default: begin
                        v_state   <= V_ACT;
                        v_counter <= 10'd0;
                    end
                endcase
            end else begin
                // Maintain vsync based on current v_state when not transitioning
                case (v_state)
                    V_ACT:  begin vsync <= 1'b1; next_y <= v_counter; end
                    V_FP:   begin vsync <= 1'b1; next_y <= 10'd0; end
                    V_SYNC: begin vsync <= 1'b0; next_y <= 10'd0; end
                    V_BP:   begin vsync <= 1'b1; next_y <= 10'd0; end
                    default: vsync <= 1'b1;
                endcase
            end

            // Blank signal: active when not in active display area for both H and V
            if ((h_state == H_ACT) && (v_state == V_ACT)) begin
                blank <= 1'b0;
            end else begin
                blank <= 1'b1;
            end
        end
    end

endmodule

output.rtl/wishbone_to_ahb_bridge.sv:
// rtl/wishbone_to_ahb_bridge.sv
// Wishbone to AHB Bridge Module

module wishbone_to_ahb_bridge (
    // Wishbone Master Interface
    input  logic        clk_i,
    input  logic        rst_i,       // Active-low reset
    input  logic        cyc_i,
    input  logic        stb_i,
    input  logic [3:0]  sel_i,
    input  logic        we_i,
    input  logic [31:0] addr_i,
    input  logic [31:0] data_i,

    // AHB Slave Interface (inputs from AHB slave)
    input  logic        hclk,
    input  logic        hreset_n,    // Active-low reset
    input  logic [31:0] hrdata,
    input  logic [1:0]  hresp,
    input  logic        hready,

    // Wishbone Outputs
    output logic [31:0] data_o,
    output logic        ack_o,

    // AHB Outputs
    output logic [1:0]  htrans,
    output logic [2:0]  hsize,
    output logic [2:0]  hburst,
    output logic        hwrite,
    output logic [31:0] haddr,
    output logic [31:0] hwdata
);

    // AHB Transfer Types
    localparam HTRANS_IDLE   = 2'b00;
    localparam HTRANS_BUSY   = 2'b01;
    localparam HTRANS_NONSEQ = 2'b10;
    localparam HTRANS_SEQ    = 2'b11;

    // AHB Burst Types
    localparam HBURST_SINGLE = 3'b000;

    // AHB Size Types
    localparam HSIZE_BYTE     = 3'b000;
    localparam HSIZE_HALFWORD = 3'b001;
    localparam HSIZE_WORD     = 3'b010;

    // FSM States
    typedef enum logic [2:0] {
        IDLE        = 3'b000,
        ADDR_PHASE  = 3'b001,
        DATA_PHASE  = 3'b010,
        ACK_PHASE   = 3'b011,
        WAIT_READY  = 3'b100
    } state_t;

    state_t current_state, next_state;

    // Internal registers
    logic [31:0] haddr_reg;
    logic [2:0]  hsize_reg;
    logic        hwrite_reg;
    logic [31:0] hwdata_reg;
    logic [1:0]  htrans_reg;
    logic [31:0] data_o_reg;
    logic        ack_o_reg;

    // Function to determine transfer size from sel_i
    function automatic logic [2:0] get_hsize;
        input logic [3:0] sel;
        case (sel)
            4'b0001, 4'b0010, 4'b0100, 4'b1000: get_hsize = HSIZE_BYTE;
            4'b0011, 4'b1100:                    get_hsize = HSIZE_HALFWORD;
            4'b1111:                             get_hsize = HSIZE_WORD;
            default:                             get_hsize = HSIZE_WORD;
        endcase
    endfunction

    // Function to fix address based on sel_i
    function automatic logic [31:0] fix_addr;
        input logic [31:0] addr;
        input logic [3:0]  sel;
        case (sel)
            4'b0001: fix_addr = {addr[31:2], 2'b00};
            4'b0010: fix_addr = {addr[31:2], 2'b01};
            4'b0100: fix_addr = {addr[31:2], 2'b10};
            4'b1000: fix_addr = {addr[31:2], 2'b11};
            4'b0011: fix_addr = {addr[31:2], 2'b00};
            4'b1100: fix_addr = {addr[31:2], 2'b10};
            4'b1111: fix_addr = {addr[31:2], 2'b00};
            default: fix_addr = {addr[31:2], 2'b00};
        endcase
    endfunction

    // Endian conversion for write data based on sel_i
    function automatic logic [31:0] convert_write_data;
        input logic [31:0] data;
        input logic [3:0]  sel;
        case (sel)
            4'b0001: convert_write_data = {24'b0, data[7:0]};
            4'b0010: convert_write_data = {16'b0, data[7:0], 8'b0};
            4'b0100: convert_write_data = {8'b0, data[7:0], 16'b0};
            4'b1000: convert_write_data = {data[7:0], 24'b0};
            4'b0011: convert_write_data = {16'b0, data[15:0]};
            4'b1100: convert_write_data = {data[15:0], 16'b0};
            4'b1111: convert_write_data = data;
            default: convert_write_data = data;
        endcase
    endfunction

    // Endian conversion for read data based on sel_i
    function automatic logic [31:0] convert_read_data;
        input logic [31:0] data;
        input logic [3:0]  sel;
        case (sel)
            4'b0001: convert_read_data = {24'b0, data[7:0]};
            4'b0010: convert_read_data = {24'b0, data[15:8]};
            4'b0100: convert_read_data = {24'b0, data[23:16]};
            4'b1000: convert_read_data = {24'b0, data[31:24]};
            4'b0011: convert_read_data = {16'b0, data[15:0]};
            4'b1100: convert_read_data = {16'b0, data[31:16]};
            4'b1111: convert_read_data = data;
            default: convert_read_data = data;
        endcase
    endfunction

    // Registered sel for data phase
    logic [3:0] sel_reg;
    logic [31:0] data_i_reg;

    // Reset condition (both resets must be high for operation)
    wire reset_active = ~rst_i | ~hreset_n;

    // FSM sequential logic
    always_ff @(posedge hclk or negedge hreset_n or negedge rst_i) begin
        if (~hreset_n || ~rst_i) begin
            current_state <= IDLE;
            haddr_reg     <= 32'b0;
            hsize_reg     <= HSIZE_WORD;
            hwrite_reg    <= 1'b0;
            hwdata_reg    <= 32'b0;
            htrans_reg    <= HTRANS_IDLE;
            data_o_reg    <= 32'b0;
            ack_o_reg     <= 1'b0;
            sel_reg       <= 4'b0;
            data_i_reg    <= 32'b0;
        end else begin
            current_state <= next_state;
            ack_o_reg     <= 1'b0;

            case (current_state)
                IDLE: begin
                    if (cyc_i && stb_i) begin
                        // Capture transaction attributes
                        haddr_reg  <= fix_addr(addr_i, sel_i);
                        hsize_reg  <= get_hsize(sel_i);
                        hwrite_reg <= we_i;
                        hwdata_reg <= convert_write_data(data_i, sel_i);
                        htrans_reg <= HTRANS_NONSEQ;
                        sel_reg    <= sel_i;
                        data_i_reg <= data_i;
                    end else begin
                        htrans_reg <= HTRANS_IDLE;
                    end
                end

                ADDR_PHASE: begin
                    if (hready) begin
                        htrans_reg <= HTRANS_IDLE;
                        hwdata_reg <= convert_write_data(data_i_reg, sel_reg);
                    end
                end

                DATA_PHASE: begin
                    if (hready) begin
                        if (!hwrite_reg) begin
                            data_o_reg <= convert_read_data(hrdata, sel_reg);
                        end
                        ack_o_reg <= 1'b1;
                    end
                end

                WAIT_READY: begin
                    if (hready) begin
                        if (!hwrite_reg) begin
                            data_o_reg <= convert_read_data(hrdata, sel_reg);
                        end
                        ack_o_reg <= 1'b1;
                    end
                end

                ACK_PHASE: begin
                    ack_o_reg  <= 1'b0;
                    htrans_reg <= HTRANS_IDLE;
                    // Check for back-to-back transaction
                    if (cyc_i && stb_i) begin
                        haddr_reg  <= fix_addr(addr_i, sel_i);
                        hsize_reg  <= get_hsize(sel_i);
                        hwrite_reg <= we_i;
                        hwdata_reg <= convert_write_data(data_i, sel_i);
                        htrans_reg <= HTRANS_NONSEQ;
                        sel_reg    <= sel_i;
                        data_i_reg <= data_i;
                    end
                end

                default: begin
                    htrans_reg <= HTRANS_IDLE;
                end
            endcase
        end
    end

    // FSM next state logic
    always_comb begin
        next_state = current_state;
        case (current_state)
            IDLE: begin
                if (cyc_i && stb_i) begin
                    next_state = ADDR_PHASE;
                end else begin
                    next_state = IDLE;
                end
            end

            ADDR_PHASE: begin
                if (hready) begin
                    next_state = DATA_PHASE;
                end else begin
                    next_state = WAIT_READY;
                end
            end

            WAIT_READY: begin
                if (hready) begin
                    next_state = ACK_PHASE;
                end else begin
                    next_state = WAIT_READY;
                end
            end

            DATA_PHASE: begin
                if (hready) begin
                    next_state = ACK_PHASE;
                end else begin
                    next_state = WAIT_READY;
                end
            end

            ACK_PHASE: begin
                if (cyc_i && stb_i) begin
                    next_state = ADDR_PHASE;
                end else begin
                    next_state = IDLE;
                end
            end

            default: next_state = IDLE;
        endcase
    end

    // Output assignments
    assign htrans = htrans_reg;
    assign hsize  = hsize_reg;
    assign hburst = HBURST_SINGLE;
    assign hwrite = hwrite_reg;
    assign haddr  = haddr_reg;
    assign hwdata = hwdata_reg;
    assign data_o = data_o_reg;
    assign ack_o  = ack_o_reg;

endmodule
